// ============================================================
// CONTENT DATABASES
// ============================================================
const QUIZZES = [
  {q:"What organelle is called the 'powerhouse of the cell'?",o:["Ribosome","Mitochondria","Golgi apparatus"],a:1,e:"Mitochondria convert glucose into ATP through cellular respiration, providing energy for virtually every cellular process."},
  {q:"How many chromosomes do humans have?",o:["23","46","48"],a:1,e:"Humans have 46 chromosomes in 23 pairs. Chimpanzees have 48 — one of our pairs fused during evolution!"},
  {q:"Which blood type is the universal donor?",o:["O negative","AB positive","A negative"],a:0,e:"O negative has no A, B, or Rh antigens, so it won't trigger immune reactions in any recipient."},
  {q:"What percentage of DNA do you share with a banana?",o:["About 20%","About 40%","About 60%"],a:2,e:"We share ~60% of DNA with bananas! Many fundamental cellular processes are conserved across all life."},
  {q:"Which organ regenerates itself?",o:["Heart","Liver","Brain"],a:1,e:"The liver can regenerate from as little as 25% of its tissue — the only internal organ that fully regenerates in mammals."},
  {q:"What is the largest cell in the human body?",o:["Red blood cell","Egg cell (ovum)","Neuron"],a:1,e:"The egg cell is ~0.1mm — visible to the naked eye! Roughly the size of a period at the end of a sentence."},
  {q:"Which animal has the most hearts?",o:["Octopus (3)","Earthworm (5)","Hagfish (4)"],a:1,e:"Earthworms have 5 pairs of aortic arches functioning as hearts, pumping blood through their segmented bodies."},
  {q:"What is the most common element in the body by mass?",o:["Carbon","Hydrogen","Oxygen"],a:2,e:"Oxygen is ~65% of body mass, mostly because you're ~60% water (H₂O) and oxygen is the heavier atom."},
  {q:"What do plant cells have that animal cells lack?",o:["Nucleus","Cell wall","Mitochondria"],a:1,e:"Plant cells have a rigid cellulose cell wall outside the membrane, giving structural support. Animal cells only have a membrane."},
  {q:"How long is DNA in one cell if uncoiled?",o:["About 2 cm","About 2 meters","About 2 km"],a:1,e:"Each cell has ~2 meters of DNA packed incredibly tightly around histone proteins. All your cells' DNA would reach the Sun and back 600 times!"},
  {q:"What is the fastest muscle in the body?",o:["Tongue","Heart","Eye muscles"],a:2,e:"The orbicularis oculi can contract in <1/100th of a second — that's why blinking is so fast."},
  {q:"Which animal survives being frozen solid?",o:["Arctic fox","Wood frog","Penguin"],a:1,e:"Wood frogs produce glucose antifreeze. Their heart stops, they stop breathing, literally freeze — then thaw and hop away in spring!"},
  {q:"How many bacteria species live in your gut?",o:["About 100","About 1,000","About 10,000"],a:1,e:"~1,000 species totaling trillions of individual bacteria — your microbiome collectively weighs about 2 kg."},
  {q:"What animal has blue blood?",o:["Horseshoe crab","Blue whale","Bluebird"],a:0,e:"Horseshoe crabs use copper-based hemocyanin (blue) instead of iron hemoglobin. Their blood tests all medical equipment for bacterial contamination!"},
  {q:"What is apoptosis?",o:["Cell division","Programmed cell death","Cell mutation"],a:1,e:"Apoptosis is your body's clean self-destruct for damaged cells. ~50–70 billion cells die this way every single day!"},
  {q:"Which kingdom includes mushrooms?",o:["Plantae","Protista","Fungi"],a:2,e:"Fungi are their own kingdom — more closely related to animals than plants! They don't photosynthesize; they digest food externally."},
  {q:"What is the strongest bone in the body?",o:["Skull","Femur","Spine"],a:1,e:"The femur supports 30x your body weight. Pound for pound, bone is stronger than steel and more flexible than concrete."},
  {q:"How many taste buds do humans have?",o:["About 2,000","About 10,000","About 50,000"],a:1,e:"~10,000 taste buds with 50–100 receptor cells each. They regenerate every 10–14 days."},
  {q:"What is the only mammal that truly flies?",o:["Flying squirrel","Bat","Sugar glider"],a:1,e:"Bats are the only true-flying mammals. Over 1,400 species — about 20% of all mammal species!"},
  {q:"What causes blood to be red?",o:["Iron in hemoglobin","Red cell walls","Plasma pigments"],a:0,e:"Iron in hemoglobin reflects red light when oxygenated. Deoxygenated blood is darker red (never blue!)."},
  {q:"How many times does the heart beat per day?",o:["About 50,000","About 100,000","About 200,000"],a:1,e:"~100,000 beats daily pumping ~2,000 gallons of blood. Over a lifetime: ~2.5 billion beats!"},
  {q:"Which cell type has no nucleus?",o:["Red blood cells","White blood cells","Platelets"],a:0,e:"Mature RBCs eject their nucleus for more hemoglobin. They can't divide or repair, living only ~120 days."},
  {q:"What is the function of ribosomes?",o:["Energy production","Protein synthesis","DNA replication"],a:1,e:"Ribosomes read mRNA and assemble amino acids into proteins. Each cell has millions — the factories of life."},
  {q:"What is the largest organ?",o:["Liver","Lungs","Skin"],a:2,e:"Skin covers ~20 sq ft, weighs ~8 lbs. Three complex layers with nerves, blood vessels, and glands."},
  {q:"Which animal lives the longest?",o:["Galápagos tortoise","Bowhead whale","Greenland shark"],a:2,e:"Greenland sharks can live 400+ years! They grow ~1 cm/year and don't mature until ~150 years old."},
  {q:"What is the pH of human blood?",o:["6.8–7.0 (acidic)","7.35–7.45 (alkaline)","8.0–8.5 (alkaline)"],a:1,e:"Blood is slightly alkaline. Even small changes are life-threatening — multiple buffer systems keep pH precisely regulated."},
  {q:"How much of the body is water?",o:["About 40%","About 60%","About 80%"],a:1,e:"Adults are ~60% water. Babies ~75%. Even bones are 31% water! Essential for virtually every biochemical reaction."},
  {q:"How many genes does the human genome have?",o:["About 5,000","About 20,000","About 100,000"],a:1,e:"~20,000–25,000 protein-coding genes. A grape has more (~30,000)! Gene count doesn't equal complexity."},
  {q:"Which vitamin does skin make from sunlight?",o:["Vitamin A","Vitamin C","Vitamin D"],a:2,e:"UV-B converts a cholesterol derivative into vitamin D3 — crucial for calcium absorption and bone health."},
  {q:"What is the smallest bone in the body?",o:["Stapes","Hyoid","Pisiform"],a:0,e:"The stapes (stirrup) in the middle ear is only 3mm — about the size of a grain of rice."},
  {q:"What is the function of melanin?",o:["Regulate temperature","Protect against UV","Produce sweat"],a:1,e:"Melanin absorbs UV radiation protecting DNA. More melanin = darker skin = more UV protection."},
  {q:"Which animal regenerates from a tiny fragment?",o:["Starfish","Planaria flatworm","Gecko"],a:1,e:"Planaria regenerate from 1/279th of their body! Adult stem cells (neoblasts) throughout their body make this possible."},
  {q:"What bond holds DNA strands together?",o:["Covalent","Hydrogen","Ionic"],a:1,e:"Hydrogen bonds between base pairs (A-T, G-C). Individually weak but collectively strong — and easy to unzip for replication."},
  {q:"What is the hardest substance in the body?",o:["Bone","Tooth enamel","Fingernails"],a:1,e:"Enamel is 96% mineral — harder than steel! But it can't regenerate, which is why cavities are permanent."},
  {q:"How fast do nerve impulses travel?",o:["Up to 1 m/s","Up to 120 m/s","Up to 1,000 m/s"],a:1,e:"Motor neurons reach 120 m/s (268 mph). Myelin sheaths insulate nerves and speed up transmission."},
  {q:"Which organelle has its own DNA?",o:["Nucleus only","Mitochondria","Golgi apparatus"],a:1,e:"Mitochondria have circular DNA inherited only from your mother — supporting the endosymbiotic theory that they were once free-living bacteria!"},
  {q:"What is the largest animal ever?",o:["T. Rex","Argentinosaurus","Blue whale"],a:2,e:"Blue whales reach 100ft and 200 tons — larger than any dinosaur! Heart weighs ~400 lbs."},
  {q:"What protein makes up hair and nails?",o:["Collagen","Keratin","Elastin"],a:1,e:"Keratin also makes hooves, horns, claws, feathers — all modified versions of the same tough fibrous protein."},
  {q:"How many cells does the body contain?",o:["37 million","37 billion","37 trillion"],a:2,e:"~37 trillion cells. Plus ~38 trillion bacteria — slightly outnumbering your own cells!"},
  {q:"What is the cerebellum's function?",o:["Memory","Motor coordination","Visual processing"],a:1,e:"The cerebellum has more than half of all brain neurons! It fine-tunes movement, balance, and motor learning."},
  {q:"Which cells clot blood?",o:["Platelets","Red blood cells","Lymphocytes"],a:0,e:"Platelets clump at wound sites and trigger a cascade forming a fibrin mesh to stop bleeding."},
  {q:"What is CRISPR?",o:["A protein","A gene-editing tool","An RNA virus"],a:1,e:"CRISPR-Cas9 is adapted from a bacterial immune system. It lets scientists make precise DNA cuts for targeted gene modification."},
  {q:"Which sense is most connected to memory?",o:["Sight","Touch","Smell"],a:2,e:"The olfactory bulb connects directly to the amygdala and hippocampus — that's why a smell can trigger vivid memories instantly."},
  {q:"How many muscles are in the body?",o:["About 200","About 400","About 600"],a:2,e:"~600 skeletal muscles making up ~40% of body weight. The gluteus maximus is largest; the stapedius (ear) is smallest."},
  {q:"What molecule carries amino acids to ribosomes?",o:["mRNA","tRNA","rRNA"],a:1,e:"Transfer RNA acts as an adapter — one end reads the mRNA codon, the other carries the matching amino acid."},
  {q:"How many chambers does the heart have?",o:["2","3","4"],a:2,e:"4 chambers: 2 atria (receiving) and 2 ventricles (pumping). This separates oxygenated and deoxygenated blood completely."},
  {q:"Which brain part controls breathing?",o:["Cerebrum","Cerebellum","Medulla oblongata"],a:2,e:"The medulla controls breathing, heart rate, and blood pressure automatically. Damage here is usually fatal."},
  {q:"What causes a 'runner's high'?",o:["Adrenaline","Endorphins","Dopamine"],a:1,e:"Endorphins bind to opioid receptors, reducing pain and producing euphoria during sustained exercise."},
  {q:"What is RNA made from DNA called?",o:["Translation","Transcription","Replication"],a:1,e:"Transcription: RNA polymerase reads DNA and builds complementary mRNA, which then travels to ribosomes for protein synthesis."},
  {q:"How many brain lobes per hemisphere?",o:["2","4","6"],a:1,e:"Frontal (decisions), parietal (sensation), temporal (hearing), and occipital (vision). 4 lobes x 2 hemispheres = 8 total."},
  {q:"What causes malaria?",o:["Bacteria","Virus","Protozoan parasite"],a:2,e:"Plasmodium parasites transmitted by Anopheles mosquitoes. They infect red blood cells, affecting ~250 million people yearly."},
  {q:"What is the largest artery?",o:["Aorta","Carotid","Femoral"],a:0,e:"The aorta is ~1 inch diameter, carrying oxygenated blood from heart to entire body. Blood pressure is highest here."},
  {q:"What is the main component of cell membranes?",o:["Carbohydrates","Proteins","Phospholipids"],a:2,e:"The phospholipid bilayer: hydrophilic heads and hydrophobic tails forming a flexible selective barrier."},
  {q:"How long for a red blood cell to circulate?",o:["About 5 seconds","About 20 seconds","About 2 minutes"],a:1,e:"~20 seconds per circuit. In its 120-day life, one RBC makes ~500,000 trips around your body!"},
  {q:"What enzyme unzips DNA?",o:["DNA polymerase","Helicase","Ligase"],a:1,e:"Helicase breaks hydrogen bonds between base pairs, 'unzipping' the double helix at ~10,000 RPM!"},
  {q:"Which biome has the most biodiversity?",o:["Temperate forest","Tropical rainforest","Coral reef"],a:1,e:"Rainforests cover 6% of Earth but contain 50%+ of all species. The Amazon alone has ~10% of all species."},
  {q:"What is the spleen's function?",o:["Produce bile","Filter blood & recycle RBCs","Regulate blood sugar"],a:1,e:"The spleen filters blood, removing old RBCs and recycling iron. It also stores white blood cells for emergencies."},
  {q:"What protein carries oxygen in blood?",o:["Albumin","Hemoglobin","Fibrinogen"],a:1,e:"Each hemoglobin has 4 iron atoms binding one O₂ each. One RBC has ~270 million hemoglobin molecules!"},
  {q:"What connects muscle to bone?",o:["Ligament","Tendon","Cartilage"],a:1,e:"Tendons are dense collagen fibers. The Achilles tendon withstands 1,000+ lbs of force during running."},
  {q:"What is the rarest blood type?",o:["AB negative","O negative","B negative"],a:0,e:"AB negative is found in <1% of people. But AB positive is the universal plasma donor."},
  {q:"What triggers fight or flight?",o:["Cortisol","Insulin","Adrenaline"],a:2,e:"Adrenaline from adrenal glands: heart rate up, blood to muscles, senses sharpened — all in seconds."},
  {q:"Which part of the eye detects color?",o:["Rods","Cones","Cornea"],a:1,e:"~6 million cones in 3 types (red, green, blue). Mantis shrimp have 16 types — imagine their color vision!"},
  {q:"What is an organism that makes its own food?",o:["Heterotroph","Autotroph","Decomposer"],a:1,e:"Autotrophs include plants, algae, and some bacteria — converting inorganic molecules into food via photosynthesis."},
  {q:"What is the longest cell in the body?",o:["Motor neuron","Muscle fiber","Intestinal cell"],a:0,e:"Motor neurons stretch from spinal cord to toe tip — over 1 meter long! By far the longest cells."},
  {q:"What brain structure regulates hunger?",o:["Thalamus","Hypothalamus","Hippocampus"],a:1,e:"The hypothalamus: hunger, thirst, temperature, sleep, hormones — your homeostasis center, only almond-sized."},
  {q:"Which macromolecule stores genetic info?",o:["Proteins","Lipids","Nucleic acids"],a:2,e:"DNA stores the blueprint; RNA reads and executes it. Together they're the information system of all known life."},
  {q:"What is convergent evolution?",o:["Species diverging","Unrelated species evolving similar traits","Genes transferring between species"],a:1,e:"Wings evolved independently in birds, bats, and insects. Similar environments produce similar solutions."},
  {q:"How many alveoli in the lungs?",o:["30 million","300 million","3 billion"],a:1,e:"~300 million alveoli = ~70 sq meters surface area. That's a tennis court folded inside your chest."},
  {q:"Which hormone regulates blood sugar?",o:["Insulin only","Glucagon only","Both together"],a:2,e:"Insulin lowers sugar; glucagon raises it. Together they maintain the precise balance your body needs."},
  {q:"How many unique antibodies can you make?",o:["~1 million","~1 billion","10+ billion"],a:2,e:"Through V(D)J recombination, your immune system generates 10+ billion unique antibodies — enough to recognize virtually anything."},
  {q:"What is the most abundant body protein?",o:["Hemoglobin","Collagen","Actin"],a:1,e:"Collagen is 25–35% of total protein — the structural scaffold of skin, bones, tendons. Your body's biological glue."},
  {q:"Which vitamin is essential for clotting?",o:["Vitamin K","Vitamin E","Vitamin B12"],a:0,e:"'K' stands for 'Koagulation' (German). Newborns get a vitamin K injection to prevent bleeding disorders."},
  {q:"Which organelle detoxifies substances?",o:["Smooth ER","Rough ER","Lysosome"],a:0,e:"The smooth ER detoxifies drugs, alcohol, and waste — especially in liver cells. Also synthesizes lipids."},
  {q:"What sugar is in DNA?",o:["Ribose","Deoxyribose","Glucose"],a:1,e:"Deoxyribose is ribose minus one oxygen ('deoxy'). This makes DNA more stable than RNA — perfect for long-term storage."},
  {q:"What is the diaphragm?",o:["A membrane around the brain","A dome-shaped breathing muscle","A heart valve"],a:1,e:"When the diaphragm contracts and flattens, it creates negative pressure drawing air into your lungs."},
  {q:"How old is the oldest known tree?",o:["~2,000 years","~5,000 years","~10,000 years"],a:1,e:"A bristlecone pine named Methuselah is 5,000+ years old — already ancient when the Egyptian pyramids were built."},
  // === VACCINES & PUBLIC HEALTH ===
  {q:"What year was the first vaccine created?",o:["1652","1796","1885"],a:1,e:"Edward Jenner created the smallpox vaccine in 1796 using cowpox material — the word 'vaccine' comes from 'vacca' (cow in Latin)."},
  {q:"Which disease was the first eradicated by vaccines?",o:["Polio","Smallpox","Measles"],a:1,e:"Smallpox was declared eradicated in 1980 after a global vaccination campaign. It killed ~300 million people in the 20th century alone before eradication."},
  {q:"How do mRNA vaccines work?",o:["Inject weakened virus","Teach cells to make spike protein","Alter your DNA"],a:1,e:"mRNA gives cells instructions to make a harmless piece of the virus's spike protein, training your immune system to recognize it. The mRNA degrades within days."},
  {q:"What does 'herd immunity' mean?",o:["Animals can't get sick","Enough people are immune to slow spread","Immunity from eating meat"],a:1,e:"When ~80–95% of a population is immune, the disease can't spread easily — protecting those who can't be vaccinated, like newborns and immunocompromised people."},
  {q:"How many lives do vaccines save per year globally?",o:["About 1 million","About 4 million","About 10 million"],a:1,e:"WHO estimates vaccines prevent 3.5–5 million deaths annually. Since 1974, immunization has saved an estimated 154 million lives."},
  {q:"What is an adjuvant in a vaccine?",o:["A preservative","An immune response booster","A flavor additive"],a:1,e:"Adjuvants (like aluminum salts) enhance the immune response, allowing vaccines to use less antigen and provide stronger, longer-lasting protection."},
  {q:"Which vaccine nearly eradicated polio worldwide?",o:["Salk (injected)","Sabin (oral)","Both together"],a:2,e:"Salk's inactivated vaccine (1955) and Sabin's oral vaccine (1961) together reduced polio by 99.9%. Only 2 countries still have endemic transmission."},
  {q:"What does WHO stand for?",o:["World Hospital Organization","World Health Organization","World Hygiene Office"],a:1,e:"The WHO coordinates international public health, leads vaccination campaigns, and responds to disease outbreaks affecting 194 member states."},
  {q:"How long did it take to develop the COVID-19 mRNA vaccines?",o:["~11 months","~3 years","~5 years"],a:0,e:"Moderna designed its vaccine in just 2 days after getting the viral sequence! Clinical trials and manufacturing took ~11 months total — fastest in history."},
  {q:"What is R₀ (R-naught)?",o:["Virus mutation rate","Average people one sick person infects","Recovery rate"],a:1,e:"R₀ measures how contagious a disease is. Measles has R₀ of 12–18 (extremely contagious). COVID-19 original strain was ~2–3. Below 1 means decline."},
  {q:"What percentage of children worldwide receive basic vaccines?",o:["About 50%","About 84%","About 99%"],a:1,e:"~84% of children receive basic immunizations, but that leaves ~20 million children unvaccinated each year — mostly in conflict zones and remote areas."},
  {q:"What is a 'live attenuated' vaccine?",o:["Contains a weakened form of the pathogen","Contains only dead virus","Contains synthetic chemicals"],a:0,e:"Live attenuated vaccines use a weakened version of the germ (like MMR, chickenpox). They create strong, long-lasting immunity, often with just 1–2 doses."},
  {q:"Which disease kills the most people globally each year?",o:["Malaria","Heart disease","Tuberculosis"],a:1,e:"Heart disease kills ~18 million people/year. But among infectious diseases, lower respiratory infections, TB, and diarrheal diseases are top killers."},
  {q:"What was the 1918 flu pandemic called?",o:["Bird Flu","Spanish Flu","Swine Flu"],a:1,e:"The 'Spanish Flu' infected ~500 million people (1/3 of the world) and killed 50–100 million. It didn't originate in Spain — Spain just reported it honestly."},
  {q:"What is antibiotic resistance?",o:["Humans becoming immune to antibiotics","Bacteria evolving to survive antibiotics","Antibiotics getting weaker over time"],a:1,e:"Bacteria evolve resistance through natural selection. Overuse/misuse accelerates this. The WHO calls it one of the biggest threats to global health."},
  // === GENE THERAPY ===
  {q:"What does CAR-T cell therapy do?",o:["Replaces bone marrow","Reprograms your T cells to attack cancer","Kills all immune cells"],a:1,e:"CAR-T engineers a patient's own T cells with a chimeric antigen receptor to recognize and destroy cancer cells. It's achieved complete remission in blood cancers where all else failed."},
  {q:"What is a base editor?",o:["A DNA-cutting enzyme","A tool that changes one DNA letter without cutting","A virus that inserts genes"],a:1,e:"Base editors chemically convert one base pair to another (e.g., C→T or A→G) without making double-strand breaks. Invented by David Liu's lab in 2016, they're far more precise than traditional CRISPR."},
  {q:"How many genetic diseases are caused by single-gene mutations?",o:["About 200","About 2,000","Over 7,000"],a:2,e:"Over 7,000 diseases in the OMIM database are caused by mutations in a single gene. Gene therapy aims to correct or compensate for each one — sickle cell, CF, Huntington's, and many more."},
  {q:"What was CRISPR originally discovered in?",o:["Human cells","Bacteria","Plants"],a:1,e:"CRISPR is a natural immune system in bacteria that remembers and destroys viral invaders. Jennifer Doudna and Emmanuelle Charpentier adapted it into a gene-editing tool, winning the 2020 Nobel Prize."},
  {q:"What is prime editing?",o:["The first gene edit ever done","A search-and-replace editor for DNA","Editing only the first gene in a sequence"],a:1,e:"Prime editing is David Liu's 'molecular word processor' — it searches for a target DNA sequence and writes in a precise correction without double-strand breaks. It can fix ~89% of known pathogenic mutations."},
  {q:"What virus is commonly used to deliver gene therapies?",o:["Adeno-associated virus (AAV)","Influenza","HIV"],a:0,e:"AAV is a harmless virus that efficiently enters human cells. Scientists hollow it out, insert a therapeutic gene, and it delivers the payload — like a biological FedEx truck for DNA."},
  {q:"What did the first FDA-approved gene therapy (Luxturna) treat?",o:["Cancer","Inherited blindness","Sickle cell disease"],a:1,e:"Luxturna (2017) delivers a working RPE65 gene directly into the retina, restoring vision in patients with inherited retinal dystrophy. Some patients saw stars for the first time."},
  {q:"What is an antisense oligonucleotide (ASO)?",o:["A synthetic DNA/RNA that silences specific genes","A new type of antibiotic","A protein that edits genes"],a:0,e:"ASOs are short synthetic nucleic acids that bind to messenger RNA, blocking production of disease-causing proteins. They're being used to treat Huntington's, ALS, and spinal muscular atrophy."},
  {q:"What is George Church known for in genetics?",o:["Discovering DNA","Pioneering genome engineering and synthetic biology","Inventing the microscope"],a:1,e:"George Church at Harvard is a pioneer of genome reading AND writing. His lab works on multiplexed gene editing, de-extinction, engineered disease resistance, and even age reversal in mammals."},
  {q:"Who invented CRISPR gene editing?",o:["David Liu","Jennifer Doudna & Emmanuelle Charpentier","George Church"],a:1,e:"Jennifer Doudna (UC Berkeley) and Emmanuelle Charpentier demonstrated CRISPR-Cas9 as a programmable gene-editing tool in 2012, winning the 2020 Nobel Prize in Chemistry."},
{q:"What is the only organ that can feel no pain?",o:["Kidneys","Brain","Spleen"],a:1,e:"The brain has no pain receptors (nociceptors). Neurosurgeons can operate on brain tissue while patients are awake and talking."},
{q:"How many liters of saliva does a person produce per day?",o:["About 0.2 liters","About 1 liter","About 3 liters"],a:1,e:"Your salivary glands produce roughly 1 liter daily. Over a lifetime, that's enough to fill two swimming pools."},
{q:"Which part of the body has the thinnest skin?",o:["Eyelids","Fingertips","Earlobes"],a:0,e:"Eyelid skin is only about 0.5 mm thick, roughly ten times thinner than the skin on the soles of your feet."},
{q:"What percentage of your body heat is lost through your head?",o:["About 10%","About 40%","About 70%"],a:0,e:"The myth says 40-50%, but studies show only about 10% of body heat escapes through the head, proportional to its surface area."},
{q:"How many times per minute do you blink on average?",o:["5-6 times","15-20 times","30-35 times"],a:1,e:"You blink 15-20 times per minute, spending about 10% of your waking hours with your eyes closed without realizing it."},
{q:"What is the pineal gland responsible for producing?",o:["Adrenaline","Melatonin","Serotonin"],a:1,e:"The pineal gland produces melatonin in response to darkness, regulating your circadian rhythm and sleep-wake cycle."},
{q:"How long does it take for food to travel through the entire digestive system?",o:["6-8 hours","24-72 hours","5-7 days"],a:1,e:"Complete digestion typically takes 24-72 hours. Food spends 6-8 hours in the stomach, then moves through about 25 feet of intestine."},
{q:"Which type of white blood cell is most abundant?",o:["Neutrophils","Lymphocytes","Eosinophils"],a:0,e:"Neutrophils make up 50-70% of all white blood cells and are the first responders to bacterial infections, engulfing invaders."},
{q:"What is the name of the fluid that cushions the brain?",o:["Plasma","Cerebrospinal fluid","Synovial fluid"],a:1,e:"Cerebrospinal fluid surrounds the brain and spinal cord, providing buoyancy, protection, and waste removal. About 150 mL is present at any time."},
{q:"How many sweat glands does the average person have?",o:["About 200,000","About 2 million","About 20 million"],a:1,e:"Roughly 2-4 million eccrine sweat glands cover your body. Feet alone have about 250,000 glands, which is why they sweat so much."},
{q:"What is the name of the tissue that connects bone to bone?",o:["Tendon","Ligament","Fascia"],a:1,e:"Ligaments are tough fibrous connective tissue that stabilize joints. The ACL in the knee is one of the most commonly injured ligaments."},
{q:"Which gland is called the 'master gland' of the endocrine system?",o:["Thyroid","Pituitary","Adrenal"],a:1,e:"The pituitary gland, about the size of a pea, controls most other endocrine glands and influences growth, metabolism, and reproduction."},
{q:"What causes goosebumps?",o:["Blood rushing to the skin","Tiny muscles pulling hair follicles","Nerve endings contracting"],a:1,e:"Arrector pili muscles contract, pulling hair follicles upright. In our furry ancestors this trapped air for warmth or made them look bigger to predators."},
{q:"How fast does a sneeze travel?",o:["About 20 mph","About 100 mph","About 300 mph"],a:1,e:"A sneeze expels air at roughly 100 mph, launching about 100,000 germs into the air and traveling up to 26 feet."},
{q:"What is the corpus callosum?",o:["A bone in the skull","A nerve bundle connecting brain hemispheres","A muscle in the heart"],a:1,e:"The corpus callosum contains about 200 million nerve fibers connecting the left and right brain hemispheres, allowing them to communicate."},
{q:"How many distinct facial expressions can humans make?",o:["About 20","About 100","Over 10,000"],a:2,e:"The 43 muscles in the human face can produce over 10,000 distinct expressions, making our faces the most expressive of any animal."},
{q:"What is the vagus nerve?",o:["A nerve in the leg","The longest cranial nerve connecting brain to gut","A nerve only in the face"],a:1,e:"The vagus nerve runs from the brainstem to the abdomen, controlling heart rate, digestion, and immune response. It is a key part of the gut-brain axis."},
{q:"How far can a flea jump relative to its body size?",o:["10 times its length","80 times its length","150 times its length"],a:2,e:"Fleas can jump about 150 times their body length, equivalent to a human jumping over a 75-story building, using elastic energy stored in their legs."},
{q:"Which bird can fly backwards?",o:["Kingfisher","Hummingbird","Swift"],a:1,e:"Hummingbirds have a unique ball-and-socket shoulder joint and can rotate their wings 180 degrees, allowing hovering and backward flight."},
{q:"How many species of ants exist on Earth?",o:["About 2,000","About 14,000","About 100,000"],a:1,e:"Over 14,000 known ant species exist, with possibly thousands more undiscovered. Their combined biomass roughly equals that of all humans."},
{q:"Which animal has the strongest bite force?",o:["Great white shark","Saltwater crocodile","Hippopotamus"],a:1,e:"Saltwater crocodiles have a bite force of about 3,700 PSI, the strongest ever measured in a living animal, far exceeding any shark or big cat."},
{q:"What is unique about a platypus among mammals?",o:["It lays eggs","It has no fur","It has six legs"],a:0,e:"The platypus is one of only five surviving species of monotremes, egg-laying mammals. Males also have venomous spurs on their hind legs."},
{q:"How do dolphins sleep without drowning?",o:["They hold their breath all night","Half their brain sleeps at a time","They float on the surface"],a:1,e:"Dolphins use unihemispheric sleep, resting one brain hemisphere while the other stays alert to breathe and watch for predators."},
{q:"Which insect has the shortest adult lifespan?",o:["Fruit fly","Mayfly","Mosquito"],a:1,e:"Some mayfly species live only 5 minutes to 24 hours as adults, just long enough to mate and lay eggs. Their aquatic larval stage lasts years."},
{q:"What percentage of animal species are invertebrates?",o:["About 50%","About 75%","About 97%"],a:2,e:"Roughly 97% of all known animal species lack a backbone. Insects alone account for about 80% of all described animal species."},
{q:"How does the archerfish catch its prey?",o:["Jumping out of water","Shooting jets of water at insects","Using bioluminescence"],a:1,e:"Archerfish spit precise jets of water up to 3 meters to knock insects off overhanging vegetation, compensating for light refraction at the water surface."},
{q:"Which animal can survive in the vacuum of space?",o:["Cockroach","Tardigrade","Scorpion"],a:1,e:"Tardigrades (water bears) enter a dehydrated state called a tun, surviving extreme temperatures, radiation, and the vacuum of space for over 10 days."},
{q:"What is the fastest land animal over short distances?",o:["Cheetah","Pronghorn antelope","Greyhound"],a:0,e:"Cheetahs reach 70 mph in short bursts, accelerating faster than most sports cars. However, the pronghorn antelope is faster over long distances."},
{q:"How do electric eels generate electricity?",o:["Chemical reactions in their skin","Stacked electrocyte cells acting like batteries","Friction from swimming"],a:1,e:"Electric eels have about 6,000 electrocyte cells stacked like batteries in series, generating up to 860 volts to stun prey and deter predators."},
{q:"Which mammal has the densest fur?",o:["Polar bear","Sea otter","Chinchilla"],a:1,e:"Sea otters have about 1 million hairs per square inch, the densest fur of any mammal. They rely on it rather than blubber for insulation."},
{q:"What unique ability do mimic octopuses have?",o:["Changing color only","Impersonating other species' shapes and behavior","Producing ink clouds"],a:1,e:"Mimic octopuses can impersonate over 15 different species including lionfish, flatfish, and sea snakes by changing shape, color, and movement patterns."},
{q:"How many lenses does a dragonfly's eye have?",o:["About 100","About 3,000","About 30,000"],a:2,e:"Each dragonfly compound eye contains roughly 30,000 individual lenses called ommatidia, giving them nearly 360-degree vision to catch prey mid-flight."},
{q:"Which animal produces the loudest sound?",o:["Blue whale","Howler monkey","Sperm whale"],a:2,e:"Sperm whale clicks reach 230 decibels, louder than a jet engine. Blue whale calls are louder in sustained low-frequency sound, but peak intensity belongs to the sperm whale."},
{q:"What is a group of flamingos called?",o:["A flock","A flamboyance","A cluster"],a:1,e:"A group of flamingos is called a flamboyance. They get their pink color from carotenoid pigments in the algae and crustaceans they eat."},
{q:"What gas do plants absorb during photosynthesis?",o:["Oxygen","Nitrogen","Carbon dioxide"],a:2,e:"Plants absorb CO2 and water, using sunlight to convert them into glucose and oxygen. A single large tree can absorb about 48 pounds of CO2 per year."},
{q:"What is the largest living organism on Earth by area?",o:["Blue whale","A honey fungus colony in Oregon","A giant sequoia"],a:1,e:"The Armillaria ostoyae fungus in Oregon's Blue Mountains spans 2,385 acres (about 3.7 square miles) and is estimated to be 2,400 years old."},
{q:"Which plant grows the fastest?",o:["Bamboo","Kudzu","Giant kelp"],a:0,e:"Some bamboo species grow up to 91 cm (35 inches) per day. You can literally watch bamboo grow if you are patient enough."},
{q:"What is the role of mycorrhizal fungi in ecosystems?",o:["They decompose dead animals","They form symbiotic networks with plant roots","They produce oxygen"],a:1,e:"Mycorrhizal fungi extend plant root networks by up to 700 times, exchanging soil nutrients for sugars. About 90% of land plants depend on these partnerships."},
{q:"How do Venus flytraps know when to snap shut?",o:["They detect light changes","Trigger hairs must be touched twice in 20 seconds","They sense chemical signals"],a:1,e:"Two touches within 20 seconds on the trigger hairs generate an electrical signal that causes rapid water movement in the cells, snapping the trap shut in 100 milliseconds."},
{q:"What is the term for plants that grow on other plants?",o:["Parasites","Epiphytes","Saprophytes"],a:1,e:"Epiphytes like orchids and bromeliads grow on other plants for physical support but are not parasites. They get nutrients from air, rain, and debris."},
{q:"What percentage of Earth's oxygen comes from ocean phytoplankton?",o:["About 20%","About 50%","About 80%"],a:1,e:"Marine phytoplankton produce roughly 50-80% of Earth's oxygen through photosynthesis. Prochlorococcus, the smallest photosynthetic organism, is the most abundant."},
{q:"What is allelopathy?",o:["Plants communicating through sound","Plants releasing chemicals that inhibit nearby plants","Plants sharing nutrients"],a:1,e:"Some plants like black walnut trees release chemicals called juglone that suppress the growth of competing plants nearby, a form of chemical warfare."},
{q:"Which part of the plant conducts water upward?",o:["Phloem","Xylem","Cambium"],a:1,e:"Xylem vessels transport water and minerals from roots to leaves using a combination of capillary action, root pressure, and transpiration pull."},
{q:"What is the largest seed in the plant kingdom?",o:["Coconut","Coco de mer","Avocado"],a:1,e:"The coco de mer palm produces seeds weighing up to 25 kg (55 lbs), found naturally only in the Seychelles. They can take 6-7 years to mature."},
{q:"What is a keystone species?",o:["The most abundant species in an ecosystem","A species whose removal causes ecosystem collapse","The oldest species in a region"],a:1,e:"Keystone species like sea otters or wolves have disproportionately large effects on their ecosystem relative to their abundance. Removing them triggers cascading changes."},
{q:"How do plants defend themselves against herbivores?",o:["Only with thorns and spines","By producing toxic or distasteful chemicals","They cannot defend themselves"],a:1,e:"Plants produce a vast array of chemical defenses including alkaloids, tannins, and terpenes. Some even release volatile chemicals to attract predators of the herbivores."},
{q:"What is the oldest known seed to be successfully germinated?",o:["A 200-year-old lotus seed","A 2,000-year-old date palm seed","A 32,000-year-old plant from permafrost"],a:2,e:"Russian scientists regenerated Silene stenophylla from 32,000-year-old fruit tissue found in Siberian permafrost, making it the oldest plant ever revived."},
{q:"What is a biome?",o:["A single organism","A large community of plants and animals defined by climate","A type of cell"],a:1,e:"Biomes are large-scale ecological areas like tundra, desert, or tropical rainforest, defined primarily by climate, precipitation, and the dominant vegetation."},
{q:"How do mangrove trees survive in saltwater?",o:["They absorb salt as nutrients","They filter salt out at their roots or excrete it through leaves","They are freshwater plants"],a:1,e:"Mangroves use ultrafiltration at their roots to exclude up to 90% of salt, and some species excrete excess salt through special glands in their leaves."},
{q:"What is the fastest-closing plant trap?",o:["Venus flytrap","Bladderwort","Sundew"],a:1,e:"The aquatic bladderwort (Utricularia) snaps shut in less than 1 millisecond, about 100 times faster than a Venus flytrap, creating a vacuum to suck in tiny prey."},
{q:"What phenomenon causes autumn leaves to change color?",o:["New pigments are created by cold weather","Green chlorophyll breaks down revealing hidden pigments","Leaves absorb different wavelengths of light"],a:1,e:"As chlorophyll degrades in autumn, yellow and orange carotenoid pigments that were always present become visible. Red anthocyanins are newly produced in some species."},
{q:"What is the most abundant element in the universe?",o:["Helium","Oxygen","Hydrogen"],a:2,e:"Hydrogen makes up about 75% of all normal matter by mass and about 90% by number of atoms. It was the first element formed after the Big Bang."},
{q:"What makes noble gases unreactive?",o:["They have no electrons","Their outer electron shells are full","They are too heavy"],a:1,e:"Noble gases like helium, neon, and argon have complete outer electron shells, making them extremely stable and reluctant to form chemical bonds."},
{q:"What is the pH of pure water?",o:["0","7","14"],a:1,e:"Pure water has a pH of 7, which is neutral. Below 7 is acidic, above 7 is basic. The pH scale is logarithmic, so pH 6 is ten times more acidic than pH 7."},
{q:"Which element has the chemical symbol 'W'?",o:["Tungsten","Vanadium","Thallium"],a:0,e:"Tungsten's symbol W comes from its German name Wolfram. It has the highest melting point of any pure element at 3,422 degrees Celsius."},
{q:"What type of bond involves sharing electrons?",o:["Ionic bond","Covalent bond","Metallic bond"],a:1,e:"In covalent bonds, atoms share electron pairs rather than transferring them. Most molecules in living organisms, including DNA and proteins, use covalent bonds."},
{q:"What is an isotope?",o:["An atom with different numbers of electrons","An atom with different numbers of neutrons","An atom with different numbers of protons"],a:1,e:"Isotopes have the same number of protons but different neutrons. Carbon-12 and Carbon-14 are isotopes. Carbon-14 is used in radiocarbon dating."},
{q:"Which acid is found in your stomach?",o:["Sulfuric acid","Hydrochloric acid","Citric acid"],a:1,e:"Your stomach produces hydrochloric acid at pH 1.5-3.5, strong enough to dissolve metal. A thick mucus lining protects the stomach from digesting itself."},
{q:"What is Avogadro's number approximately?",o:["6.02 x 10^23","3.14 x 10^15","9.81 x 10^20"],a:0,e:"Avogadro's number (6.022 x 10^23) defines a mole. One mole of water molecules would fill about 18 milliliters, roughly a tablespoon."},
{q:"What element is liquid at room temperature besides mercury?",o:["Gallium","Bromine","Cesium"],a:1,e:"Bromine is the only non-metal that is liquid at standard room temperature (25C). Gallium melts just above room temperature at 29.8C and would melt in your hand."},
{q:"What is an exothermic reaction?",o:["A reaction that absorbs heat","A reaction that releases heat","A reaction that produces light only"],a:1,e:"Exothermic reactions release energy as heat to the surroundings. Combustion, rusting, and even mixing cement with water are everyday exothermic reactions."},
{q:"Which scientist created the first periodic table?",o:["John Dalton","Dmitri Mendeleev","Antoine Lavoisier"],a:1,e:"Mendeleev published his periodic table in 1869, boldly leaving gaps for undiscovered elements and predicting their properties. His predictions proved remarkably accurate."},
{q:"What is the lightest metal?",o:["Aluminum","Lithium","Magnesium"],a:1,e:"Lithium has a density of only 0.534 g/cm3, about half the density of water. It is so light it floats, and it is the key element in modern rechargeable batteries."},
{q:"What causes iron to rust?",o:["Reaction with nitrogen","Oxidation by oxygen and water","Exposure to sunlight"],a:1,e:"Rust is iron oxide formed when iron reacts with oxygen in the presence of water. This electrochemical process costs the global economy hundreds of billions annually."},
{q:"What is the hardest natural substance on Earth?",o:["Diamond","Graphene","Titanium"],a:0,e:"Diamond scores 10 on the Mohs hardness scale. Each carbon atom bonds to four others in a rigid tetrahedral structure, making it the hardest natural material."},
{q:"What are the three states of matter most commonly taught?",o:["Solid, liquid, gas","Solid, liquid, plasma","Gas, plasma, condensate"],a:0,e:"Solid, liquid, and gas are the classic three states. Plasma is actually the most common state in the universe, found in stars and lightning."},
{q:"What is a catalyst?",o:["A substance consumed in a reaction","A substance that speeds up a reaction without being consumed","An element that slows reactions"],a:1,e:"Catalysts lower the activation energy of reactions. Enzymes are biological catalysts that speed up reactions in your body by factors of millions."},
{q:"Which element is essential for all organic chemistry?",o:["Nitrogen","Carbon","Silicon"],a:1,e:"Carbon can form four covalent bonds and chain with itself indefinitely, creating the immense variety of molecules needed for life. No other element is as versatile."},
{q:"What is the speed of light in a vacuum?",o:["300,000 km/s","150,000 km/s","1 million km/s"],a:0,e:"Light travels at approximately 299,792 km/s. At this speed, it takes about 8 minutes and 20 seconds for sunlight to reach Earth."},
{q:"What is the Heisenberg Uncertainty Principle?",o:["Energy cannot be created or destroyed","You cannot know both position and momentum precisely","Every action has an equal reaction"],a:1,e:"The more precisely you measure a particle's position, the less precisely you can know its momentum, and vice versa. This is a fundamental limit of nature, not a measurement error."},
{q:"What keeps planets in orbit around the Sun?",o:["Magnetism","Gravity","Dark energy"],a:1,e:"Gravity creates a curved path for planets. A planet's forward momentum and the Sun's gravitational pull balance to create a stable elliptical orbit."},
{q:"What is absolute zero?",o:["-273.15 degrees Celsius","0 degrees Celsius","-100 degrees Celsius"],a:0,e:"Absolute zero (0 Kelvin or -273.15 C) is the theoretical lowest temperature where all molecular motion would cease. It can never be fully reached."},
{q:"What phenomenon explains why the sky is blue?",o:["Reflection from oceans","Rayleigh scattering","Absorption by ozone"],a:1,e:"Rayleigh scattering causes shorter blue wavelengths to scatter more than longer red wavelengths as sunlight passes through the atmosphere, making the sky appear blue."},
{q:"What did the double-slit experiment demonstrate?",o:["Light is only a wave","Light is only a particle","Light behaves as both wave and particle"],a:2,e:"The double-slit experiment showed wave-particle duality, one of the most fundamental and strange results in physics. Even single photons create interference patterns."},
{q:"What is the unit of electrical resistance?",o:["Watt","Ohm","Ampere"],a:1,e:"The ohm, named after Georg Simon Ohm, measures electrical resistance. Ohm's Law (V=IR) relates voltage, current, and resistance in a circuit."},
{q:"What is entropy?",o:["A measure of disorder in a system","A measure of energy input","A type of force"],a:0,e:"Entropy always increases in an isolated system according to the second law of thermodynamics. This is why ice melts, rooms get messy, and time flows forward."},
{q:"What particle carries the electromagnetic force?",o:["Gluon","Photon","W boson"],a:1,e:"Photons are massless force carriers (gauge bosons) for electromagnetism, responsible for light, radio waves, and the repulsion between like charges."},
{q:"How much of the universe is dark matter and dark energy?",o:["About 27%","About 68%","About 95%"],a:2,e:"About 95% of the universe is dark matter (~27%) and dark energy (~68%). Ordinary matter that we can see and touch makes up only about 5%."},
{q:"What happens to time near a massive object according to general relativity?",o:["Time speeds up","Time slows down","Time reverses"],a:1,e:"Gravitational time dilation means clocks tick slower in stronger gravitational fields. GPS satellites must correct for this effect to remain accurate."},
{q:"What is superconductivity?",o:["Conducting heat perfectly","Zero electrical resistance at low temperatures","Faster-than-light signal transmission"],a:1,e:"Below a critical temperature, some materials lose all electrical resistance. Current flows forever without energy loss. This enables MRI machines and particle accelerators."},
{q:"What is the Doppler effect?",o:["Light bending around massive objects","Change in frequency of waves from a moving source","Particles tunneling through barriers"],a:1,e:"The Doppler effect explains why an ambulance siren sounds higher-pitched approaching you and lower-pitched moving away. It applies to both sound and light."},
{q:"What force holds the nucleus of an atom together?",o:["Electromagnetic force","Strong nuclear force","Gravitational force"],a:1,e:"The strong nuclear force is about 100 times stronger than electromagnetism but only operates at subatomic distances. It overcomes proton repulsion to bind the nucleus."},
{q:"What is quantum tunneling?",o:["Particles passing through energy barriers they classically could not","Creating wormholes between atoms","Electrons orbiting faster than light"],a:0,e:"Quantum tunneling allows particles to pass through barriers they lack the energy to overcome classically. It is essential for nuclear fusion in stars and modern electronics."},
{q:"Who proposed the theory of special relativity?",o:["Isaac Newton","Albert Einstein","Niels Bohr"],a:1,e:"Einstein published special relativity in 1905, showing that the speed of light is constant for all observers and that mass and energy are equivalent (E=mc2)."},
{q:"What is a black body in physics?",o:["A black hole","An idealized object that absorbs all radiation","A dark matter particle"],a:1,e:"A black body absorbs all incoming electromagnetic radiation regardless of frequency. Its emission spectrum depends only on temperature, which led to the birth of quantum mechanics."},
{q:"How many moons does Jupiter have?",o:["16","At least 95","Exactly 50"],a:1,e:"Jupiter has at least 95 confirmed moons as of recent surveys. The four largest (Io, Europa, Ganymede, Callisto) were discovered by Galileo in 1610."},
{q:"What is a neutron star?",o:["A star made entirely of neutrons","The collapsed core of a massive star","A star that emits no light"],a:1,e:"When massive stars explode in supernovae, their cores collapse. The result is incredibly dense: a teaspoon of neutron star material weighs about 6 billion tons."},
{q:"What is the Great Red Spot on Jupiter?",o:["A volcanic crater","A persistent anticyclonic storm","An impact scar from a comet"],a:1,e:"The Great Red Spot is a storm larger than Earth that has been raging for at least 350 years, with wind speeds reaching 400 mph."},
{q:"Which planet rotates on its side?",o:["Neptune","Venus","Uranus"],a:2,e:"Uranus has an axial tilt of 98 degrees, likely caused by a massive collision billions of years ago. This means its poles take turns facing the Sun."},
{q:"What is the closest star to our Sun?",o:["Sirius","Proxima Centauri","Alpha Centauri A"],a:1,e:"Proxima Centauri is about 4.24 light-years away. It is a red dwarf in the Alpha Centauri system and has at least one planet in its habitable zone."},
{q:"What causes a solar eclipse?",o:["Earth passes between Sun and Moon","Moon passes between Sun and Earth","Sun moves behind another star"],a:1,e:"The Moon's shadow falls on Earth during a solar eclipse. By cosmic coincidence, the Moon is 400x smaller than the Sun but 400x closer, making them appear the same size."},
{q:"What is the Oort Cloud?",o:["A nebula near our solar system","A distant shell of icy bodies surrounding our solar system","A cloud of gas on Jupiter"],a:1,e:"The Oort Cloud is a theorized spherical shell of icy objects extending up to 2 light-years from the Sun, believed to be the source of long-period comets."},
{q:"How old is the universe?",o:["About 4.5 billion years","About 13.8 billion years","About 100 billion years"],a:1,e:"The universe is approximately 13.8 billion years old based on cosmic microwave background measurements. Earth is about 4.5 billion years old, roughly a third of that."},
{q:"What are pulsars?",o:["Dying red giant stars","Rapidly rotating neutron stars emitting beams of radiation","Colliding galaxies"],a:1,e:"Pulsars rotate up to 716 times per second, sweeping beams of radiation like cosmic lighthouses. They were initially nicknamed LGM (Little Green Men) before being understood."},
{q:"What is the Kuiper Belt?",o:["A ring of asteroids between Mars and Jupiter","A region of icy bodies beyond Neptune","A belt of debris around Saturn"],a:1,e:"The Kuiper Belt extends from Neptune's orbit outward and contains dwarf planets like Pluto and Eris, plus millions of icy remnants from the solar system's formation."},
{q:"Which planet has the tallest known mountain in our solar system?",o:["Earth","Mars","Venus"],a:1,e:"Olympus Mons on Mars stands about 21.9 km (72,000 ft) tall, nearly three times the height of Mount Everest. It is a shield volcano roughly the size of Arizona."},
{q:"What is cosmic microwave background radiation?",o:["Radiation from the Sun","Leftover glow from the Big Bang","Radio signals from other galaxies"],a:1,e:"The CMB is thermal radiation from about 380,000 years after the Big Bang, now cooled to 2.7 Kelvin. It fills all of space and was accidentally discovered in 1965."},
{q:"What is a white dwarf?",o:["A small, young star","The hot, dense remnant of a low-mass star","A type of galaxy"],a:1,e:"When stars like our Sun exhaust their fuel, they shed their outer layers and leave behind a white dwarf about the size of Earth but with a mass close to the Sun's."},
{q:"How long is one day on Venus?",o:["About 24 hours","About 116 Earth days","About 243 Earth days"],a:2,e:"Venus rotates so slowly that one Venusian day (243 Earth days) is longer than its year (225 Earth days). It also rotates backwards compared to most planets."},
{q:"What is the event horizon of a black hole?",o:["The center of a black hole","The boundary beyond which nothing can escape","The area where light bends around it"],a:1,e:"The event horizon is the point of no return. Beyond it, the escape velocity exceeds the speed of light, so nothing, not even light, can get out."},
{q:"Which spacecraft first landed on Mars?",o:["Viking 1","Spirit rover","Curiosity rover"],a:0,e:"NASA's Viking 1 successfully landed on Mars on July 20, 1976, and transmitted the first photos from the Martian surface. It operated for over 6 years."},
{q:"What makes up Saturn's rings?",o:["Solid rock bands","Billions of ice and rock particles","Gases trapped by gravity"],a:1,e:"Saturn's rings are made of billions of particles ranging from tiny grains to house-sized chunks, mostly water ice with some rocky debris."},
{q:"What era did the dinosaurs live in?",o:["Paleozoic","Mesozoic","Cenozoic"],a:1,e:"The Mesozoic Era (252-66 million years ago) is divided into the Triassic, Jurassic, and Cretaceous periods. Dinosaurs dominated for about 165 million years."},
{q:"What caused the mass extinction that killed the dinosaurs?",o:["A supervolcano","An asteroid impact","An ice age"],a:1,e:"A 10 km asteroid struck what is now the Yucatan Peninsula 66 million years ago, creating the Chicxulub crater and triggering global environmental catastrophe."},
{q:"What is natural selection?",o:["Organisms choosing their mates","Survival and reproduction of organisms best suited to their environment","Random genetic changes over time"],a:1,e:"Darwin's key insight: organisms with traits better suited to their environment survive and reproduce more, passing those advantageous traits to offspring."},
{q:"What is the oldest known fossil?",o:["About 500 million years old","About 1 billion years old","About 3.5 billion years old"],a:2,e:"Stromatolite fossils from Western Australia are about 3.5 billion years old, formed by ancient cyanobacteria. These microbial mats were among the first life on Earth."},
{q:"What was the Cambrian Explosion?",o:["A volcanic event","A rapid diversification of animal life","The formation of Earth's atmosphere"],a:1,e:"About 541 million years ago, most major animal phyla appeared in the fossil record over a geologically brief 20 million years. The cause remains one of evolution's great puzzles."},
{q:"Which species is the closest living relative of T. rex?",o:["Komodo dragon","Chicken","Crocodile"],a:1,e:"Protein analysis of preserved T. rex soft tissue confirmed that birds, including chickens, are the closest living relatives of tyrannosaurs. Dinosaurs never really went extinct."},
{q:"What is genetic drift?",o:["Intentional gene modification","Random changes in gene frequency in small populations","Movement of organisms to new habitats"],a:1,e:"Genetic drift is evolution by chance rather than selection. In small populations, random events can cause alleles to increase or decrease regardless of their fitness benefit."},
{q:"What were the first animals to live on land?",o:["Amphibians","Arthropods","Reptiles"],a:1,e:"Arthropods like millipede ancestors colonized land about 450 million years ago, well before the first tetrapods. They followed plants that had arrived even earlier."},
{q:"How many mass extinctions has Earth experienced?",o:["2","5","12"],a:1,e:"Earth has had five major mass extinctions. The largest, the Permian-Triassic event 252 million years ago, killed about 96% of all marine species and 70% of land vertebrates."},
{q:"What is a homologous structure?",o:["Structures with similar function but different origins","Structures with similar origin but possibly different functions","Identical structures in all animals"],a:1,e:"A human arm, whale flipper, and bat wing share the same bone structure despite different functions, revealing their common evolutionary ancestor."},
{q:"What is punctuated equilibrium?",o:["Evolution happening at a constant rate","Long periods of stability interrupted by rapid change","Extinction followed by creation"],a:1,e:"Proposed by Gould and Eldredge, this theory suggests species are mostly stable, with evolution occurring in rapid bursts associated with speciation events."},
{q:"When did the first flowers appear on Earth?",o:["About 500 million years ago","About 130 million years ago","About 30 million years ago"],a:1,e:"Flowering plants (angiosperms) first appeared about 130 million years ago in the Cretaceous period and rapidly diversified. Darwin called their rapid rise an 'abominable mystery.'"},
{q:"What is an example of vestigial structure in humans?",o:["The heart","The appendix","The liver"],a:1,e:"The human appendix is a reduced remnant of a larger cecum used by our herbivorous ancestors to digest cellulose. Wisdom teeth and the tailbone are other vestigial structures."},
{q:"What type of fossil forms when minerals replace original bone?",o:["Cast fossil","Petrified fossil","Trace fossil"],a:1,e:"Petrification occurs when minerals like silica gradually replace organic material molecule by molecule, preserving the original structure in stone over millions of years."},
{q:"What is adaptive radiation?",o:["Organisms adapting to radiation from the Sun","A single species diversifying into many forms to fill different niches","Nuclear radiation causing mutations"],a:1,e:"Darwin's finches in the Galapagos are a classic example: one ancestor species evolved into 13+ species with different beak shapes adapted to different food sources."},
{q:"What is the molecular clock in evolution?",o:["A gene that controls aging","Using mutation rates to estimate when species diverged","A cellular timer for cell division"],a:1,e:"DNA accumulates mutations at roughly constant rates. By comparing sequences between species, scientists can estimate when their last common ancestor lived."},
{q:"What is sexual selection?",o:["Choosing mates based on traits that may not aid survival","Natural selection only during mating season","Selection by scientists in a lab"],a:0,e:"Sexual selection explains extravagant traits like peacock tails. Darwin proposed that mate choice drives evolution of traits that may actually reduce survival but increase reproductive success."},
{q:"What is the placebo effect?",o:["A drug interaction","Improvement from an inert treatment due to belief","A side effect of surgery"],a:1,e:"Patients given sugar pills can show real physiological improvements. Brain imaging shows placebos actually trigger endorphin release and neural changes."},
{q:"Who discovered penicillin?",o:["Louis Pasteur","Alexander Fleming","Joseph Lister"],a:1,e:"Alexander Fleming noticed mold killing bacteria in a Petri dish in 1928. Penicillin became the first mass-produced antibiotic and has saved an estimated 200 million lives."},
{q:"What is an autoimmune disease?",o:["A disease caused by vaccines","The immune system attacking the body's own tissues","A disease with no immune response"],a:1,e:"In autoimmune diseases like lupus, type 1 diabetes, and rheumatoid arthritis, the immune system mistakenly identifies healthy cells as threats and attacks them."},
{q:"What is the leading cause of death worldwide?",o:["Cancer","Cardiovascular disease","Infectious disease"],a:1,e:"Cardiovascular disease causes about 17.9 million deaths per year globally, accounting for 32% of all deaths. Many cases are preventable through lifestyle changes."},
{q:"What does an MRI scan use to create images?",o:["X-rays","Strong magnetic fields and radio waves","Ultrasound waves"],a:1,e:"MRI uses powerful magnets to align hydrogen atoms in the body, then radio pulses knock them out of alignment. As they realign, they emit signals that create detailed images."},
{q:"What is the function of the lymphatic system?",o:["Producing red blood cells","Draining excess fluid and fighting infection","Regulating body temperature"],a:1,e:"The lymphatic system returns excess interstitial fluid to blood, filters pathogens through lymph nodes, and transports immune cells. It has no pump and relies on muscle movement."},
{q:"What is anesthesia?",o:["Pain medication taken orally","A state of controlled, temporary loss of sensation or consciousness","A type of antibiotic"],a:1,e:"Before anesthesia was developed in the 1840s, surgery was done on conscious patients. Ether and chloroform revolutionized medicine by making painless surgery possible."},
{q:"What is the difference between a pandemic and an epidemic?",o:["Pandemics are more deadly","Pandemics spread across multiple countries or continents","There is no difference"],a:1,e:"An epidemic is a disease outbreak in a specific region, while a pandemic spreads across multiple countries or continents, affecting a much larger population."},
{q:"What organ does dialysis replace the function of?",o:["Liver","Kidney","Pancreas"],a:1,e:"Dialysis filters waste products and excess fluid from the blood when kidneys fail. A typical session takes 3-5 hours and is needed about three times per week."},
{q:"What is a prion disease?",o:["A disease caused by misfolded proteins","A viral brain infection","A bacterial blood disease"],a:0,e:"Prions are misfolded proteins that cause other proteins to misfold, creating a chain reaction. They cause fatal brain diseases like mad cow disease and Creutzfeldt-Jakob disease."},
{q:"Who performed the first successful heart transplant?",o:["Michael DeBakey","Christiaan Barnard","Denton Cooley"],a:1,e:"Christiaan Barnard performed the first human heart transplant in Cape Town, South Africa, in 1967. The patient survived 18 days before dying of pneumonia."},
{q:"What is the blood-brain barrier?",o:["A bone protecting the brain","A selective membrane controlling what enters the brain from blood","A layer of fat around the brain"],a:1,e:"The blood-brain barrier is formed by tightly packed endothelial cells that prevent most pathogens and large molecules from entering the brain, but this also makes drug delivery difficult."},
{q:"What are stem cells?",o:["Cells that can only become blood cells","Undifferentiated cells that can develop into many cell types","Dead cells waiting to be replaced"],a:1,e:"Stem cells can self-renew and differentiate into specialized cells. Embryonic stem cells can become any cell type, while adult stem cells are more limited."},
{q:"What vitamin deficiency causes scurvy?",o:["Vitamin A","Vitamin C","Vitamin D"],a:1,e:"Scurvy results from vitamin C deficiency, which impairs collagen synthesis. It plagued sailors for centuries until James Lind showed citrus fruits prevented it in 1747."},
{q:"What is MRSA?",o:["A type of cancer","Methicillin-resistant Staphylococcus aureus","A genetic disorder"],a:1,e:"MRSA is a staph bacterium resistant to many common antibiotics. It is a major hospital-acquired infection and a stark example of the antibiotic resistance crisis."},
{q:"What is the purpose of a fever?",o:["It is always harmful and serves no purpose","It helps the immune system fight infection","It kills brain cells to slow down thinking"],a:1,e:"Moderate fevers enhance immune cell activity, inhibit pathogen growth, and speed up healing. The body deliberately raises its temperature as a defense mechanism."},
{q:"What was trepanation?",o:["An ancient form of brain surgery involving drilling into the skull","An early type of vaccination","A medieval breathing treatment"],a:0,e:"Trepanation, drilling holes in the skull, is one of the oldest known surgical procedures, dating back 7,000+ years. Skulls show evidence of healing, meaning patients survived."},
{q:"How many base pairs are in the human genome?",o:["About 3 million","About 3 billion","About 3 trillion"],a:1,e:"The human genome contains approximately 3.2 billion base pairs of DNA. If printed in standard font, it would fill about 175 large phone books."},
{q:"What does 'epigenetics' study?",o:["Gene mutations","Heritable changes in gene expression without altering DNA sequence","The origin of genes"],a:1,e:"Epigenetic modifications like DNA methylation can turn genes on or off without changing the DNA code. Diet, stress, and environment can cause epigenetic changes that may pass to offspring."},
{q:"What is a plasmid?",o:["A type of virus","A small circular DNA molecule in bacteria","A human chromosome"],a:1,e:"Plasmids are small DNA rings separate from the main bacterial chromosome. Scientists use them as vectors to insert foreign genes into organisms for genetic engineering."},
{q:"What is PCR (polymerase chain reaction)?",o:["A method to sequence proteins","A technique to amplify specific DNA segments","A way to edit genes"],a:1,e:"PCR can make billions of copies of a specific DNA segment in hours. Invented by Kary Mullis in 1983, it revolutionized forensics, diagnostics, and research."},
{q:"What is gene therapy?",o:["Taking vitamins to improve genes","Introducing genetic material into cells to treat disease","Removing all mutations from DNA"],a:1,e:"Gene therapy delivers functional copies of genes to replace defective ones. It has successfully treated inherited blindness, spinal muscular atrophy, and some blood disorders."},
{q:"What are telomeres?",o:["Enzymes that repair DNA","Protective caps at the ends of chromosomes","Proteins that fold DNA"],a:1,e:"Telomeres are repetitive DNA sequences that protect chromosome ends, like aglets on shoelaces. They shorten with each cell division and are linked to aging."},
{q:"What is Dolly the sheep famous for?",o:["Being the first transgenic animal","Being the first cloned mammal from an adult cell","Being the first animal in space"],a:1,e:"Dolly was born in 1996 at the Roslin Institute in Scotland, cloned from a mammary cell of a six-year-old sheep using somatic cell nuclear transfer."},
{q:"What percentage of human DNA is shared between any two people?",o:["About 85%","About 99.9%","About 75%"],a:1,e:"All humans share 99.9% of their DNA. The 0.1% difference accounts for all the variation in appearance, disease susceptibility, and other traits between individuals."},
{q:"What is a genetically modified organism (GMO)?",o:["An organism born with a natural mutation","An organism whose DNA has been altered using genetic engineering","Any organism produced by selective breeding"],a:1,e:"GMOs have had specific genes added, removed, or modified using biotechnology. Examples include insect-resistant crops, golden rice with added vitamin A, and insulin-producing bacteria."},
{q:"What is RNA interference (RNAi)?",o:["RNA making copies of itself","A process where small RNA molecules silence gene expression","RNA editing DNA directly"],a:1,e:"RNAi uses small interfering RNA molecules to block specific messenger RNAs, preventing them from being translated into proteins. It won the Nobel Prize in 2006."},
{q:"What is a knockout mouse?",o:["A mouse used in boxing research","A mouse with a specific gene deliberately inactivated","A mouse bred for its appearance"],a:1,e:"Knockout mice have specific genes disabled to study what those genes do. They are crucial tools for understanding human diseases and testing potential treatments."},
{q:"What is mitochondrial DNA inherited from?",o:["Both parents equally","Mother only","Father only"],a:1,e:"Mitochondrial DNA is inherited exclusively from the mother because sperm mitochondria are destroyed after fertilization. This makes mtDNA useful for tracing maternal lineage."},
{q:"What is the Human Genome Project?",o:["A project to clone humans","An effort to map all human genes","A study of human behavior"],a:1,e:"The Human Genome Project (1990-2003) was a 13-year international effort that identified all ~20,000 human genes and sequenced 3 billion DNA base pairs. It cost about 2.7 billion dollars."},
{q:"What is CRISPR-Cas9 guided by?",o:["A protein signal","A short guide RNA sequence","An electrical current"],a:1,e:"A custom-designed guide RNA directs the Cas9 enzyme to the exact DNA location to be cut. Scientists can design guide RNAs to target virtually any gene."},
{q:"What is horizontal gene transfer?",o:["Parents passing genes to offspring","Organisms transferring genes between species outside of reproduction","Genes moving within a chromosome"],a:1,e:"Bacteria commonly swap genes through horizontal transfer, which is a major driver of antibiotic resistance. It also occurs between completely different species, even between kingdoms."},
{q:"What are SNPs (single nucleotide polymorphisms)?",o:["Large chromosomal rearrangements","Single-letter variations in DNA between individuals","Protein folding errors"],a:1,e:"SNPs are the most common type of genetic variation, occurring roughly every 300 nucleotides. They are used in ancestry testing, disease risk assessment, and pharmacogenomics."},
{q:"What organism was first to have its genome fully sequenced?",o:["A bacterium (Haemophilus influenzae)","A fruit fly","A mouse"],a:0,e:"Haemophilus influenzae was the first free-living organism to have its complete genome sequenced in 1995 by Craig Venter's team. It has about 1.8 million base pairs."},
{q:"What causes tides on Earth?",o:["Wind patterns","Gravitational pull of the Moon and Sun","Earth's rotation alone"],a:1,e:"The Moon's gravity creates a tidal bulge on the near side of Earth and a centrifugal bulge on the far side. The Sun contributes about 46% as much tidal force as the Moon."},
{q:"What are tectonic plates?",o:["Layers of the atmosphere","Large slabs of Earth's lithosphere that move slowly","Underground water channels"],a:1,e:"Earth's outer shell is divided into about 15 major tectonic plates that float on the semi-fluid asthenosphere, moving 1-10 cm per year and causing earthquakes and volcanism."},
{q:"What is the Mohorovicic discontinuity?",o:["A fault line in the ocean","The boundary between Earth's crust and mantle","A type of earthquake wave"],a:1,e:"The Moho, discovered in 1909, is the boundary where seismic waves suddenly accelerate, marking the transition from the crust to the denser mantle rock below."},
{q:"How old is Earth?",o:["About 4.5 billion years","About 6,000 years","About 13.8 billion years"],a:0,e:"Radiometric dating of meteorites and the oldest Earth rocks indicates our planet formed approximately 4.54 billion years ago from the solar nebula."},
{q:"What is the Ring of Fire?",o:["A volcanic ridge in Africa","A horseshoe-shaped zone of earthquakes and volcanoes around the Pacific","A feature of the Sun"],a:1,e:"The Ring of Fire hosts about 75% of the world's active volcanoes and 90% of earthquakes. It runs 40,000 km around the Pacific Ocean's tectonic plate boundaries."},
{q:"What causes the Northern Lights (aurora borealis)?",o:["Sunlight reflecting off ice","Charged solar particles interacting with atmospheric gases","Chemical reactions in the upper atmosphere"],a:1,e:"Solar wind particles, guided by Earth's magnetic field to the poles, collide with atmospheric gases. Oxygen glows green or red, nitrogen glows blue or purple."},
{q:"What is the Richter scale measuring?",o:["Wind speed","Earthquake magnitude","Volcanic eruption intensity"],a:1,e:"The Richter scale measures earthquake magnitude logarithmically. Each whole number increase represents 10 times more ground motion and about 31.6 times more energy released."},
{q:"What layer of the atmosphere contains the ozone layer?",o:["Troposphere","Stratosphere","Mesosphere"],a:1,e:"The ozone layer in the stratosphere (15-35 km up) absorbs 97-99% of the Sun's harmful UV radiation. The 1987 Montreal Protocol helped stop its depletion."},
{q:"What is a supervolcano?",o:["Any volcano over 3,000 meters tall","A volcano capable of an eruption ejecting more than 1,000 cubic km of material","An extinct volcano"],a:1,e:"Yellowstone sits over a supervolcano that last erupted 640,000 years ago. A full eruption could blanket North America in ash, but monitoring shows no imminent threat."},
{q:"What percentage of Earth's water is freshwater?",o:["About 3%","About 25%","About 50%"],a:0,e:"Only about 3% of Earth's water is fresh, and most of that is locked in ice caps and glaciers. Less than 1% of all water is accessible freshwater for human use."},
{q:"What is a tsunami?",o:["A very large normal wave","A series of ocean waves caused by underwater disturbances","A type of hurricane"],a:1,e:"Tsunamis are generated by earthquakes, volcanic eruptions, or landslides displacing water. In deep ocean they travel at jet speed (800 km/h) but are barely noticeable until they reach shore."},
{q:"What causes Earth's magnetic field?",o:["Iron in the crust","Convection of liquid iron in the outer core","Rotation of the mantle"],a:1,e:"Earth's magnetic field is generated by convection currents in the liquid iron outer core, creating a geodynamo. It shields us from solar wind and cosmic radiation."},
{q:"What type of rock is formed from cooled lava?",o:["Sedimentary","Metamorphic","Igneous"],a:2,e:"Igneous rocks form when molten rock (magma or lava) cools and solidifies. Basalt (fine-grained, from fast cooling) and granite (coarse-grained, from slow cooling) are common examples."},
{q:"What is the Coriolis effect?",o:["Ocean currents caused by temperature differences","The apparent deflection of moving objects due to Earth's rotation","Gravitational pull from the Moon"],a:1,e:"Earth's rotation causes moving air and water to curve right in the Northern Hemisphere and left in the Southern. This drives cyclone rotation and major ocean current patterns."},
{q:"What is the deepest point in the ocean?",o:["Mariana Trench","Puerto Rico Trench","Tonga Trench"],a:0,e:"The Challenger Deep in the Mariana Trench reaches about 10,935 meters (nearly 11 km) deep. The pressure there is over 1,000 times atmospheric pressure at sea level."},
{q:"What is a geode?",o:["A type of fossil","A hollow rock lined with crystals inside","A volcanic glass"],a:1,e:"Geodes form when mineral-rich water seeps into gas bubbles in volcanic rock. Over millions of years, crystals like quartz or amethyst grow inward from the walls."},
{q:"What drives the water cycle?",o:["Gravity alone","Solar energy and gravity","Wind and tides"],a:1,e:"Solar energy evaporates water from oceans and surfaces, gravity pulls precipitation back to Earth, and the cycle continuously redistributes water across the planet."},
{q:"What does CPU stand for?",o:["Central Processing Unit","Computer Power Utility","Central Program Updater"],a:0,e:"The CPU executes instructions from programs by performing arithmetic, logic, and input/output operations. Modern CPUs contain billions of transistors on a chip the size of a fingernail."},
{q:"What is Moore's Law?",o:["Internet speed doubles every year","Transistor count on chips doubles roughly every two years","Computer prices halve every five years"],a:1,e:"Gordon Moore observed in 1965 that transistor density doubles approximately every two years. This exponential growth drove the digital revolution for decades."},
{q:"What year was the World Wide Web invented?",o:["1983","1989","1995"],a:1,e:"Tim Berners-Lee invented the World Wide Web in 1989 at CERN, creating HTML, URLs, and HTTP. The first website went live in 1991 and described the project itself."},
{q:"What is machine learning?",o:["Robots learning to walk","Algorithms that improve through experience and data","Computers memorizing databases"],a:1,e:"Machine learning algorithms identify patterns in data and improve their predictions without being explicitly programmed for each task. It powers recommendation systems, image recognition, and more."},
{q:"What is a quantum computer?",o:["A very fast classical computer","A computer using quantum bits that can be 0 and 1 simultaneously","A computer that uses light instead of electricity"],a:1,e:"Quantum computers use qubits that exploit superposition and entanglement to process many possibilities simultaneously, potentially solving certain problems exponentially faster."},
{q:"What does GPS stand for?",o:["Global Positioning System","Geographic Path Satellite","Ground Position Scanner"],a:0,e:"GPS uses a constellation of at least 24 satellites orbiting at 20,200 km. Your device calculates its position by measuring signal travel time from at least 4 satellites."},
{q:"What is blockchain technology?",o:["A type of computer virus","A decentralized, tamper-resistant digital ledger","An advanced encryption algorithm"],a:1,e:"Blockchain records transactions across many computers so no single entity controls the record. Each block is cryptographically linked to the previous one, making tampering evident."},
{q:"What was the first programmable electronic computer?",o:["ENIAC","Colossus","Apple I"],a:1,e:"Colossus, built in 1943 at Bletchley Park to break German codes during WWII, was the first programmable electronic computer. It remained classified until the 1970s."},
{q:"What is the Turing Test?",o:["A test of computer processing speed","A test of whether a machine can exhibit intelligent behavior indistinguishable from a human","A test of network security"],a:1,e:"Proposed by Alan Turing in 1950, it evaluates whether a machine's responses are indistinguishable from a human's. It remains a benchmark for artificial intelligence."},
{q:"What does HTTPS stand for?",o:["HyperText Transfer Protocol Secure","High Technology Transfer Protocol System","Hyper Transmission Text Protocol Safe"],a:0,e:"HTTPS encrypts communication between your browser and a website using TLS/SSL, preventing eavesdropping and tampering. The padlock icon in your browser indicates HTTPS."},
{q:"How many bits are in a byte?",o:["4","8","16"],a:1,e:"One byte equals 8 bits and can represent 256 different values (2^8). A kilobyte is 1,024 bytes, and a modern hard drive holds terabytes (trillions of bytes)."},
{q:"What is fiber optic cable made of?",o:["Copper wire","Thin strands of glass or plastic","Aluminum tubes"],a:1,e:"Fiber optics transmit data as pulses of light through hair-thin glass strands. They carry data at near light speed with far less signal loss than copper cables."},
{q:"What is the Internet of Things (IoT)?",o:["A new version of the internet","Everyday physical objects connected to the internet","A virtual reality network"],a:1,e:"IoT connects devices like thermostats, fridges, and sensors to the internet, allowing them to collect and share data. There are estimated to be over 15 billion IoT devices worldwide."},
{q:"What programming language was created by Guido van Rossum?",o:["Java","Python","Ruby"],a:1,e:"Guido van Rossum created Python in 1991, named after Monty Python. Its emphasis on readability and simplicity has made it one of the most popular languages in the world."},
{q:"What is 3D printing also known as?",o:["Subtractive manufacturing","Additive manufacturing","Injection molding"],a:1,e:"3D printing builds objects layer by layer from digital designs. It is used to create everything from prosthetic limbs to rocket engine parts and even human tissue scaffolds."},
{q:"What was the first message sent over the internet?",o:["Hello World","LO (the system crashed before completing LOGIN)","Testing 123"],a:1,e:"On October 29, 1969, the first ARPANET message was 'LOGIN' but the system crashed after 'LO.' The researchers joked it was a fitting message: 'Lo and behold.'"},
{q:"What is CMOS technology used for in computers?",o:["Storing permanent data","Building low-power integrated circuits and processors","Connecting to the internet"],a:1,e:"Complementary Metal-Oxide-Semiconductor technology is the basis for most modern processors and memory chips, valued for its low power consumption and high density."},
{q:"Who discovered radioactivity?",o:["Marie Curie","Henri Becquerel","Ernest Rutherford"],a:1,e:"Henri Becquerel accidentally discovered radioactivity in 1896 when uranium salts fogged photographic plates. Marie Curie later coined the term 'radioactivity' and expanded the research."},
{q:"What did Rosalind Franklin contribute to science?",o:["Discovered penicillin","Produced the X-ray image crucial to discovering DNA's structure","Invented the telescope"],a:1,e:"Franklin's Photo 51 (1952) was a key X-ray diffraction image revealing DNA's helical structure. Watson and Crick used her data, often without proper credit, to build their famous model."},
{q:"Who proposed the heliocentric model of the solar system?",o:["Galileo Galilei","Nicolaus Copernicus","Johannes Kepler"],a:1,e:"Copernicus published his heliocentric theory in 1543, placing the Sun at the center. It was revolutionary because the Earth-centered model had dominated for 1,400 years."},
{q:"What did Marie Curie win two Nobel Prizes for?",o:["Physics and Chemistry","Physics and Medicine","Chemistry and Peace"],a:0,e:"Marie Curie won the 1903 Nobel in Physics (for radioactivity research) and the 1911 Nobel in Chemistry (for discovering radium and polonium). She remains the only person to win in two different sciences."},
{q:"Who is known as the father of modern genetics?",o:["Charles Darwin","Gregor Mendel","James Watson"],a:1,e:"Gregor Mendel, an Augustinian monk, discovered the laws of inheritance by studying pea plants in the 1860s. His work was largely ignored until rediscovered around 1900."},
{q:"What did Nikola Tesla pioneer?",o:["The telephone","Alternating current (AC) electrical systems","The steam engine"],a:1,e:"Tesla developed AC power systems, the Tesla coil, and contributed to radio technology. His AC system won the 'War of Currents' against Edison's DC and powers the modern world."},
{q:"Who developed the theory of continental drift?",o:["Charles Lyell","Alfred Wegener","James Hutton"],a:1,e:"Alfred Wegener proposed in 1912 that continents were once joined in a supercontinent called Pangaea. Ridiculed in his lifetime, his theory was confirmed by plate tectonics in the 1960s."},
{q:"What did Watson and Crick discover in 1953?",o:["The gene","The double helix structure of DNA","RNA"],a:1,e:"Watson and Crick, building on work by Franklin and Wilkins, proposed the double helix model of DNA in 1953. They shared the 1962 Nobel Prize in Physiology or Medicine."},
{q:"Who invented the first practical microscope for scientific use?",o:["Antonie van Leeuwenhoek","Robert Hooke","Galileo Galilei"],a:0,e:"Antonie van Leeuwenhoek crafted single-lens microscopes with up to 270x magnification in the 1670s, becoming the first to observe bacteria, sperm cells, and blood flow in capillaries."},
{q:"What is Hawking radiation?",o:["Radiation from the Sun","Theoretical radiation emitted by black holes","Cosmic background radiation"],a:1,e:"Stephen Hawking predicted in 1974 that black holes emit thermal radiation due to quantum effects near the event horizon, meaning they slowly evaporate over immense timescales."},
{q:"Who developed the first successful polio vaccine?",o:["Jonas Salk","Albert Sabin","Louis Pasteur"],a:0,e:"Jonas Salk developed the inactivated polio vaccine in 1955 and famously refused to patent it, saying 'Could you patent the sun?' It saved millions from paralysis."},
{q:"What did Dmitri Mendeleev predict using his periodic table?",o:["The existence of electrons","Properties of undiscovered elements","Nuclear fission"],a:1,e:"Mendeleev left gaps in his 1869 periodic table and predicted the properties of missing elements like gallium and germanium. Their later discovery validated his system brilliantly."},
{q:"Who proved that germs cause disease?",o:["Louis Pasteur and Robert Koch","Hippocrates","Florence Nightingale"],a:0,e:"Pasteur demonstrated germ theory through experiments disproving spontaneous generation, while Koch developed postulates to prove specific microbes cause specific diseases in the 1870s-1880s."},
{q:"What did Niels Bohr contribute to physics?",o:["The law of gravity","A model of the atom with quantized electron orbits","The theory of relativity"],a:1,e:"Bohr's 1913 atomic model proposed that electrons orbit the nucleus at fixed energy levels and emit light when jumping between them, helping found quantum mechanics."},
{q:"Who was the first woman to win a Nobel Prize in science?",o:["Marie Curie","Dorothy Hodgkin","Barbara McClintock"],a:0,e:"Marie Curie won the 1903 Nobel Prize in Physics, shared with her husband Pierre and Henri Becquerel, for their research on radioactivity. She remains the most celebrated female scientist."},
{q:"What did Ada Lovelace contribute to computing?",o:["Built the first computer","Wrote the first computer algorithm","Invented the transistor"],a:1,e:"In 1843, Ada Lovelace wrote detailed notes on Charles Babbage's Analytical Engine, including what is recognized as the first published computer algorithm, a century before modern computers."},
{q:"Who discovered the structure of the benzene molecule?",o:["Friedrich August Kekule","Linus Pauling","Dmitri Mendeleev"],a:0,e:"Kekule proposed the ring structure of benzene in 1865, reportedly inspired by a dream of a snake biting its own tail. The hexagonal ring became foundational to organic chemistry."},
];

const FACTS = [
  {i:"🧬",t:"Your DNA could stretch to Pluto and back — twice",d:"Uncoiled DNA from all 37 trillion cells stretches ~34 billion miles. That's a round trip to Pluto with DNA to spare.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"National Human Genome Research Institute",url:"https://en.wikipedia.org/wiki/DNA"},
  {i:"🧠",t:"Your brain uses 20% of body energy but is only 2% of weight",d:"86 billion neurons firing up to 200 times per second are incredibly energy-hungry, consuming ~20% of your oxygen and calories.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"Nature Neuroscience",url:"https://en.wikipedia.org/wiki/Human_brain"},
  {i:"🦑",t:"Octopuses have 3 hearts, blue blood, and 9 brains",d:"Two hearts for gills, one for the body. Copper-based hemocyanin makes blood blue. Each arm has its own mini-brain (ganglion).",img:"https://images.unsplash.com/photo-1545671913-b89ac1b4ac10?w=600&h=350&fit=crop",s:"Marine Biological Laboratory",url:"https://en.wikipedia.org/wiki/Octopus"},
  {i:"🦴",t:"Babies have 270 bones — adults only 206",d:"Bones fuse during childhood. Your femur is stronger than concrete, and your skeleton replaces itself every ~10 years.",img:"https://images.unsplash.com/photo-1530497610245-94d3c16cda28?w=600&h=350&fit=crop",s:"American Academy of Orthopaedic Surgeons",url:"https://en.wikipedia.org/wiki/Human_skeleton"},
  {i:"🫀",t:"Your heart will beat 2.5 billion times in your lifetime",d:"Pumping ~2,000 gallons/day through 60,000 miles of blood vessels — enough to circle Earth 2.5 times.",img:"https://images.unsplash.com/photo-1628348068343-c6a848d2b6dd?w=600&h=350&fit=crop",s:"American Heart Association",url:"https://en.wikipedia.org/wiki/Heart"},
  {i:"🦠",t:"You have more bacteria than human cells",d:"~38 trillion bacteria vs ~37 trillion human cells. Most live in your gut and are essential for digestion, immunity, and mood.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Cell Journal",url:"https://en.wikipedia.org/wiki/Human_microbiome"},
  {i:"👁️",t:"Your eyes distinguish ~10 million colors",d:"6 million cones for color, 120 million rods for low light. The eye processes information faster than any camera ever built.",img:"https://images.unsplash.com/photo-1508963493744-76fce69379c0?w=600&h=350&fit=crop",s:"Journal of Vision Research",url:"https://en.wikipedia.org/wiki/Color_vision"},
  {i:"🕸️",t:"Spider silk is 5x stronger than steel by weight",d:"Some orb-weavers produce 7 types of silk, each optimized for catching prey, wrapping eggs, or structural support.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"Nature Materials",url:"https://en.wikipedia.org/wiki/Spider_silk"},
  {i:"🫁",t:"Your lungs unfold to a tennis court",d:"~300 million alveoli create ~70 sq meters of gas-exchange surface. You breathe ~22,000 times daily without thinking.",img:"https://images.unsplash.com/photo-1516549655169-df83a0774514?w=600&h=350&fit=crop",s:"American Lung Association",url:"https://en.wikipedia.org/wiki/Lung"},
  {i:"🐋",t:"A blue whale's heart is the size of a small car",d:"The largest animal ever — bigger than any dinosaur. Its aorta is large enough for a human to crawl through.",img:"https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=600&h=350&fit=crop",s:"National Geographic",url:"https://en.wikipedia.org/wiki/Blue_whale"},
  {i:"🧫",t:"One bacterium becomes 8 million in 24 hours",d:"E. coli divides every 20 minutes. Exponential binary fission: 1 → 8,000,000+ in a single day.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Microbiology & Molecular Biology Reviews",url:"https://en.wikipedia.org/wiki/Binary_fission"},
  {i:"🌿",t:"Trees talk through underground fungal networks",d:"The 'Wood Wide Web' lets trees share nutrients, warn neighbors of pests, and nurture seedlings via mycorrhizal fungi.",img:"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=600&h=350&fit=crop",s:"Nature Ecology & Evolution",url:"https://en.wikipedia.org/wiki/Mycorrhizal_network"},
  {i:"🦎",t:"Axolotls regrow limbs, organs, and brain parts",d:"Scientists study their regeneration hoping to unlock similar abilities in humans someday.",img:"https://images.unsplash.com/photo-1615497001839-b0a0eac3274c?w=600&h=350&fit=crop",s:"Developmental Biology Journal",url:"https://en.wikipedia.org/wiki/Axolotl"},
  {i:"💉",t:"Horseshoe crab blood is worth $60,000/gallon",d:"Their blue blood (LAL) instantly detects bacterial toxins. Every FDA-approved injection is tested with it.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Atlantic States Marine Fisheries Commission",url:"https://en.wikipedia.org/wiki/Horseshoe_crab"},
  {i:"🍄",t:"The largest organism is a 2,385-acre fungus",d:"A honey mushroom in Oregon is estimated 2,400–8,650 years old. Most is hidden underground as mycelium.",img:"https://images.unsplash.com/photo-1504198322253-cfa87a0ff25f?w=600&h=350&fit=crop",s:"USDA Forest Service",url:"https://en.wikipedia.org/wiki/Armillaria_ostoyae"},
  {i:"⚡",t:"Electric eels generate 860 volts",d:"Electrocytes stacked in series act as biological batteries for hunting, defense, and navigation.",img:"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&h=350&fit=crop",s:"Science Magazine",url:"https://en.wikipedia.org/wiki/Electric_eel"},
  {i:"🐙",t:"Cuttlefish change color, pattern, AND texture in milliseconds",d:"Chromatophores, iridophores, and papillae give them the most sophisticated camouflage in nature.",img:"https://images.unsplash.com/photo-1551244072-5d12893278ab?w=600&h=350&fit=crop",s:"Journal of Experimental Biology",url:"https://en.wikipedia.org/wiki/Cuttlefish"},
  {i:"🐜",t:"All ants weigh roughly as much as all humans",d:"~20 quadrillion ants on Earth, collectively ~80 million tons — comparable to total human biomass.",img:"https://images.unsplash.com/photo-1556983852-43bf21186b2a?w=600&h=350&fit=crop",s:"Proceedings of the National Academy of Sciences",url:"https://en.wikipedia.org/wiki/Ant"},
  {i:"🌺",t:"The corpse flower smells like rotting flesh — on purpose",d:"It produces chemicals mimicking decaying meat to attract carrion beetles and flesh flies for pollination.",img:"https://images.unsplash.com/photo-1490750967868-88aa4f44baee?w=600&h=350&fit=crop",s:"Chicago Botanic Garden",url:"https://en.wikipedia.org/wiki/Amorphophallus_titanum"},
  {i:"🩸",t:"Your blood vessels could wrap around Earth 2.5 times",d:"~60,000 miles of arteries, veins, and capillaries. Capillaries are so narrow that RBCs squeeze through single-file.",img:"https://images.unsplash.com/photo-1615631648086-325025c9e51e?w=600&h=350&fit=crop",s:"American Heart Association",url:"https://en.wikipedia.org/wiki/Blood_vessel"},
  {i:"🐢",t:"Greenland sharks live over 400 years",d:"The longest-lived vertebrates known. They don't reach sexual maturity until ~150 years old.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"Science Magazine",url:"https://en.wikipedia.org/wiki/Greenland_shark"},
  {i:"🦈",t:"Sharks are older than trees",d:"Sharks: ~450 million years. Trees: ~360 million years. Sharks survived all 5 mass extinctions.",img:"https://images.unsplash.com/photo-1560275619-4662e36fa65c?w=600&h=350&fit=crop",s:"Nature Ecology & Evolution",url:"https://en.wikipedia.org/wiki/Shark"},
  {i:"🧬",t:"Only 1.5% of DNA codes for proteins",d:"The rest plays critical roles in gene regulation and chromosome structure — far from 'junk.'",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"ENCODE Project, Nature",url:"https://en.wikipedia.org/wiki/Non-coding_DNA"},
  {i:"🦩",t:"Flamingos turn pink from their food",d:"Carotenoid pigments in shrimp and algae are deposited in feathers. Without this diet, they stay white.",img:"https://images.unsplash.com/photo-1497206365907-f5e630693df0?w=600&h=350&fit=crop",s:"Ornithological Applications",url:"https://en.wikipedia.org/wiki/Flamingo"},
  {i:"🔬",t:"Your body makes 3.8 million cells per second",d:"~330 billion cells replaced daily — about 1% of all your cells swapped out every single day.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Cell Stem Cell Journal",url:"https://en.wikipedia.org/wiki/Cell_division"},
  {i:"🐬",t:"Dolphins sleep with one eye open",d:"Unihemispheric sleep: half the brain rests while the other watches for predators and remembers to breathe.",img:"https://images.unsplash.com/photo-1564438091-2a6c464c0cd2?w=600&h=350&fit=crop",s:"Neuroscience & Biobehavioral Reviews",url:"https://en.wikipedia.org/wiki/Unihemispheric_slow-wave_sleep"},
  {i:"🦠",t:"Viruses outnumber all life combined",d:"~10³¹ viruses on Earth. Stacked end to end, they'd stretch 100 million light-years beyond the Milky Way.",img:"https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=600&h=350&fit=crop",s:"Nature Reviews Microbiology",url:"https://en.wikipedia.org/wiki/Virus"},
  {i:"🌲",t:"The oldest living organism is 5,000+ years old",d:"A bristlecone pine named Methuselah was already ancient when the pyramids were built.",img:"https://images.unsplash.com/photo-1473448912268-2022ce9509d8?w=600&h=350&fit=crop",s:"USDA Forest Service",url:"https://en.wikipedia.org/wiki/Methuselah_(tree)"},
  {i:"🐝",t:"A bee visits 5,000 flowers per day",d:"To make 1 lb of honey, bees collectively fly ~55,000 miles and visit 2 million flowers.",img:"https://images.unsplash.com/photo-1558642452-9d2a7deb7f62?w=600&h=350&fit=crop",s:"American Beekeeping Federation",url:"https://en.wikipedia.org/wiki/Honey_bee"},
  {i:"🧬",t:"Identical twins diverge via epigenetics",d:"Same DNA sequence, but different environments cause different genes to activate over time.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Nature Genetics",url:"https://en.wikipedia.org/wiki/Epigenetics"},
  {i:"🐛",t:"Caterpillars liquefy inside their cocoon",d:"They dissolve into soup, then imaginal discs reorganize everything into wings, legs, and antennae.",img:"https://images.unsplash.com/photo-1470058869958-2a77beeae652?w=600&h=350&fit=crop",s:"Scientific American",url:"https://en.wikipedia.org/wiki/Pupa"},
  {i:"🦈",t:"Sharks detect blood from a quarter mile away",d:"Incredibly sensitive olfactory receptors detect 1 part per million. Some also sense bioelectrical fields.",img:"https://images.unsplash.com/photo-1560275619-4662e36fa65c?w=600&h=350&fit=crop",s:"Journal of Experimental Biology",url:"https://en.wikipedia.org/wiki/Shark_senses"},
  {i:"🌍",t:"99.9% of all species that ever lived are extinct",d:"~5 billion species have existed; only ~8.7 million remain. Mass extinctions shaped the tree of life for 3.8 billion years.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"PNAS",url:"https://en.wikipedia.org/wiki/Extinction"},
  {i:"🐙",t:"Octopuses taste with their arms",d:"Each arm has ~240 suckers with thousands of chemoreceptors. They identify prey by chemistry alone.",img:"https://images.unsplash.com/photo-1545671913-b89ac1b4ac10?w=600&h=350&fit=crop",s:"Cell Journal",url:"https://en.wikipedia.org/wiki/Octopus"},
  {i:"🧫",t:"Tardigrades survive outer space",d:"Withstanding radiation, -272°C to 150°C, 6x deepest ocean pressure, and the vacuum of space.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Current Biology",url:"https://en.wikipedia.org/wiki/Tardigrade"},
  {i:"🐌",t:"A snail can sleep for 3 years",d:"During unfavorable conditions, snails enter dormancy, sealing their shell with a mucus plug.",img:"https://images.unsplash.com/photo-1498462440456-0dba182e775b?w=600&h=350&fit=crop",s:"Journal of Molluscan Studies",url:"https://en.wikipedia.org/wiki/Snail"},
  {i:"🦋",t:"Monarchs navigate 3,000 miles with a sun compass in their antennae",d:"They migrate Canada to Mexico — a place they've never been — using circadian clocks compensating for the sun.",img:"https://images.unsplash.com/photo-1558104631-0fa41a8a3cb1?w=600&h=350&fit=crop",s:"Cell Reports",url:"https://en.wikipedia.org/wiki/Monarch_butterfly_migration"},
  {i:"🐘",t:"Elephants can't jump — but their trunks have 40,000 muscles",d:"Your entire body has ~600 muscles. An elephant trunk lifts 700 lbs yet picks up a single blade of grass.",img:"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=600&h=350&fit=crop",s:"Royal Society Open Science",url:"https://en.wikipedia.org/wiki/Elephant"},
  {i:"🐠",t:"Clownfish change sex when the dominant female dies",d:"Sequential hermaphroditism: the top male becomes female, next male moves up. Finding Nemo got complicated.",img:"https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=600&h=350&fit=crop",s:"Nature",url:"https://en.wikipedia.org/wiki/Clownfish"},
  {i:"🐺",t:"Dogs can smell your emotions",d:"They detect cortisol and adrenaline in your sweat, distinguishing happy, fearful, and angry scent profiles.",img:"https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=600&h=350&fit=crop",s:"Animal Cognition",url:"https://en.wikipedia.org/wiki/Dog_cognition"},
  {i:"🦎",t:"Geckos walk on ceilings via molecular forces",d:"Millions of nano-hairs (setae) per toe create van der Waals attraction. One toe supports their entire weight.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"PNAS",url:"https://en.wikipedia.org/wiki/Gecko"},
  {i:"🌿",t:"Plants 'hear' themselves being eaten",d:"Arabidopsis increases chemical defenses when detecting caterpillar chewing vibrations — even without physical damage.",img:"https://images.unsplash.com/photo-1416879595882-3373a0480b5b?w=600&h=350&fit=crop",s:"Oecologia",url:"https://en.wikipedia.org/wiki/Plant_perception_(physiology)"},
  {i:"💡",t:"Bioluminescence evolved independently 50+ times",d:"From anglerfish to fireflies to dinoflagellates. ~76% of deep-sea creatures produce their own light.",img:"https://images.unsplash.com/photo-1551244072-5d12893278ab?w=600&h=350&fit=crop",s:"Annual Review of Marine Science",url:"https://en.wikipedia.org/wiki/Bioluminescence"},
  {i:"🐝",t:"Bees can recognize human faces",d:"Honeybees learn and remember individual faces using holistic processing — the same technique humans use.",img:"https://images.unsplash.com/photo-1558642452-9d2a7deb7f62?w=600&h=350&fit=crop",s:"Journal of Experimental Biology",url:"https://en.wikipedia.org/wiki/Bee_learning_and_communication"},
  {i:"🧠",t:"Reading this fact just rewired your brain",d:"Every experience physically changes brain structure through neuroplasticity, strengthening synaptic connections.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"Nature Neuroscience",url:"https://en.wikipedia.org/wiki/Neuroplasticity"},
  {i:"🐄",t:"Cows have best friends and get stressed apart",d:"They produce less cortisol when housed with preferred companions and show excitement solving problems.",img:"https://images.unsplash.com/photo-1570042225831-d98fa7577f1e?w=600&h=350&fit=crop",s:"Applied Animal Behaviour Science",url:"https://en.wikipedia.org/wiki/Cattle"},
  {i:"🦀",t:"Mantis shrimp have 16 color receptors (humans have 3)",d:"They see UV and polarized light. Their punch accelerates faster than a .22 bullet, creating cavitation bubbles.",img:"https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=600&h=350&fit=crop",s:"Journal of Experimental Biology",url:"https://en.wikipedia.org/wiki/Mantis_shrimp"},
  {i:"🦥",t:"Sloths are so slow that algae grows on their fur",d:"The algae provides camouflage; the fur provides habitat. Some sloths also host entire moth colonies in their fur.",img:"https://images.unsplash.com/photo-1577936168622-a7ba1edcaee2?w=600&h=350&fit=crop",s:"Proceedings of the Royal Society B",url:"https://en.wikipedia.org/wiki/Sloth"},
  {i:"🧪",t:"Your tears have different chemistry based on why you're crying",d:"Basal, reflex, and emotional tears each have distinct profiles. Emotional tears contain stress hormones and painkillers.",img:"https://images.unsplash.com/photo-1508963493744-76fce69379c0?w=600&h=350&fit=crop",s:"Psychoneuroendocrinology",url:"https://en.wikipedia.org/wiki/Tears"},
  {i:"🐍",t:"Some snakes fly — gliding 30+ feet through the air",d:"Paradise tree snakes flatten their body into a concave wing shape and undulate to control their glide path.",img:"https://images.unsplash.com/photo-1531386151447-fd76ad50012f?w=600&h=350&fit=crop",s:"Journal of Experimental Biology",url:"https://en.wikipedia.org/wiki/Chrysopelea"},
  // === VACCINES & PUBLIC HEALTH ===
  {i:"💉",t:"Vaccines save 4+ million lives every single year",d:"Since 1974, immunization programs have saved an estimated 154 million lives — that's 6 lives every minute for 50 years.",img:"https://images.unsplash.com/photo-1615631648086-325025c9e51e?w=600&h=350&fit=crop",s:"World Health Organization",url:"https://en.wikipedia.org/wiki/Vaccine"},
  {i:"🦠",t:"Smallpox killed 300 million people — then vaccines erased it",d:"The deadliest disease in history was declared eradicated in 1980 thanks to a global vaccination campaign. The last natural case was in 1977.",img:"https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=600&h=350&fit=crop",s:"WHO Global Smallpox Eradication Programme",url:"https://en.wikipedia.org/wiki/Smallpox_eradication"},
  {i:"🧬",t:"mRNA vaccine technology was 30 years in the making",d:"Katalin Karikó spent decades developing mRNA tech despite funding rejections. Her persistence led to COVID vaccines and won the 2023 Nobel Prize.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nobel Prize Committee, 2023",url:"https://en.wikipedia.org/wiki/MRNA_vaccine"},
  {i:"💉",t:"Your immune system remembers vaccines for decades",d:"Memory B and T cells created by vaccination can persist for 10–75+ years. Smallpox vaccine recipients still showed immunity 75 years later.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Nature Immunology",url:"https://en.wikipedia.org/wiki/Immunological_memory"},
  {i:"🌍",t:"Polio is 99.9% eradicated thanks to vaccines",d:"From 350,000 cases in 125 countries (1988) to just a handful of cases in 2 countries today. We're on the verge of eradicating polio forever.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"Global Polio Eradication Initiative",url:"https://en.wikipedia.org/wiki/Polio_eradication"},
  {i:"🧪",t:"The COVID vaccine was designed in just 2 days",d:"Once scientists had the SARS-CoV-2 genetic sequence, Moderna designed their mRNA vaccine in 48 hours. The rest of the time was testing and manufacturing.",img:"https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=600&h=350&fit=crop",s:"New England Journal of Medicine",url:"https://en.wikipedia.org/wiki/Moderna_COVID-19_vaccine"},
  {i:"🦠",t:"Antibiotic-resistant superbugs kill 1.27 million people/year",d:"Antimicrobial resistance is a growing crisis. Overuse of antibiotics accelerates bacterial evolution — new solutions are urgently needed.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"The Lancet, 2022",url:"https://en.wikipedia.org/wiki/Antimicrobial_resistance"},
  {i:"💉",t:"Measles vaccine has saved over 56 million lives since 2000",d:"Before vaccination, measles killed 2.6 million people/year. The vaccine is 97% effective with two doses and is one of the best investments in global health.",img:"https://images.unsplash.com/photo-1615631648086-325025c9e51e?w=600&h=350&fit=crop",s:"WHO & CDC",url:"https://en.wikipedia.org/wiki/Measles_vaccine"},
  // === GENE THERAPY FACTS ===
  {i:"🧬",t:"Gene therapy can now cure diseases with a single injection",d:"Zolgensma delivers a working copy of the SMN1 gene to treat spinal muscular atrophy. One dose replaces the missing gene — for life. It costs $2.1M per dose, the most expensive drug ever made.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"FDA / Novartis Gene Therapies",url:"https://en.wikipedia.org/wiki/Zolgensma"},
  {i:"🧬",t:"CAR-T cells are living drugs that hunt cancer",d:"Engineers extract your T cells, genetically add a cancer-targeting receptor, multiply them to billions, and reinfuse them. These living drugs seek and destroy tumors 24/7.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Nature Reviews Cancer",url:"https://en.wikipedia.org/wiki/CAR_T_cell"},
  {i:"🧬",t:"Base editing changes single DNA letters without cutting",d:"Unlike traditional CRISPR, base editors chemically convert one base to another — like a molecular pencil erasing and rewriting one letter. No double-strand breaks, far fewer errors.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nature, 2016 — David Liu Lab, Broad Institute",url:"https://en.wikipedia.org/wiki/Base_editing"},
  {i:"🧬",t:"Over 7,000 diseases are caused by a single gene mutation",d:"Sickle cell, cystic fibrosis, Huntington's, muscular dystrophy — each caused by a typo in one gene. Gene therapy aims to fix or replace each one.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"WHO / OMIM Database",url:"https://en.wikipedia.org/wiki/Genetic_disorder"},
  {i:"🧬",t:"CRISPR was discovered in bacteria's immune system",d:"Bacteria store snippets of viral DNA as a memory bank. When the virus returns, CRISPR-Cas cuts it up. Scientists repurposed this ancient defense into gene-editing scissors.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Science, 2012 — Doudna & Charpentier",url:"https://en.wikipedia.org/wiki/CRISPR"},
  {i:"🧬",t:"Prime editing can make any DNA change without double-strand breaks",d:"David Liu's prime editor is a molecular word processor: it searches for a specific DNA sequence, then writes in the correction. It can fix ~89% of known pathogenic mutations.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nature, 2019 — Broad Institute",url:"https://en.wikipedia.org/wiki/Prime_editing"},
  {i:"🧬",t:"mRNA therapies teach your cells to make their own medicine",d:"Instead of injecting a protein drug, mRNA tells your cells to produce it themselves. This approach works for vaccines, enzyme replacement, and now gene therapy — temporarily turning cells into drug factories.",img:"https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=600&h=350&fit=crop",s:"Nature Reviews Drug Discovery",url:"https://en.wikipedia.org/wiki/MRNA_therapeutics"},
  {i:"🧬",t:"Gene drives could eliminate malaria-carrying mosquitoes",d:"CRISPR gene drives spread a genetic change through an entire wild population. In lab tests, drives spreading female infertility collapsed mosquito populations within 8–12 generations.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Nature Biotechnology, 2024 — Target Malaria",url:"https://en.wikipedia.org/wiki/Gene_drive"},
{i:"🧠",t:"Your brain generates enough electricity to power a light bulb",d:"The 86 billion neurons in your brain collectively produce about 12-25 watts of electrical power. This constant electrical storm creates brainwaves detectable from outside your skull.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"MIT Neuroscience",url:"https://en.wikipedia.org/wiki/Neural_oscillation"},
{i:"🦷",t:"Tooth enamel is the hardest substance in your body",d:"Ranking 5 on the Mohs hardness scale, tooth enamel is harder than steel. Yet it cannot regenerate once damaged because the cells that create it die after the tooth erupts.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Journal of Dental Research",url:"https://en.wikipedia.org/wiki/Tooth_enamel"},
{i:"😴",t:"Your brain washes itself with fluid while you sleep",d:"The glymphatic system flushes cerebrospinal fluid through brain tissue during deep sleep, clearing toxic waste products like amyloid-beta linked to Alzheimer's disease.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"Science Magazine",url:"https://en.wikipedia.org/wiki/Glymphatic_system"},
{i:"👃",t:"Your nose can detect over 1 trillion different scents",d:"Scientists once thought humans could smell only 10,000 odors. A 2014 Rockefeller University study revealed our olfactory system distinguishes at least one trillion scent combinations.",img:"https://images.unsplash.com/photo-1508963493744-76fce69379c0?w=600&h=350&fit=crop",s:"Science, 2014",url:"https://en.wikipedia.org/wiki/Olfaction"},
{i:"💪",t:"Your strongest muscle is the masseter in your jaw",d:"The masseter can exert over 200 pounds of force on your molars. Pound for pound, it generates more force than any other muscle in the human body.",img:"https://images.unsplash.com/photo-1530497610245-94d3c16cda28?w=600&h=350&fit=crop",s:"Journal of Biomechanics",url:"https://en.wikipedia.org/wiki/Masseter_muscle"},
{i:"🔴",t:"Red blood cells travel your entire body in 20 seconds",d:"Each red blood cell completes a full circuit of your circulatory system in about 20 seconds. Over its 120-day lifespan, a single red blood cell makes roughly 500,000 trips.",img:"https://images.unsplash.com/photo-1615631648086-325025c9e51e?w=600&h=350&fit=crop",s:"American Society of Hematology",url:"https://en.wikipedia.org/wiki/Red_blood_cell"},
{i:"🤧",t:"A sneeze travels at over 100 miles per hour",d:"A single sneeze can launch 40,000 droplets at speeds exceeding 100 mph, projecting them up to 26 feet. That is faster than most animals on Earth can run.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Journal of Fluid Mechanics",url:"https://en.wikipedia.org/wiki/Sneeze"},
{i:"🧬",t:"Your DNA repair enzymes fix a million errors per cell per day",d:"Ultraviolet light, free radicals, and replication mistakes constantly damage your DNA. Specialized enzymes scan and repair roughly one million lesions in every cell every single day.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Nature Reviews Molecular Cell Biology",url:"https://en.wikipedia.org/wiki/DNA_repair"},
{i:"🦠",t:"Your gut bacteria produce most of your serotonin",d:"About 90% of the body's serotonin is manufactured in the gut by microbes and enterochromaffin cells. Your mood literally depends on the bacteria living in your intestines.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Cell, 2015",url:"https://en.wikipedia.org/wiki/Gut%E2%80%93brain_axis"},
{i:"👶",t:"Newborns have no kneecaps — just cartilage",d:"Babies are born with cartilage pads where kneecaps will form. The patella does not fully ossify into bone until children are 3-5 years old, which is why toddlers bounce so well.",img:"https://images.unsplash.com/photo-1530497610245-94d3c16cda28?w=600&h=350&fit=crop",s:"Pediatric Radiology",url:"https://en.wikipedia.org/wiki/Patella"},
{i:"🩻",t:"Your small intestine is about 20 feet long",d:"Despite being packed inside your abdomen, the small intestine stretches roughly 20 feet. Its inner surface has millions of villi, giving it the absorption area of a tennis court.",img:"https://images.unsplash.com/photo-1628348068343-c6a848d2b6dd?w=600&h=350&fit=crop",s:"Gray's Anatomy",url:"https://en.wikipedia.org/wiki/Small_intestine"},
{i:"🧓",t:"Humans are the only animals with chins",d:"No other primate or mammal has a protruding bony chin. Scientists still debate why we evolved this unique feature — theories range from speech mechanics to sexual selection.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"Evolutionary Anthropology",url:"https://en.wikipedia.org/wiki/Human_chin"},
{i:"💧",t:"You produce a bathtub of saliva every month",d:"Your salivary glands produce 1-2 liters of saliva daily, roughly 50 liters per month. Saliva contains enzymes, antibodies, and compounds that begin digestion before you even swallow.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Journal of Oral Biology",url:"https://en.wikipedia.org/wiki/Saliva"},
{i:"🌊",t:"The ocean's deepest point could swallow Mount Everest",d:"The Challenger Deep in the Mariana Trench reaches 36,070 feet below sea level. If you placed Everest at the bottom, its peak would still be over a mile underwater.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"NOAA",url:"https://en.wikipedia.org/wiki/Challenger_Deep"},
{i:"🦐",t:"Giant tube worms thrive without sunlight near volcanic vents",d:"These 6-foot worms live at hydrothermal vents where water reaches 750 degrees F. They have no mouth or gut — symbiotic bacteria inside them convert chemicals into food.",img:"https://images.unsplash.com/photo-1551244072-5d12893278ab?w=600&h=350&fit=crop",s:"Deep-Sea Research",url:"https://en.wikipedia.org/wiki/Giant_tube_worm"},
{i:"🐡",t:"The ocean produces over half the world's oxygen",d:"Phytoplankton, kelp, and algal organisms in the ocean generate 50-80% of Earth's oxygen through photosynthesis. Every other breath you take comes from the sea.",img:"https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=600&h=350&fit=crop",s:"National Geographic",url:"https://en.wikipedia.org/wiki/Phytoplankton"},
{i:"🐚",t:"Coral reefs support 25% of all marine species",d:"Though they cover less than 1% of the ocean floor, coral reefs are home to roughly a quarter of all known marine species. They are the rainforests of the sea.",img:"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&h=350&fit=crop",s:"IUCN",url:"https://en.wikipedia.org/wiki/Coral_reef"},
{i:"🐙",t:"The deep sea is home to the largest squid on Earth",d:"The colossal squid can reach 46 feet long and has eyes the size of dinner plates — the largest in the animal kingdom. It uses rotating hooks on its tentacles to catch prey.",img:"https://images.unsplash.com/photo-1545671913-b89ac1b4ac10?w=600&h=350&fit=crop",s:"Museum of New Zealand Te Papa",url:"https://en.wikipedia.org/wiki/Colossal_squid"},
{i:"🐳",t:"Sperm whales dive deeper than any other mammal",d:"They plunge to depths of 7,380 feet and hold their breath for over 90 minutes. Their skulls contain spermaceti oil that may help regulate buoyancy during these extreme dives.",img:"https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=600&h=350&fit=crop",s:"Marine Mammal Science",url:"https://en.wikipedia.org/wiki/Sperm_whale"},
{i:"🦈",t:"Some deep-sea fish have transparent heads",d:"The barreleye fish has a completely see-through skull. Its tubular eyes can rotate upward to spot prey silhouettes against faint surface light while the rest of its head stays invisible.",img:"https://images.unsplash.com/photo-1551244072-5d12893278ab?w=600&h=350&fit=crop",s:"MBARI",url:"https://en.wikipedia.org/wiki/Barreleye"},
{i:"🌌",t:"Sound waves from ocean creatures are louder than a jet engine",d:"Sperm whale clicks reach 236 decibels and snapping shrimp create 218-decibel cavitation bubbles. Both exceed the 150 decibels of a jet engine at close range.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"Journal of the Acoustical Society",url:"https://en.wikipedia.org/wiki/Snapping_shrimp"},
{i:"🦑",t:"Some jellyfish are biologically immortal",d:"Turritopsis dohrnii can revert from adult medusa back to polyp stage when stressed, essentially resetting its biological clock. In theory, it can do this indefinitely.",img:"https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=600&h=350&fit=crop",s:"Developmental Biology",url:"https://en.wikipedia.org/wiki/Turritopsis_dohrnii"},
{i:"🐠",t:"Parrotfish poop creates white sand beaches",d:"A single parrotfish can produce 800 pounds of white sand per year by eating coral, digesting the algae, and excreting the calcium carbonate as fine sand grains.",img:"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&h=350&fit=crop",s:"National Geographic",url:"https://en.wikipedia.org/wiki/Parrotfish"},
{i:"🐋",t:"Whale songs can travel 10,000 miles across oceans",d:"Low-frequency calls from blue and fin whales propagate through deep ocean sound channels. Before ship noise, whales could communicate across entire ocean basins.",img:"https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=600&h=350&fit=crop",s:"Marine Ecology Progress Series",url:"https://en.wikipedia.org/wiki/Whale_vocalization"},
{i:"☀️",t:"The Sun loses 4 million tons of mass every second",d:"Nuclear fusion converts hydrogen to helium, releasing energy via E=mc squared. The Sun sheds 4.26 million metric tons per second, yet has enough fuel for 5 billion more years.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA",url:"https://en.wikipedia.org/wiki/Sun"},
{i:"🪐",t:"Saturn's density is low enough to float on water",d:"Despite being the second-largest planet, Saturn's average density is only 0.687 grams per cubic centimeter. If you had a bathtub big enough, it would theoretically float.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA JPL",url:"https://en.wikipedia.org/wiki/Saturn"},
{i:"🌑",t:"Neutron stars are so dense a teaspoon weighs 6 billion tons",d:"When massive stars collapse, protons and electrons merge into neutrons packed unimaginably tight. A sugar-cube-sized chunk would outweigh Mount Everest.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"Astrophysical Journal",url:"https://en.wikipedia.org/wiki/Neutron_star"},
{i:"🔭",t:"There are more stars in the universe than grains of sand on Earth",d:"The observable universe contains roughly 200 billion trillion stars. Earth's beaches hold around 7.5 quintillion grains of sand, meaning stars outnumber them by a factor of about 25,000.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"European Space Agency",url:"https://en.wikipedia.org/wiki/Observable_universe"},
{i:"💫",t:"A day on Venus is longer than its year",d:"Venus takes 243 Earth days to rotate once on its axis but only 225 Earth days to orbit the Sun. It also rotates backwards compared to most planets.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA",url:"https://en.wikipedia.org/wiki/Venus"},
{i:"🕳️",t:"Black holes bend time itself",d:"Near a black hole's event horizon, gravity is so extreme that time slows dramatically relative to distant observers. Fall in and seconds for you could be centuries outside.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"Physical Review Letters",url:"https://en.wikipedia.org/wiki/Gravitational_time_dilation"},
{i:"🌠",t:"Olympus Mons on Mars is three times taller than Everest",d:"The largest volcano in the solar system stands 72,000 feet tall and spans the width of France. Its caldera alone could swallow a city, and its slopes are so gradual you would not notice climbing them.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA Mars Exploration",url:"https://en.wikipedia.org/wiki/Olympus_Mons"},
{i:"🌍",t:"The Milky Way and Andromeda will collide in 4.5 billion years",d:"These two galaxies are racing toward each other at 250,000 mph. When they merge, they will form a new giant elliptical galaxy astronomers have already named Milkomeda.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"The Astrophysical Journal",url:"https://en.wikipedia.org/wiki/Andromeda%E2%80%93Milky_Way_collision"},
{i:"✨",t:"There is a giant cloud of alcohol in space",d:"Sagittarius B2, a molecular cloud near the center of the Milky Way, contains enough ethyl alcohol to fill 400 trillion trillion pints of beer.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"Max Planck Institute for Radio Astronomy",url:"https://en.wikipedia.org/wiki/Sagittarius_B2"},
{i:"💎",t:"It rains diamonds on Neptune and Uranus",d:"Extreme pressure and temperature deep inside these ice giants compress methane into diamond crystals. These diamonds may rain down toward the planetary cores like hailstones.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"Nature Physics",url:"https://en.wikipedia.org/wiki/Diamond_rain"},
{i:"🌕",t:"The Moon is slowly drifting away from Earth",d:"Tidal interactions push the Moon about 1.5 inches farther from Earth every year. Billions of years ago, the Moon was so close that days lasted only 6 hours.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA Lunar Reconnaissance",url:"https://en.wikipedia.org/wiki/Lunar_distance"},
{i:"🪐",t:"Jupiter's Great Red Spot is shrinking but still fits two Earths",d:"This anticyclonic storm has raged for at least 350 years. It was once wide enough to fit three Earths across, but satellite observations show it is steadily shrinking.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA Juno Mission",url:"https://en.wikipedia.org/wiki/Great_Red_Spot"},
{i:"🌋",t:"Io is the most volcanically active body in the solar system",d:"Jupiter's moon Io has over 400 active volcanoes, driven by intense tidal heating from Jupiter's gravity. Some eruptions launch material 300 miles above its surface.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA JPL",url:"https://en.wikipedia.org/wiki/Io_(moon)"},
{i:"🌊",t:"Europa likely has more water than all of Earth's oceans combined",d:"Jupiter's moon Europa hides a subsurface ocean beneath its icy crust that may contain twice as much water as Earth. It is a prime candidate in the search for extraterrestrial life.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NASA Europa Clipper",url:"https://en.wikipedia.org/wiki/Europa_(moon)"},
{i:"🦕",t:"The asteroid that killed the dinosaurs hit harder than a billion nukes",d:"The Chicxulub impactor released energy equivalent to 10 billion Hiroshima bombs, creating a crater 110 miles wide and triggering a global winter that wiped out 75% of all species.",img:"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=600&h=350&fit=crop",s:"Science Magazine",url:"https://en.wikipedia.org/wiki/Chicxulub_crater"},
{i:"🐊",t:"Crocodilians have barely changed in 80 million years",d:"Modern crocodiles look remarkably like their Late Cretaceous ancestors. Their body plan is so well-adapted to ambush predation that evolution has had little reason to change it.",img:"https://images.unsplash.com/photo-1497206365907-f5e630693df0?w=600&h=350&fit=crop",s:"Proceedings of the Royal Society B",url:"https://en.wikipedia.org/wiki/Crocodilia"},
{i:"🐟",t:"Coelacanths were thought extinct for 65 million years",d:"Believed to have died with the dinosaurs, a living coelacanth was caught off South Africa in 1938. These lobe-finned fish represent a critical link between fish and land vertebrates.",img:"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&h=350&fit=crop",s:"Nature",url:"https://en.wikipedia.org/wiki/Coelacanth"},
{i:"🦎",t:"Eyes evolved independently over 40 separate times",d:"From the compound eyes of insects to the camera eyes of octopuses and humans, evolution arrived at vision through wildly different paths — a textbook case of convergent evolution.",img:"https://images.unsplash.com/photo-1508963493744-76fce69379c0?w=600&h=350&fit=crop",s:"Annual Review of Ecology",url:"https://en.wikipedia.org/wiki/Evolution_of_the_eye"},
{i:"🦀",t:"Horseshoe crabs have survived all five mass extinctions",d:"These marine arthropods have existed largely unchanged for 450 million years. They predate dinosaurs, trees, and even most insects, making them true living fossils.",img:"https://images.unsplash.com/photo-1560275619-4662e36fa65c?w=600&h=350&fit=crop",s:"American Museum of Natural History",url:"https://en.wikipedia.org/wiki/Horseshoe_crab"},
{i:"🌋",t:"The Great Dying wiped out 96% of all marine species",d:"The Permian-Triassic extinction 252 million years ago was the worst catastrophe in Earth's history. Massive volcanic eruptions in Siberia released enough CO2 to boil the oceans of oxygen.",img:"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=600&h=350&fit=crop",s:"Science",url:"https://en.wikipedia.org/wiki/Permian%E2%80%93Triassic_extinction_event"},
{i:"🐦",t:"Birds are living dinosaurs — literally",d:"Every sparrow, eagle, and penguin is a theropod dinosaur. They descended directly from small feathered raptors, making the Cretaceous extinction not a dinosaur ending but a dinosaur transformation.",img:"https://images.unsplash.com/photo-1473448912268-2022ce9509d8?w=600&h=350&fit=crop",s:"Nature",url:"https://en.wikipedia.org/wiki/Origin_of_birds"},
{i:"🐚",t:"The nautilus has remained virtually unchanged for 500 million years",d:"These chambered cephalopods predate almost every complex animal alive today. Their spiral shells and jet propulsion system have persisted through every mass extinction in history.",img:"https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=600&h=350&fit=crop",s:"Paleobiology",url:"https://en.wikipedia.org/wiki/Nautilus"},
{i:"🦷",t:"T. rex had a bite force of 12,800 pounds — enough to crush a car",d:"Tyrannosaurus rex had the strongest bite of any known land animal. Its serrated teeth could pulverize bone, and fossils show it regularly ate other dinosaurs whole.",img:"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=600&h=350&fit=crop",s:"Proceedings of the Royal Society B",url:"https://en.wikipedia.org/wiki/Tyrannosaurus"},
{i:"🌿",t:"Dolphins and ichthyosaurs evolved nearly identical body shapes",d:"Despite being separated by 200 million years and completely different lineages, both evolved streamlined bodies, dorsal fins, and long snouts. This is convergent evolution at its most dramatic.",img:"https://images.unsplash.com/photo-1564438091-2a6c464c0cd2?w=600&h=350&fit=crop",s:"Integrative and Comparative Biology",url:"https://en.wikipedia.org/wiki/Convergent_evolution"},
{i:"🦠",t:"Oxygen was once a deadly poison to most life on Earth",d:"The Great Oxygenation Event 2.4 billion years ago killed most anaerobic organisms. What we call breathable air was history's first mass pollution event and the worst extinction by percentage.",img:"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=600&h=350&fit=crop",s:"Nature Geoscience",url:"https://en.wikipedia.org/wiki/Great_Oxygenation_Event"},
{i:"🌱",t:"Plants can count, tell time, and do basic math",d:"Arabidopsis plants divide their starch reserves by the number of hours until dawn, performing a kind of arithmetic division to avoid starvation. They adjust this calculation seasonally.",img:"https://images.unsplash.com/photo-1416879595882-3373a0480b5b?w=600&h=350&fit=crop",s:"eLife, 2013",url:"https://en.wikipedia.org/wiki/Plant_cognition"},
{i:"🍄",t:"Fungi communicate with each other using electrical impulses",d:"Researchers found that fungi send electrical signals through their mycelial networks in patterns resembling human language, with up to 50 distinct signal clusters or 'words.'",img:"https://images.unsplash.com/photo-1504198322253-cfa87a0ff25f?w=600&h=350&fit=crop",s:"Royal Society Open Science",url:"https://en.wikipedia.org/wiki/Fungal_communication"},
{i:"🌵",t:"The Welwitschia plant lives 2,000 years with only two leaves",d:"Found only in the Namib Desert, this bizarre plant grows just two continuously splitting leaves for its entire lifespan. Some specimens alive today were seedlings when the Roman Empire stood.",img:"https://images.unsplash.com/photo-1470058869958-2a77beeae652?w=600&h=350&fit=crop",s:"Botanical Journal of the Linnean Society",url:"https://en.wikipedia.org/wiki/Welwitschia"},
{i:"🌻",t:"Sunflowers follow the sun using an internal clock",d:"Young sunflowers track the sun from east to west during the day and reset at night using circadian-regulated differential growth. Once mature, they permanently face east to warm up faster.",img:"https://images.unsplash.com/photo-1558642452-9d2a7deb7f62?w=600&h=350&fit=crop",s:"Science, 2016",url:"https://en.wikipedia.org/wiki/Heliotropism"},
{i:"🍄",t:"A single mushroom can release 30,000 spores per second",d:"Some fungi launch spores at accelerations 10,000 times greater than a rocket launch. A giant puffball mushroom can release 7 trillion spores in a single fruiting event.",img:"https://images.unsplash.com/photo-1504198322253-cfa87a0ff25f?w=600&h=350&fit=crop",s:"PLOS ONE",url:"https://en.wikipedia.org/wiki/Spore"},
{i:"🌿",t:"The Venus flytrap can count to five",d:"It requires two trigger hair touches within 20 seconds to snap shut. Three touches activate digestion enzymes. Five touches maximize nutrient absorption. Each touch fires an action potential.",img:"https://images.unsplash.com/photo-1416879595882-3373a0480b5b?w=600&h=350&fit=crop",s:"Current Biology",url:"https://en.wikipedia.org/wiki/Venus_flytrap"},
{i:"🌲",t:"Trees share nutrients with sick neighbors through fungal networks",d:"Mother trees preferentially feed their offspring and ailing neighbors through mycorrhizal networks. Dying trees dump their carbon into the network as a final gift to the forest.",img:"https://images.unsplash.com/photo-1473448912268-2022ce9509d8?w=600&h=350&fit=crop",s:"Ecology Letters",url:"https://en.wikipedia.org/wiki/Mycorrhizal_network"},
{i:"🌺",t:"Some orchids mimic female wasps so well that males try to mate with them",d:"The hammer orchid produces a fake female wasp complete with pheromones. When male wasps attempt to mate with the flower, they get dusted with pollen they carry to the next trap.",img:"https://images.unsplash.com/photo-1490750967868-88aa4f44baee?w=600&h=350&fit=crop",s:"American Journal of Botany",url:"https://en.wikipedia.org/wiki/Pseudocopulation"},
{i:"🍃",t:"Eucalyptus trees can explode during bushfires",d:"Their leaves contain highly flammable oils that vaporize in extreme heat. The oil vapor can ignite mid-air, creating explosive fireballs that spread fire across wide gaps.",img:"https://images.unsplash.com/photo-1470058869958-2a77beeae652?w=600&h=350&fit=crop",s:"International Journal of Wildland Fire",url:"https://en.wikipedia.org/wiki/Eucalyptus"},
{i:"🍄",t:"Fungi are more closely related to animals than to plants",d:"The animal and fungal kingdoms share a common ancestor that plants do not. Like animals, fungi are heterotrophs that digest food externally and store energy as glycogen, not starch.",img:"https://images.unsplash.com/photo-1504198322253-cfa87a0ff25f?w=600&h=350&fit=crop",s:"Nature Reviews Genetics",url:"https://en.wikipedia.org/wiki/Opisthokont"},
{i:"🌱",t:"Bamboo can grow 35 inches in a single day",d:"Some bamboo species hold the record for the fastest-growing plant on Earth. You can practically watch them grow — they add about 1.5 inches per hour at peak growth.",img:"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=600&h=350&fit=crop",s:"Guinness World Records",url:"https://en.wikipedia.org/wiki/Bamboo"},
{i:"⚛️",t:"An atom is 99.9999999999996% empty space",d:"If an atom's nucleus were a marble, its electrons would orbit a mile away. Nearly all the 'solid' matter you touch is overwhelmingly nothing but empty space held together by forces.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"CERN",url:"https://en.wikipedia.org/wiki/Atom"},
{i:"🔬",t:"Quantum entanglement is real and proven — Einstein called it 'spooky'",d:"Two entangled particles instantly correlate their states regardless of distance. The 2022 Nobel Prize in Physics confirmed this violates local realism. Einstein was right that it was spooky, but wrong that it was impossible.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nobel Prize Committee, 2022",url:"https://en.wikipedia.org/wiki/Quantum_entanglement"},
{i:"🧊",t:"Hot water can freeze faster than cold water",d:"The Mpemba effect has been observed since Aristotle's time. Under certain conditions, warm water reaches freezing before cold water does. The exact mechanism is still debated by physicists.",img:"https://images.unsplash.com/photo-1558104631-0fa41a8a3cb1?w=600&h=350&fit=crop",s:"Journal of Chemical Education",url:"https://en.wikipedia.org/wiki/Mpemba_effect"},
{i:"⚡",t:"Lightning is five times hotter than the surface of the Sun",d:"A lightning bolt reaches temperatures of 30,000 Kelvin, while the Sun's surface is about 5,778 Kelvin. This superheated channel of air expands so rapidly it creates the shockwave we hear as thunder.",img:"https://images.unsplash.com/photo-1497206365907-f5e630693df0?w=600&h=350&fit=crop",s:"NOAA",url:"https://en.wikipedia.org/wiki/Lightning"},
{i:"🧲",t:"Superconductors let electricity flow forever with zero resistance",d:"Below a critical temperature, certain materials lose all electrical resistance. A current started in a superconducting loop would theoretically flow for billions of years without diminishing.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"Physical Review Letters",url:"https://en.wikipedia.org/wiki/Superconductivity"},
{i:"💧",t:"Water is one of only a few substances that expand when freezing",d:"Most liquids become denser as they solidify, but ice is about 9% less dense than liquid water. This anomaly is why ice floats and why life in lakes can survive winter beneath frozen surfaces.",img:"https://images.unsplash.com/photo-1558104631-0fa41a8a3cb1?w=600&h=350&fit=crop",s:"Journal of Physical Chemistry",url:"https://en.wikipedia.org/wiki/Properties_of_water"},
{i:"🔥",t:"Glass is neither a solid nor a liquid — it is an amorphous solid",d:"Glass molecules are frozen in a disordered liquid-like arrangement rather than a crystalline lattice. The myth that old windows are thicker at the bottom due to flow is false; they were just made unevenly.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"Journal of Non-Crystalline Solids",url:"https://en.wikipedia.org/wiki/Amorphous_solid"},
{i:"⚛️",t:"Quantum tunneling lets particles pass through solid walls",d:"A particle can appear on the other side of a barrier it classically cannot cross. This is not science fiction — it is how the Sun fuses hydrogen and how flash memory stores data.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Reviews of Modern Physics",url:"https://en.wikipedia.org/wiki/Quantum_tunnelling"},
{i:"🧪",t:"A single gram of graphene could cover a football field",d:"Graphene is a one-atom-thick sheet of carbon that is 200 times stronger than steel, conducts electricity better than copper, and is nearly transparent. It won the 2010 Nobel Prize.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"Nobel Prize Committee, 2010",url:"https://en.wikipedia.org/wiki/Graphene"},
{i:"🧲",t:"Helium becomes a superfluid that defies gravity",d:"Below 2.17 Kelvin, helium-4 flows with zero viscosity. It can climb walls, flow through atom-thin cracks, and remain perfectly still in a spinning container. It is the strangest liquid known.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nature Physics",url:"https://en.wikipedia.org/wiki/Superfluid_helium-4"},
{i:"⏱️",t:"Time genuinely moves slower at sea level than on a mountaintop",d:"Einstein's general relativity predicts that gravity slows time, and atomic clocks confirm it. A clock at sea level ticks measurably slower than one at high altitude. GPS satellites must correct for this daily.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Physical Review Letters",url:"https://en.wikipedia.org/wiki/Gravitational_time_dilation"},
{i:"🧬",t:"Epigenetic changes from trauma can be inherited for generations",d:"Studies on Holocaust survivors and famine victims show stress-induced epigenetic marks passed to children and grandchildren, altering cortisol regulation without changing the DNA sequence itself.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Biological Psychiatry",url:"https://en.wikipedia.org/wiki/Transgenerational_epigenetic_inheritance"},
{i:"🧬",t:"CRISPR can now edit thousands of genes simultaneously",d:"Multiplexed CRISPR screening allows scientists to knock out or activate thousands of genes in a single experiment, dramatically accelerating the search for disease-causing genetic variants.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Nature Methods",url:"https://en.wikipedia.org/wiki/CRISPR_gene_editing"},
{i:"🧪",t:"Synthetic biology has created organisms with a six-letter genetic code",d:"Natural DNA uses four bases — A, T, C, G. Scientists added two artificial bases, creating the first semi-synthetic organism that can store and retrieve information nature never encoded.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Nature, 2017",url:"https://en.wikipedia.org/wiki/Expanded_genetic_code"},
{i:"🧬",t:"Your identical twin's fingerprints are completely different from yours",d:"Even with identical DNA, fingerprint patterns are influenced by random prenatal pressures and amniotic fluid flow. No two fingerprints — even from the same person — are exactly alike.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Forensic Science International",url:"https://en.wikipedia.org/wiki/Fingerprint"},
{i:"🧫",t:"Scientists built a synthetic cell that grows and divides normally",d:"Craig Venter's team created a minimal synthetic cell with just 473 genes. After adding back discovered division genes, the cell divides into uniform shapes just like natural bacteria.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Cell, 2021",url:"https://en.wikipedia.org/wiki/Mycoplasma_laboratorium"},
{i:"🧬",t:"Horizontal gene transfer means you share genes with viruses",d:"About 8% of the human genome comes from ancient retroviral DNA. These viral genes were co-opted millions of years ago and some are now essential — including genes for placenta formation.",img:"https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=600&h=350&fit=crop",s:"Cell",url:"https://en.wikipedia.org/wiki/Endogenous_retrovirus"},
{i:"🧬",t:"Women are genetic mosaics — each cell randomly silences one X chromosome",d:"In every female cell, one X chromosome is randomly inactivated. This means women are a patchwork of two different X-linked gene expressions. Calico cats display this visibly as fur patches.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Nature Reviews Genetics",url:"https://en.wikipedia.org/wiki/X-inactivation"},
{i:"🧬",t:"Telomere length predicts biological aging better than birthdate",d:"Telomeres are protective caps on chromosomes that shorten with each cell division. Chronic stress, poor sleep, and smoking accelerate this shortening, while exercise and meditation slow it.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"The Lancet Oncology",url:"https://en.wikipedia.org/wiki/Telomere"},
{i:"🐦",t:"Crows use tools, solve multi-step puzzles, and hold grudges",d:"New Caledonian crows craft hook tools from sticks and can solve eight-step sequential puzzles. They also recognize individual human faces and remember those who threatened them for years.",img:"https://images.unsplash.com/photo-1473448912268-2022ce9509d8?w=600&h=350&fit=crop",s:"Science",url:"https://en.wikipedia.org/wiki/New_Caledonian_crow"},
{i:"🐜",t:"Leafcutter ants invented agriculture 50 million years before humans",d:"They cultivate specialized fungus gardens, feed them with chewed leaves, apply antibiotics to prevent mold, and even weed out competing fungi — a complete farming system.",img:"https://images.unsplash.com/photo-1556983852-43bf21186b2a?w=600&h=350&fit=crop",s:"Annual Review of Ecology",url:"https://en.wikipedia.org/wiki/Leafcutter_ant"},
{i:"🐦",t:"Arctic terns migrate 44,000 miles every year — pole to pole",d:"They fly from the Arctic to the Antarctic and back, seeing more daylight than any other animal. Over a 30-year lifespan, they fly the equivalent of three round trips to the Moon.",img:"https://images.unsplash.com/photo-1497206365907-f5e630693df0?w=600&h=350&fit=crop",s:"PNAS",url:"https://en.wikipedia.org/wiki/Arctic_tern"},
{i:"🐙",t:"Octopuses edit their own RNA on the fly",d:"Instead of relying solely on DNA mutations for adaptation, octopuses extensively edit their messenger RNA. This gives them extraordinary neural flexibility but slows their DNA evolution.",img:"https://images.unsplash.com/photo-1545671913-b89ac1b4ac10?w=600&h=350&fit=crop",s:"Cell, 2017",url:"https://en.wikipedia.org/wiki/RNA_editing"},
{i:"🐘",t:"Elephants mourn their dead and perform funeral rituals",d:"They return to bones of deceased family members, gently touching them with their trunks. They have been observed covering dead companions with branches and earth and standing vigil for days.",img:"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=600&h=350&fit=crop",s:"Applied Animal Behaviour Science",url:"https://en.wikipedia.org/wiki/Elephant_cognition"},
{i:"🐀",t:"Rats laugh when you tickle them",d:"Rats produce ultrasonic chirps at 50 kHz — inaudible to humans — when tickled. They seek out tickling, play-chase the researcher's hand, and their laughter has distinct patterns like human giggles.",img:"https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=600&h=350&fit=crop",s:"Science, 2016",url:"https://en.wikipedia.org/wiki/Rat#Intelligence"},
{i:"🐋",t:"Humpback whales compose new songs that spread like pop hits",d:"A new whale song can spread across entire ocean populations in just a few years. Old songs are abandoned and new ones are adopted, suggesting cultural transmission and aesthetic preference.",img:"https://images.unsplash.com/photo-1568430462989-44163eb1752f?w=600&h=350&fit=crop",s:"Current Biology",url:"https://en.wikipedia.org/wiki/Whale_song"},
{i:"🐦",t:"Pigeons can learn to distinguish Monet from Picasso paintings",d:"In lab studies, pigeons correctly categorized paintings by artist style they had never seen before. They process visual information using pattern recognition similar to human art perception.",img:"https://images.unsplash.com/photo-1577936168622-a7ba1edcaee2?w=600&h=350&fit=crop",s:"Journal of Experimental Psychology",url:"https://en.wikipedia.org/wiki/Pigeon_intelligence"},
{i:"🐟",t:"Cleaner fish recognize themselves in mirrors",d:"Cleaner wrasses pass the mirror self-recognition test — previously thought exclusive to great apes, elephants, and dolphins. They try to scrub off marks only visible in the mirror.",img:"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&h=350&fit=crop",s:"PLOS Biology",url:"https://en.wikipedia.org/wiki/Mirror_test"},
{i:"🐜",t:"Some ants perform amputation surgery on wounded nestmates",d:"Florida carpenter ants bite off the infected limbs of injured colony members. The survival rate of these ant amputees is 90-95%, compared to 40% for untreated wounded ants.",img:"https://images.unsplash.com/photo-1556983852-43bf21186b2a?w=600&h=350&fit=crop",s:"Current Biology, 2024",url:"https://en.wikipedia.org/wiki/Ant_colony"},
{i:"🌍",t:"Earth's inner core rotates at a different speed than the rest of the planet",d:"Seismic data suggests the solid iron inner core may rotate slightly faster or slower than the mantle. Some research indicates it may have recently reversed its rotation direction.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"Nature Geoscience",url:"https://en.wikipedia.org/wiki/Earth%27s_inner_core"},
{i:"🌋",t:"Yellowstone sits atop a magma chamber that could cover the entire US in ash",d:"The Yellowstone supervolcano's magma reservoir holds enough material that a full eruption would blanket most of North America in volcanic ash and temporarily alter global climate.",img:"https://images.unsplash.com/photo-1531386151447-fd76ad50012f?w=600&h=350&fit=crop",s:"USGS Volcano Hazards",url:"https://en.wikipedia.org/wiki/Yellowstone_Caldera"},
{i:"⛰️",t:"The Himalayas grow taller by about half an inch every year",d:"The Indian tectonic plate continues to ram into the Eurasian plate at ~2 inches per year, pushing the Himalayas higher. Erosion partially offsets this, but Everest is still getting taller.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"Geological Society of America",url:"https://en.wikipedia.org/wiki/Himalayas"},
{i:"🌍",t:"Earth's magnetic poles have flipped hundreds of times",d:"The last geomagnetic reversal happened 780,000 years ago. During a flip, the magnetic field weakens to about 10% of normal strength, potentially exposing the surface to increased radiation.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"Nature Reviews Earth & Environment",url:"https://en.wikipedia.org/wiki/Geomagnetic_reversal"},
{i:"🌏",t:"All continents were once a single landmass called Pangaea",d:"About 335 million years ago, Earth had one supercontinent and one mega-ocean. Pangaea began breaking apart 175 million years ago, and the continents are still drifting today.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"American Geophysical Union",url:"https://en.wikipedia.org/wiki/Pangaea"},
{i:"🌊",t:"A cubic mile of seawater contains 25 tons of gold",d:"The world's oceans hold an estimated 20 million tons of dissolved gold. At current prices that is worth roughly $750 trillion, but extracting it costs far more than the gold is worth.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"NOAA",url:"https://en.wikipedia.org/wiki/Gold_extraction"},
{i:"⚡",t:"Earth is struck by lightning 8.6 million times per day",d:"That is roughly 100 bolts per second worldwide. Lightning creates temperatures hotter than the Sun's surface and generates radio waves detectable from space.",img:"https://images.unsplash.com/photo-1497206365907-f5e630693df0?w=600&h=350&fit=crop",s:"Journal of Geophysical Research",url:"https://en.wikipedia.org/wiki/Lightning"},
{i:"🌋",t:"The Ring of Fire hosts 75% of the world's active volcanoes",d:"This 25,000-mile horseshoe around the Pacific Ocean is where tectonic plates collide and subduct. It produces 90% of the world's earthquakes and the most explosive volcanic eruptions.",img:"https://images.unsplash.com/photo-1531386151447-fd76ad50012f?w=600&h=350&fit=crop",s:"USGS",url:"https://en.wikipedia.org/wiki/Ring_of_Fire"},
{i:"🏔️",t:"Mauna Kea is taller than Everest when measured from its base",d:"From its base on the ocean floor, Mauna Kea in Hawaii rises 33,500 feet — over 4,000 feet taller than Everest. More than half of this massive shield volcano is hidden underwater.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"National Geographic",url:"https://en.wikipedia.org/wiki/Mauna_Kea"},
{i:"🌎",t:"Earth's atmosphere weighs 5.5 quadrillion tons",d:"This invisible ocean of gas exerts 14.7 pounds of pressure on every square inch of your body right now. You do not feel it because internal body pressure pushes back equally.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"NOAA",url:"https://en.wikipedia.org/wiki/Atmosphere_of_Earth"},
{i:"🌊",t:"The ocean's thermohaline circulation takes 1,000 years to complete one loop",d:"This global conveyor belt of ocean currents moves warm surface water toward the poles and returns cold deep water toward the equator. It regulates climate for the entire planet.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"Nature Climate Change",url:"https://en.wikipedia.org/wiki/Thermohaline_circulation"},
{i:"🤖",t:"AI detected breast cancer 5 years before it appeared on mammograms",d:"MIT's deep learning algorithm identified subtle tissue patterns that predicted future cancer in patients whose scans were read as normal by radiologists. It works across all demographics.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Radiology, MIT CSAIL",url:"https://en.wikipedia.org/wiki/Artificial_intelligence_in_healthcare"},
{i:"🦿",t:"Bionic limbs can now be controlled by thought alone",d:"Osseointegrated prosthetics connected directly to bone and nerves let amputees feel texture, temperature, and pressure. Users report that the prosthetic feels like part of their own body.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"Science Robotics",url:"https://en.wikipedia.org/wiki/Neuroprosthetics"},
{i:"🔬",t:"Nanobots can deliver drugs directly inside individual cancer cells",d:"DNA origami nanorobots unfold and release chemotherapy payloads only when they detect specific tumor surface markers, sparing healthy tissue from the devastating side effects of treatment.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nature Biotechnology",url:"https://en.wikipedia.org/wiki/Nanomedicine"},
{i:"🧠",t:"Neuralink's brain chip let a paralyzed man play chess with his mind",d:"In 2024, the first human Neuralink recipient used a brain-computer interface to control a computer cursor and play chess and video games using only his thoughts.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"Neuralink / Nature Medicine",url:"https://en.wikipedia.org/wiki/Neuralink"},
{i:"🧪",t:"CRISPR-based diagnostics detect diseases from a single drop of blood",d:"SHERLOCK and DETECTR platforms use CRISPR to identify specific viral or bacterial DNA sequences in minutes. They can spot infections like COVID, Zika, and dengue with lab-grade accuracy at point of care.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Science",url:"https://en.wikipedia.org/wiki/SHERLOCK_(molecular_biology)"},
{i:"🫀",t:"3D-printed hearts using patient cells could end transplant waiting lists",d:"Researchers printed a miniature heart from a patient's own cells, complete with chambers and blood vessels. Scaling up could eliminate organ rejection since the heart is built from your own tissue.",img:"https://images.unsplash.com/photo-1628348068343-c6a848d2b6dd?w=600&h=350&fit=crop",s:"Advanced Science",url:"https://en.wikipedia.org/wiki/3D_bioprinting"},
{i:"🔬",t:"Liquid biopsies detect 50+ types of cancer from a blood draw",d:"Circulating tumor DNA shed into the bloodstream can reveal cancer location and type years before symptoms appear. The Galleri test screens for over 50 cancer types from a single tube of blood.",img:"https://images.unsplash.com/photo-1615631648086-325025c9e51e?w=600&h=350&fit=crop",s:"Annals of Oncology",url:"https://en.wikipedia.org/wiki/Liquid_biopsy"},
{i:"🤖",t:"AlphaFold predicted the shape of every known protein",d:"DeepMind's AI solved a 50-year grand challenge in biology by predicting 3D structures of 200+ million proteins. This database is accelerating drug discovery worldwide at unprecedented speed.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"Nature, 2022",url:"https://en.wikipedia.org/wiki/AlphaFold"},
{i:"💊",t:"Implantable devices can release insulin automatically for diabetics",d:"Closed-loop artificial pancreas systems monitor glucose levels continuously and deliver precise insulin doses. Patients report sleeping through the night without blood sugar emergencies for the first time.",img:"https://images.unsplash.com/photo-1628348068343-c6a848d2b6dd?w=600&h=350&fit=crop",s:"The Lancet Diabetes & Endocrinology",url:"https://en.wikipedia.org/wiki/Artificial_pancreas"},
{i:"🦠",t:"Fecal transplants cure deadly gut infections where antibiotics fail",d:"Transferring gut bacteria from a healthy donor cures Clostridioides difficile infection in over 90% of cases. It works by restoring the diverse microbiome that antibiotics destroyed.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"New England Journal of Medicine",url:"https://en.wikipedia.org/wiki/Fecal_microbiota_transplant"},
{i:"🔬",t:"CRISPR pig organs could solve the organ transplant crisis",d:"Scientists edited 69 genes in pig DNA to remove viruses and reduce immune rejection. These engineered organs could save thousands of people who die waiting for human donor organs each year.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Nature, 2023",url:"https://en.wikipedia.org/wiki/Xenotransplantation"},
{i:"🧊",t:"There is a lake buried under two miles of Antarctic ice",d:"Lake Vostok has been sealed beneath the Antarctic ice sheet for 15-25 million years. It may harbor unique life forms that evolved in total isolation from the rest of Earth.",img:"https://images.unsplash.com/photo-1558104631-0fa41a8a3cb1?w=600&h=350&fit=crop",s:"Nature Geoscience",url:"https://en.wikipedia.org/wiki/Lake_Vostok"},
{i:"🐝",t:"Honeybees vote on new homes using a democratic dance-off",d:"Scout bees perform waggle dances to advertise candidate nest sites. The colony reaches consensus when enough scouts dance for the same location — a quorum-based decision system.",img:"https://images.unsplash.com/photo-1558642452-9d2a7deb7f62?w=600&h=350&fit=crop",s:"Science",url:"https://en.wikipedia.org/wiki/Waggle_dance"},
{i:"🌋",t:"There are more than 3 million shipwrecks on the ocean floor",d:"Only a fraction have been explored. Many preserve unique microbial ecosystems, and deep-water wrecks can survive virtually intact for centuries due to the absence of oxygen and light.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"UNESCO",url:"https://en.wikipedia.org/wiki/Shipwreck"},
{i:"🧬",t:"Chimeric antigen receptors can now target solid tumors too",d:"New-generation CAR-T designs overcome the immunosuppressive tumor microenvironment. Armored CARs secrete cytokines that recruit the body's own immune cells to join the attack on solid cancers.",img:"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=600&h=350&fit=crop",s:"Nature Reviews Cancer",url:"https://en.wikipedia.org/wiki/Chimeric_antigen_receptor_T_cell"},
{i:"🌌",t:"The cosmic microwave background is the oldest light in the universe",d:"This faint glow is the afterglow of the Big Bang, emitted 380,000 years after the universe began. It fills all of space and has been cooling for 13.8 billion years to just 2.7 Kelvin.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"ESA Planck Mission",url:"https://en.wikipedia.org/wiki/Cosmic_microwave_background"},
{i:"🐕",t:"Dogs can smell disease — including COVID, cancer, and diabetes",d:"Trained medical detection dogs identify volatile organic compounds from diseases with accuracy rivaling laboratory tests. Some dogs detect low blood sugar episodes 20 minutes before they happen.",img:"https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=600&h=350&fit=crop",s:"The Lancet Infectious Diseases",url:"https://en.wikipedia.org/wiki/Medical_detection_dog"},
{i:"🔭",t:"The James Webb Space Telescope sees galaxies from 13.5 billion years ago",d:"JWST's infrared instruments peer so deep into space that it observes galaxies forming just 300 million years after the Big Bang. It found unexpectedly massive galaxies that challenge existing theories.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"NASA JWST",url:"https://en.wikipedia.org/wiki/James_Webb_Space_Telescope"},
{i:"🧊",t:"There is a desert in Antarctica that has not seen rain in 2 million years",d:"The McMurdo Dry Valleys are the driest place on Earth. Katabatic winds evaporate all moisture, creating a landscape so barren that NASA uses it to simulate conditions on Mars.",img:"https://images.unsplash.com/photo-1558104631-0fa41a8a3cb1?w=600&h=350&fit=crop",s:"Antarctic Science",url:"https://en.wikipedia.org/wiki/McMurdo_Dry_Valleys"},
{i:"🦠",t:"Bacteriophages outnumber bacteria 10 to 1 and shape all ecosystems",d:"These bacteria-killing viruses are the most abundant biological entities on Earth. They kill roughly 40% of ocean bacteria daily, driving nutrient cycling that sustains all marine food webs.",img:"https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?w=600&h=350&fit=crop",s:"Nature Reviews Microbiology",url:"https://en.wikipedia.org/wiki/Bacteriophage"},
{i:"🧬",t:"Every human alive descends from a single woman who lived 200,000 years ago",d:"Mitochondrial Eve is the most recent common matrilineal ancestor of all living humans. She lived in East Africa, and her mitochondrial DNA is carried by every person on Earth today.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Nature Genetics",url:"https://en.wikipedia.org/wiki/Mitochondrial_Eve"},
{i:"🌿",t:"Some plants reset their age by cloning themselves for millennia",d:"A clonal colony of quaking aspen in Utah called Pando is connected by one root system and is estimated to be 80,000 years old. It is among the oldest and heaviest known living organisms.",img:"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=600&h=350&fit=crop",s:"PLOS ONE",url:"https://en.wikipedia.org/wiki/Pando_(tree)"},
{i:"🧫",t:"Tardigrades survived being shot from a gun at 2,000 mph",d:"In impact experiments simulating meteorite strikes, tardigrades survived accelerations of 3,000 g. This suggests they could potentially survive interplanetary transfer on asteroid debris.",img:"https://images.unsplash.com/photo-1579165466741-7f35e4755660?w=600&h=350&fit=crop",s:"Astrobiology",url:"https://en.wikipedia.org/wiki/Panspermia"},
{i:"🐦",t:"The bar-tailed godwit flies 7,000 miles nonstop without eating or drinking",d:"This shorebird holds the record for the longest nonstop flight of any bird. It flies from Alaska to New Zealand in about 11 days, burning half its body weight in fat as fuel.",img:"https://images.unsplash.com/photo-1497206365907-f5e630693df0?w=600&h=350&fit=crop",s:"Ornithological Science",url:"https://en.wikipedia.org/wiki/Bar-tailed_godwit"},
{i:"🧠",t:"Your brain can store roughly 2.5 petabytes of information",d:"That is enough to hold 3 million hours of television. Each of your 86 billion neurons forms up to 10,000 synaptic connections, creating a storage network more complex than the internet.",img:"https://images.unsplash.com/photo-1559757175-5700dde675bc?w=600&h=350&fit=crop",s:"Salk Institute",url:"https://en.wikipedia.org/wiki/Neuroscience_of_memory"},
{i:"⚛️",t:"If you removed the empty space from atoms, humanity would fit in a sugar cube",d:"Atoms are overwhelmingly empty. If you collapsed the space between nuclei and electrons in every human body, the entire human race would compress into a volume smaller than a sugar cube.",img:"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=600&h=350&fit=crop",s:"CERN",url:"https://en.wikipedia.org/wiki/Atomic_nucleus"},
{i:"🌋",t:"Iceland is splitting in two along the Mid-Atlantic Ridge",d:"Iceland sits directly on the boundary between the North American and Eurasian plates. The island is being pulled apart at about 1 inch per year, creating dramatic rift valleys and volcanic activity.",img:"https://images.unsplash.com/photo-1531386151447-fd76ad50012f?w=600&h=350&fit=crop",s:"Geological Society of America",url:"https://en.wikipedia.org/wiki/Mid-Atlantic_Ridge"},
{i:"🐟",t:"The Antarctic icefish has no hemoglobin and clear blood",d:"This is the only vertebrate with no red blood cells. It survives because Antarctic waters are so cold and oxygen-rich that dissolved oxygen diffuses directly through its enlarged heart and blood vessels.",img:"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&h=350&fit=crop",s:"Nature",url:"https://en.wikipedia.org/wiki/Icefish"},
{i:"💡",t:"LED lights were invented accidentally while trying to make lasers",d:"Nick Holonyak Jr. created the first visible LED in 1962 at General Electric. LED technology now saves roughly 570 million tons of CO2 emissions per year compared to incandescent lighting.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"Applied Physics Letters",url:"https://en.wikipedia.org/wiki/Light-emitting_diode"},
{i:"🦕",t:"Some dinosaurs had feathers and were as colorful as parrots",d:"Melanosomes preserved in fossil feathers reveal dinosaurs like Sinosauropteryx had russet and white banding. Microraptor had iridescent black feathers that shimmered like a starling.",img:"https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=600&h=350&fit=crop",s:"Science, 2012",url:"https://en.wikipedia.org/wiki/Feathered_dinosaur"},
{i:"🧪",t:"Aerogel is 99.8% air and can support 4,000 times its own weight",d:"This ghostly translucent material is the lightest solid ever created. It insulates so well that NASA uses it to catch comet dust traveling at six times the speed of a bullet.",img:"https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&h=350&fit=crop",s:"NASA JPL",url:"https://en.wikipedia.org/wiki/Aerogel"},
{i:"🐠",t:"Anglerfish males permanently fuse to females and share a bloodstream",d:"Deep-sea anglerfish males are tiny parasites. When one finds a female, he bites into her body and their tissues merge. He degenerates into a pair of gonads that she uses when ready to spawn.",img:"https://images.unsplash.com/photo-1551244072-5d12893278ab?w=600&h=350&fit=crop",s:"Journal of Ichthyology",url:"https://en.wikipedia.org/wiki/Anglerfish"},
{i:"🌍",t:"Earth's rotation is slowing — days are getting longer",d:"Tidal friction from the Moon is gradually braking Earth's spin. Days are about 2 milliseconds longer per century. A billion years ago, a day lasted only 18 hours.",img:"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=600&h=350&fit=crop",s:"Proceedings of the Royal Society A",url:"https://en.wikipedia.org/wiki/Earth%27s_rotation"},
{i:"🧲",t:"Magnetars have fields a quadrillion times stronger than Earth's",d:"These neutron stars have the most powerful magnetic fields in the known universe. At close range, their field would distort atoms into needle shapes and warp the fabric of spacetime itself.",img:"https://images.unsplash.com/photo-1504450874802-0ba2bcd659e3?w=600&h=350&fit=crop",s:"The Astrophysical Journal",url:"https://en.wikipedia.org/wiki/Magnetar"},
{i:"🧬",t:"Naked mole rats are virtually immune to cancer",d:"They produce high-molecular-mass hyaluronic acid that prevents cells from overcrowding. In over 30 years of study, spontaneous cancer in naked mole rats has almost never been observed.",img:"https://images.unsplash.com/photo-1530026405186-ed1f139313bb?w=600&h=350&fit=crop",s:"Nature",url:"https://en.wikipedia.org/wiki/Naked_mole-rat"},
{i:"🌊",t:"The ocean floor has mountains taller than anything on land",d:"The Mid-Ocean Ridge system stretches 40,000 miles and includes peaks rising 13,000 feet above the abyssal plains. It is the longest mountain chain on Earth, yet is almost entirely unseen.",img:"https://images.unsplash.com/photo-1559291001-693fb9166cba?w=600&h=350&fit=crop",s:"NOAA Ocean Exploration",url:"https://en.wikipedia.org/wiki/Mid-ocean_ridge"},
{i:"🦇",t:"Bats eat up to 1,200 mosquitoes per hour",d:"A single colony of Mexican free-tailed bats can consume 250 tons of insects per night. Without bats, mosquito-borne diseases and crop pest damage would skyrocket.",img:"https://images.unsplash.com/photo-1473448912268-2022ce9509d8?w=600&h=350&fit=crop",s:"Bat Conservation International",url:"https://en.wikipedia.org/wiki/Bat"},
];

