const THIS_OR_THAT = [
  {q:"Which has MORE?",a:"🧠",al:"Neurons in your brain",b:"⭐",bl:"Stars in the Milky Way",w:"b",ans:"Stars win!",e:"86 billion neurons vs ~200–400 billion stars. The Milky Way has at least 2–4x more stars than your brain has neurons!"},
  {q:"Which is FASTER?",a:"⚡",al:"Nerve impulse",b:"🔊",bl:"Speed of sound",w:"a",ans:"Nerve impulse!",e:"Nerve impulses reach 120 m/s (268 mph) vs speed of sound at 343 m/s. Actually, sound is faster — but myelinated nerves are shockingly close!"},
  {q:"Which is LONGER?",a:"🧬",al:"DNA in one cell",b:"🏀",bl:"Basketball court",w:"a",ans:"DNA by far!",e:"DNA in one cell stretches ~2 meters. A basketball court is ~28 meters. But ALL your cells' DNA? 34 billion miles — to Pluto and back!"},
  {q:"Which has MORE cells?",a:"🧫",al:"Your body (human cells)",b:"🦠",bl:"Your body (bacteria)",w:"b",ans:"Bacteria win!",e:"~37 trillion human cells vs ~38 trillion bacteria. They slightly outnumber you — you're more microbe than human by cell count!"},
  {q:"Which lives LONGER?",a:"🐢",al:"Giant tortoise",b:"🦈",bl:"Greenland shark",w:"b",ans:"Greenland shark!",e:"Giant tortoises live ~150–175 years. Greenland sharks live 400+ years — they don't even mature until age 150!"},
  {q:"Which is STRONGER per weight?",a:"🕸️",al:"Spider silk",b:"🔩",bl:"Steel",w:"a",ans:"Spider silk!",e:"Spider silk is 5x stronger than steel by weight and more flexible than Kevlar. Nature's ultimate fiber!"},
  {q:"Which pumps MORE blood daily?",a:"🫀",al:"Human heart",b:"🐋",bl:"Blue whale heart",w:"b",ans:"Blue whale!",e:"Your heart pumps ~2,000 gallons/day. A blue whale's heart pumps ~60,000 gallons/day — and it's the size of a small car."},
  {q:"Which has MORE eyes?",a:"🕷️",al:"Spider",b:"🦞",bl:"Scallop",w:"b",ans:"Scallop wins!",e:"Most spiders have 8 eyes. But scallops have up to 200 eyes along their mantle, each with a tiny mirror like a telescope!"},
  {q:"Which animal is MORE venomous?",a:"🐍",al:"Inland taipan snake",b:"🪼",bl:"Box jellyfish",w:"b",ans:"Box jellyfish!",e:"The inland taipan has the most toxic venom per bite, but box jellyfish venom can kill in minutes and has caused more human deaths."},
  {q:"Which is HEAVIER?",a:"🐘",al:"All elephants on Earth",b:"🐜",bl:"All ants on Earth",w:"b",ans:"It's close!",e:"Both weigh roughly 80 million tons! ~20 quadrillion ants collectively match the biomass of all elephants — there are just SO many ants."},
  {q:"Which came FIRST?",a:"🦈",al:"Sharks",b:"🌲",bl:"Trees",w:"a",ans:"Sharks!",e:"Sharks appeared ~450 million years ago. Trees evolved ~360 million years ago. Sharks are 90 million years older than trees!"},
  {q:"Which is HOTTER?",a:"☀️",al:"Surface of the Sun",b:"⚡",bl:"Lightning bolt",w:"b",ans:"Lightning!",e:"The Sun's surface is ~5,500°C. A lightning bolt reaches ~30,000°C — about 5x hotter than the surface of the Sun!"},
  {q:"Which BEATS faster?",a:"🐁",al:"Mouse heart",b:"🐦",bl:"Hummingbird heart",w:"b",ans:"Hummingbird!",e:"Mouse: ~600 bpm. Hummingbird: up to 1,260 bpm — over 20 beats per second! The fastest heart in the animal kingdom."},
  {q:"Which produces MORE oxygen?",a:"🌳",al:"Rainforests",b:"🌊",bl:"Oceans (phytoplankton)",w:"b",ans:"Oceans win!",e:"Phytoplankton produce 50–80% of Earth's oxygen. Rainforests produce ~20%. The ocean is our true lung!"},
  {q:"Which vaccine SAVED more lives?",a:"💉",al:"Smallpox vaccine",b:"💉",bl:"Measles vaccine",w:"a",ans:"Smallpox vaccine!",e:"Smallpox killed ~300 million in the 20th century alone. The vaccine completely eradicated it — saving countless millions every year since 1980."},
  // === BATCH 2: Biology & Nature ===
  {q:"Which is BIGGER?",a:"🦠",al:"A virus",b:"🧬",bl:"A ribosome",w:"b",ans:"Ribosome!",e:"Most viruses are 20–300 nm. Ribosomes are ~25 nm but are far more complex molecular machines with millions of atoms."},
  {q:"Which can REGENERATE better?",a:"🦎",al:"Axolotl",b:"⭐",bl:"Starfish",w:"a",ans:"Axolotl!",e:"Starfish regrow arms, but axolotls regenerate limbs, organs, spinal cord, and even parts of their brain — all without scarring!"},
  {q:"Which has a BIGGER genome?",a:"🧬",al:"Human",b:"🌿",bl:"Paris japonica (plant)",w:"b",ans:"The plant!",e:"Human genome: 3.2 billion base pairs. Paris japonica: 150 billion base pairs — 50x larger! Genome size doesn't equal complexity."},
  {q:"Which is MORE efficient?",a:"💡",al:"LED lightbulb",b:"🌱",bl:"Photosynthesis",w:"a",ans:"LED!",e:"LEDs convert ~50% of energy to light. Photosynthesis converts ~1–2% of sunlight to chemical energy. But plants build themselves — so context matters!"},
  {q:"Which uses MORE brain power?",a:"🧮",al:"Doing math",b:"😊",bl:"Recognizing a face",w:"b",ans:"Face recognition!",e:"Your brain dedicates an enormous neural network to face processing. Recognizing a face in milliseconds uses more neurons than complex arithmetic!"},
  {q:"Which has MORE species?",a:"🐛",al:"Insects",b:"🌿",bl:"Plants",w:"a",ans:"Insects!",e:"~1 million known insect species vs ~400,000 plant species. Beetles alone (~400,000 species) nearly match all plants!"},
  {q:"Which can survive MORE radiation?",a:"🦠",al:"Deinococcus radiodurans",b:"🐻",bl:"Tardigrade",w:"a",ans:"Deinococcus!",e:"Tardigrades survive ~1,000 Gy. Deinococcus radiodurans survives ~15,000 Gy — it can reassemble its shattered DNA from hundreds of fragments!"},
  {q:"Which is COLDER?",a:"🌌",al:"Outer space",b:"🧪",bl:"Bose-Einstein condensate in a lab",w:"b",ans:"The lab!",e:"Space is ~2.7 K (−270.45°C). Labs have cooled atoms to within billionths of a degree above absolute zero — far colder than space!"},
  {q:"Which has BETTER night vision?",a:"🦉",al:"Owl",b:"🐱",bl:"Cat",w:"a",ans:"Owl!",e:"Owls see in light levels 10–100x dimmer than cats. Their tubular eyes have massive corneas and packed rod cells — nature's best night cameras."},
  {q:"Which is OLDER?",a:"🪨",al:"Oldest rock on Earth",b:"🌙",bl:"The Moon",w:"b",ans:"The Moon!",e:"Oldest Earth rock: ~4.4 billion years. Moon: ~4.5 billion years. The Moon formed from debris when a Mars-sized body hit Earth!"},
  {q:"Which is MORE acidic?",a:"🔋",al:"Battery acid",b:"🧃",bl:"Stomach acid",w:"a",ans:"Battery acid!",e:"Battery acid: pH ~0.8. Stomach acid: pH ~1.5–3.5. But your stomach lining replaces itself every 3–4 days to survive its own acid!"},
  {q:"Which travels FARTHER daily?",a:"🩸",al:"A red blood cell",b:"🐦",bl:"Arctic tern (daily avg)",w:"a",ans:"Red blood cell!",e:"RBCs travel ~12,000 miles/day through your circulatory system. Arctic terns average ~150 miles/day during migration. Your blood is a highway!"},
  {q:"Which has MORE bones?",a:"🐍",al:"Python",b:"👶",bl:"Human baby",w:"a",ans:"Python!",e:"Pythons have up to 600 vertebrae + ribs (~1,800 bones). Human babies have ~270 bones (which fuse to 206 in adults)."},
  {q:"Which is DEEPER?",a:"🌊",al:"Mariana Trench",b:"🕳️",bl:"Deepest mine on Earth",w:"a",ans:"Mariana Trench!",e:"Mariana Trench: ~11,034 m deep. Mponeng Gold Mine (deepest mine): ~4,000 m. The ocean goes nearly 3x deeper than any human dig!"},
  {q:"Which carries MORE genetic info?",a:"🧬",al:"Human DNA",b:"💾",bl:"1 terabyte hard drive",w:"a",ans:"DNA!",e:"DNA stores ~215 petabytes per gram. Your genome is ~750 MB, but all the epigenetic info makes your cellular data far exceed any hard drive."},
  // === BATCH 3: Physics & Chemistry ===
  {q:"Which is FASTER?",a:"💡",al:"Light",b:"⚡",bl:"Electricity in a wire",w:"a",ans:"Light!",e:"Light: 299,792 km/s. Electricity: ~270,000 km/s in copper wire (90% of light speed). Electrons themselves move only ~0.1 mm/s though!"},
  {q:"Which is DENSER?",a:"🌟",al:"Neutron star",b:"⚫",bl:"Black hole",w:"b",ans:"Black hole!",e:"Neutron star: ~4 × 10¹⁷ kg/m³. A black hole's singularity has theoretically infinite density. A teaspoon of neutron star weighs ~6 billion tons!"},
  {q:"Which has MORE atoms?",a:"💧",al:"Glass of water",b:"🌊",bl:"Grains of sand on Earth",w:"a",ans:"Glass of water!",e:"A glass of water has ~10²⁵ atoms. Total sand grains on Earth: ~7.5 × 10¹⁸. Water has over a million times more atoms!"},
  {q:"Which is MORE conductive?",a:"🥇",al:"Gold",b:"🥈",bl:"Silver",w:"b",ans:"Silver!",e:"Silver is the best electrical conductor of any element. Gold is used in electronics for its corrosion resistance, not conductivity."},
  {q:"Which is HARDER?",a:"💎",al:"Diamond",b:"🔬",bl:"Wurtzite boron nitride",w:"b",ans:"Wurtzite BN!",e:"Simulations show wurtzite boron nitride is 18% harder than diamond. But it's so rare it's never been tested in bulk — diamond remains king in practice."},
  {q:"Which has MORE energy?",a:"☀️",al:"1 second of the Sun",b:"💣",bl:"All nuclear bombs ever detonated",w:"a",ans:"The Sun!",e:"The Sun outputs 3.8 × 10²⁶ joules per second. All nuclear tests combined: ~2.4 × 10¹⁸ joules. The Sun does this every 0.000000006 seconds!"},
  {q:"Which is LOUDER?",a:"🚀",al:"Rocket launch",b:"🦐",bl:"Pistol shrimp snap",w:"a",ans:"Rocket!",e:"Saturn V: ~204 dB. Pistol shrimp: ~218 dB underwater (but dB scales differ in air vs water). The shrimp creates a cavitation bubble hotter than the Sun!"},
  {q:"Which falls FASTER?",a:"🪶",al:"Feather in a vacuum",b:"🪨",bl:"Rock in a vacuum",w:"tie",ans:"They're equal!",e:"Galileo was right — in a vacuum, ALL objects fall at the same rate regardless of mass. NASA proved this on the Moon with a hammer and feather!"},
  {q:"Which has MORE isotopes?",a:"🔬",al:"Tin",b:"🔬",bl:"Xenon",w:"a",ans:"Tin!",e:"Tin has 10 stable isotopes — more than any other element. Xenon has 9. Most elements have only 1–3 stable isotopes."},
  {q:"Which boils at a LOWER temp?",a:"🧊",al:"Nitrogen",b:"🫧",bl:"Oxygen",w:"a",ans:"Nitrogen!",e:"Nitrogen boils at −196°C. Oxygen boils at −183°C. That's why liquid nitrogen is used as a cheap cryogenic fluid!"},
  // === BATCH 4: Space & Earth ===
  {q:"Which is BIGGER?",a:"🌍",al:"Earth",b:"⭐",bl:"The Sun's volume",w:"b",ans:"The Sun!",e:"1.3 million Earths could fit inside the Sun. The Sun contains 99.86% of all mass in the solar system!"},
  {q:"Which is CLOSER to us?",a:"🌙",al:"The Moon",b:"☀️",bl:"The Sun",w:"a",ans:"The Moon!",e:"Moon: ~384,400 km. Sun: ~150 million km. The Sun is ~390x farther away. Light from the Sun takes 8 minutes to reach us; from the Moon, 1.3 seconds."},
  {q:"Which has MORE moons?",a:"🪐",al:"Saturn",b:"🪐",bl:"Jupiter",w:"a",ans:"Saturn!",e:"Saturn: 146+ confirmed moons. Jupiter: 95+ confirmed moons. Saturn took the lead after dozens of tiny moons were discovered in 2023."},
  {q:"Which is WINDIER?",a:"🌪️",al:"Strongest Earth tornado",b:"🪐",bl:"Neptune's winds",w:"b",ans:"Neptune!",e:"Strongest tornado: ~500 km/h. Neptune's winds: up to 2,100 km/h — the fastest in the solar system! And we don't fully understand why."},
  {q:"Which is TALLER?",a:"🏔️",al:"Mt. Everest",b:"🌋",bl:"Mauna Kea (base to summit)",w:"b",ans:"Mauna Kea!",e:"Everest: 8,849 m above sea level. Mauna Kea: 10,211 m from ocean floor to summit. Most of Mauna Kea is underwater!"},
  {q:"Which has MORE water?",a:"🌊",al:"All Earth's oceans",b:"🪐",bl:"Europa (Jupiter's moon)",w:"b",ans:"Europa!",e:"Europa likely has 2–3x more liquid water than all Earth's oceans, hidden beneath an ice shell. It's a prime candidate for extraterrestrial life!"},
  {q:"Which is OLDER?",a:"🌌",al:"The universe",b:"🌍",bl:"The Earth",w:"a",ans:"The universe!",e:"Universe: ~13.8 billion years. Earth: ~4.54 billion years. The universe is about 3x older than our planet."},
  {q:"Which rotates FASTER?",a:"🌍",al:"Earth",b:"🪐",bl:"Jupiter",w:"b",ans:"Jupiter!",e:"Earth day: 24 hours. Jupiter day: ~9.9 hours. Jupiter spins so fast its equator bulges outward, despite being 11x Earth's diameter!"},
  {q:"Which is HOTTER at its core?",a:"🌍",al:"Earth's core",b:"☀️",bl:"Sun's surface",w:"a",ans:"Earth's core!",e:"Earth's core: ~6,000°C. Sun's surface: ~5,500°C. Our core is hotter than the Sun's surface (but the Sun's core is 15 million °C)!"},
  {q:"Which desert is LARGER?",a:"🏜️",al:"Sahara",b:"🧊",bl:"Antarctica",w:"b",ans:"Antarctica!",e:"Antarctica: 14.2 million km². Sahara: 9.2 million km². Antarctica is technically a desert (very low precipitation) — and it's 55% bigger!"},
  // === BATCH 5: Human Body ===
  {q:"Which is LONGER?",a:"🧠",al:"All your nerves stretched out",b:"🩸",bl:"All your blood vessels",w:"b",ans:"Blood vessels!",e:"Nerves: ~45 miles total. Blood vessels: ~60,000 miles — enough to wrap around Earth 2.5 times!"},
  {q:"Which REPLACES itself faster?",a:"🫁",al:"Lung cells",b:"🔴",bl:"Red blood cells",w:"b",ans:"Red blood cells!",e:"Your body makes ~2 million new red blood cells per second. Lung alveolar cells take ~8 days to replace."},
  {q:"Which has MORE nerve endings?",a:"👆",al:"Fingertips",b:"👅",bl:"Tongue",w:"a",ans:"Fingertips!",e:"Fingertips: ~2,500 receptors per cm². Tongue: ~200 per cm². Your fingertips are among the most sensitive parts of your body."},
  {q:"Which is STRONGER?",a:"💪",al:"Jaw muscles (masseter)",b:"🦵",bl:"Thigh muscles (quads)",w:"b",ans:"Quads!",e:"Quads can generate ~300+ lbs of force. Masseter generates ~170 lbs of bite force. But per unit size, the masseter is the strongest muscle."},
  {q:"Which HEALS faster?",a:"👅",al:"Tongue wound",b:"🖐️",bl:"Skin wound",w:"a",ans:"Tongue!",e:"Oral wounds heal ~2x faster than skin. Saliva contains growth factors, the mouth has rich blood supply, and oral tissue has special healing cells."},
  {q:"Which uses MORE muscles?",a:"😀",al:"Smiling",b:"😠",bl:"Frowning",w:"b",ans:"Frowning!",e:"Smiling uses ~12 muscles. Frowning uses ~43 muscles. It literally takes more effort to be unhappy — smile more!"},
  {q:"Which is LARGER?",a:"👁️",al:"Your eyeball now vs. at birth",b:"👂",bl:"Your ear now vs. at birth",w:"b",ans:"Ears grow more!",e:"Eyes grow from 16mm to 24mm (50%). Ears never stop growing — they increase by ~50% by age 30 and keep going due to cartilage."},
  {q:"Which can you detect MORE of?",a:"👃",al:"Smells your nose detects",b:"👅",bl:"Tastes your tongue detects",w:"a",ans:"Nose wins!",e:"Your nose detects ~1 trillion distinct scents. Your tongue detects only 5 basic tastes (sweet, sour, salty, bitter, umami)."},
  {q:"Which PRODUCES more heat?",a:"🧠",al:"Your brain",b:"🫀",bl:"Your heart",w:"a",ans:"Brain!",e:"Your brain uses 20% of body energy and generates significant heat. The heart generates less heat per gram because it's mechanically more efficient."},
  {q:"Which is FASTER?",a:"💭",al:"A thought",b:"🏎️",bl:"Formula 1 car",w:"a",ans:"A thought!",e:"Neural signals travel at 120 m/s (268 mph). F1 top speed: ~231 mph. Your thoughts are literally faster than the fastest race car!"},
  // === BATCH 6: Evolution & History ===
  {q:"Which evolved FIRST?",a:"👁️",al:"Eyes",b:"🧠",bl:"Brains",w:"a",ans:"Eyes!",e:"Simple light-sensing eyespots evolved ~540 million years ago. Complex brains evolved later. The eye evolved independently 50+ times!"},
  {q:"Which has been around LONGER?",a:"🌿",al:"Ferns",b:"🦕",bl:"Dinosaurs",w:"a",ans:"Ferns!",e:"Ferns: ~360 million years. Dinosaurs: ~230 million years. Ferns were ancient forests long before dinosaurs walked the Earth."},
  {q:"Which went extinct MORE recently?",a:"🦣",al:"Woolly mammoth",b:"🏛️",bl:"Ancient Egypt",w:"b",ans:"Trick question!",e:"Woolly mammoths still existed on Wrangel Island until ~1700 BC — while the Egyptian pyramids were already ~1,000 years old! They overlapped."},
  {q:"Which is MORE genetically similar to humans?",a:"🐒",al:"Chimpanzee",b:"🍌",bl:"Banana",w:"a",ans:"Chimpanzee!",e:"Chimps share ~98.7% of our DNA. Bananas share ~60%. You're quite literally part banana — thanks to shared ancient genes."},
  {q:"Which has been domesticated LONGER?",a:"🐕",al:"Dogs",b:"🐈",bl:"Cats",w:"a",ans:"Dogs!",e:"Dogs: ~15,000–40,000 years ago. Cats: ~10,000 years ago. Dogs were our first animal companions, domesticated from wolves during the Ice Age."},
  {q:"Which can learn MORE words?",a:"🐕",al:"Border collie",b:"🦜",bl:"African grey parrot",w:"a",ans:"Border collie!",e:"Chaser the border collie learned 1,022 words. Alex the grey parrot knew ~150 words but could use them in context — true comprehension!"},
  {q:"Which MIGRATES farther?",a:"🐦",al:"Arctic tern",b:"🐋",bl:"Gray whale",w:"a",ans:"Arctic tern!",e:"Arctic tern: 44,000 miles/year (pole to pole). Gray whale: ~12,000 miles/year. The tern sees more daylight than any other creature!"},
  {q:"Which CHANGES color faster?",a:"🐙",al:"Octopus",b:"🦎",bl:"Chameleon",w:"a",ans:"Octopus!",e:"Octopuses change color in ~200 milliseconds using neural control of chromatophores. Chameleons take 20+ seconds using crystal lattice changes."},
  {q:"Which is SMARTER per body size?",a:"🐦",al:"Crow",b:"🐬",bl:"Dolphin",w:"a",ans:"Crow!",e:"Crows have the highest brain-to-body ratio of any bird. They make and use tools, solve multi-step puzzles, and even understand water displacement!"},
  {q:"Which SLEEPS less?",a:"🦒",al:"Giraffe",b:"🐘",bl:"Elephant",w:"a",ans:"Giraffe!",e:"Giraffes sleep only ~30 minutes/day in short 5-minute naps. Elephants sleep ~2 hours/day. Giraffes are the least-sleeping mammals!"},
  // === BATCH 7: Technology & Medicine ===
  {q:"Which was invented FIRST?",a:"🔬",al:"Microscope",b:"🔭",bl:"Telescope",w:"a",ans:"It's close!",e:"Both emerged around 1600 in the Netherlands. The compound microscope (1590s) slightly predates Galileo's telescope improvements (1609)."},
  {q:"Which costs MORE?",a:"💊",al:"Zolgensma (gene therapy)",b:"🚀",bl:"SpaceX Falcon 9 launch",w:"a",ans:"Zolgensma!",e:"Zolgensma: $2.1 million per dose. Falcon 9: ~$67 million per launch. The gene therapy is expensive but cures a fatal disease with one injection."},
  {q:"Which has MORE transistors?",a:"📱",al:"iPhone 15 chip",b:"🧠",bl:"Synapses in your brain",w:"b",ans:"Brain!",e:"iPhone A17: ~19 billion transistors. Brain: ~100 trillion synapses. Your brain has ~5,000x more connections than the most advanced chip."},
  {q:"Which processes data FASTER?",a:"💻",al:"Supercomputer",b:"🧠",bl:"Human brain",w:"a",ans:"Supercomputer!",e:"Frontier: 1.1 exaflops. Brain: ~1 exaflop equivalent. But the brain uses only 20 watts vs Frontier's 21 megawatts — brain is a million times more efficient!"},
  {q:"Which stores MORE data?",a:"🧬",al:"1 gram of DNA",b:"💿",bl:"1,000 Blu-ray discs",w:"a",ans:"DNA!",e:"1g of DNA stores ~215 petabytes. 1,000 Blu-rays: ~50 terabytes. DNA stores over 4,000x more — nature invented the ultimate storage medium."},
  {q:"Which is SMALLER?",a:"⚛️",al:"Atom",b:"🦠",bl:"Virus",w:"a",ans:"Atom!",e:"Atoms: ~0.1–0.3 nanometers. Smallest viruses: ~20 nanometers. A virus is made of thousands to millions of atoms!"},
  {q:"Which is MORE precise?",a:"✂️",al:"CRISPR-Cas9",b:"✏️",bl:"Base editing",w:"b",ans:"Base editing!",e:"CRISPR cuts DNA (can cause errors). Base editing chemically converts one letter without cutting — like using a pencil eraser instead of scissors."},
  {q:"Which was decoded FIRST?",a:"🧬",al:"Human genome",b:"🦠",bl:"COVID-19 genome",w:"a",ans:"Human genome!",e:"Human Genome Project completed in 2003 (13 years). COVID-19 was sequenced in January 2020 — in just days, thanks to technology the HGP built!"},
  {q:"Which is THINNER?",a:"🕸️",al:"Spider silk thread",b:"📱",bl:"Phone screen glass",w:"a",ans:"Spider silk!",e:"Spider silk: ~3 micrometers. Phone glass: ~500 micrometers. Spider silk is 150x thinner, yet proportionally stronger than steel!"},
  {q:"Which was discovered MORE recently?",a:"🔬",al:"DNA structure",b:"🦠",bl:"CRISPR",w:"b",ans:"CRISPR!",e:"Watson & Crick described DNA's double helix in 1953. Doudna & Charpentier showed CRISPR as a gene-editing tool in 2012 — 59 years later."},
  // === BATCH 8: Ocean & Extreme Life ===
  {q:"Which goes DEEPER?",a:"🐋",al:"Sperm whale dive",b:"🤿",bl:"Deepest human scuba dive",w:"a",ans:"Sperm whale!",e:"Sperm whales: 2,250 meters. Ahmed Gabr's record scuba: 332 meters. Whales dive 7x deeper, holding breath for 90+ minutes!"},
  {q:"Which is MORE bioluminescent?",a:"🪼",al:"Jellyfish",b:"🦑",bl:"Deep-sea squid",w:"b",ans:"Squid!",e:"~76% of deep-sea creatures are bioluminescent. Squid use the most sophisticated light organs — they can match ambient light to become invisible!"},
  {q:"Which is MORE extreme?",a:"🌋",al:"Hydrothermal vent",b:"🧊",bl:"Antarctic ice",w:"a",ans:"Vent!",e:"Hydrothermal vents reach 400°C+ yet life thrives there. Antarctic record: -89.2°C. The vent temperature extreme is more remarkable because LIFE survives it."},
  {q:"Which has MORE tentacles?",a:"🐙",al:"Octopus",b:"🪼",bl:"Lion's mane jellyfish",w:"b",ans:"Jellyfish!",e:"Octopus: 8 arms. Lion's mane jellyfish: up to 1,200 tentacles, some stretching 120 feet — longer than a blue whale!"},
  {q:"Which HOLDS breath longer?",a:"🐊",al:"Crocodile",b:"🐢",bl:"Sea turtle",w:"a",ans:"Crocodile!",e:"Crocodiles can hold breath for ~2 hours. Sea turtles: ~7 hours when resting. But crocs manage it while actively hunting — impressive cardiovascular control!"},
  // === BATCH 9: Food & Plants ===
  {q:"Which has MORE vitamin C?",a:"🍊",al:"Orange",b:"🫑",bl:"Bell pepper",w:"b",ans:"Bell pepper!",e:"One bell pepper: ~170mg vitamin C. One orange: ~70mg. Bell peppers have over 2x more vitamin C than oranges!"},
  {q:"Which GROWS faster?",a:"🎋",al:"Bamboo",b:"🌻",bl:"Sunflower",w:"a",ans:"Bamboo!",e:"Bamboo can grow 91 cm (3 feet) per day — the fastest-growing plant on Earth. Sunflowers grow ~2.5 cm/day at peak."},
  {q:"Which tree lives LONGER?",a:"🌳",al:"Bristlecone pine",b:"🌿",bl:"Giant sequoia",w:"a",ans:"Bristlecone pine!",e:"Bristlecone pine 'Methuselah': 4,856 years old. Oldest giant sequoia: ~3,200 years. Bristlecone pines were ancient when the pyramids were built!"},
  {q:"Which fruit has MORE seeds?",a:"🍓",al:"Strawberry",b:"🥝",bl:"Kiwi",w:"b",ans:"Kiwi!",e:"Strawberry: ~200 seeds (on the outside!). Kiwi: ~1,500 tiny seeds. But strawberries are unique — they're the only fruit with seeds on the outside."},
  {q:"Which is MORE caffeinated?",a:"☕",al:"Cup of coffee",b:"🍵",bl:"Cup of green tea",w:"a",ans:"Coffee!",e:"Coffee: ~95mg caffeine per cup. Green tea: ~30mg per cup. But tea leaves actually contain more caffeine by weight — they're just brewed weaker."},
  {q:"Which PRODUCES more food per acre?",a:"🌾",al:"Rice",b:"🥔",bl:"Potatoes",w:"b",ans:"Potatoes!",e:"Potatoes yield ~40,000 lbs/acre. Rice: ~8,000 lbs/acre. Potatoes produce 5x more food per acre — they fueled the European population boom."},
  // === BATCH 10: Weird Science ===
  {q:"Which is WEIRDER?",a:"🔬",al:"Quantum entanglement",b:"⏱️",bl:"Time dilation",w:"b",ans:"Time dilation!",e:"GPS satellites run clocks 38 microseconds/day faster than ground clocks due to both special and general relativity. Without correction, GPS would drift 10 km/day!"},
  {q:"Which is MORE empty space?",a:"⚛️",al:"An atom",b:"☀️",bl:"The solar system",w:"a",ans:"An atom!",e:"An atom is 99.9999999999996% empty space. If the nucleus were a marble, electrons would be 2 miles away. You're mostly nothing!"},
  {q:"Which is MORE likely?",a:"🎲",al:"Winning the lottery",b:"☄️",bl:"Being hit by a meteorite",w:"a",ans:"Lottery!",e:"Lottery odds: ~1 in 300 million. Meteorite strike: ~1 in 1.6 billion. You're 5x more likely to win the lottery — but neither is happening!"},
  {q:"Which has a LONGER lifespan?",a:"💡",al:"Incandescent bulb",b:"🔋",bl:"Alkaline battery",w:"b",ans:"Battery!",e:"Incandescent bulb: ~1,000 hours. Alkaline battery shelf life: ~5–10 years (~44,000–88,000 hours). The battery outlasts the bulb by orders of magnitude."},
  {q:"Which is MORE symmetrical?",a:"❄️",al:"Snowflake",b:"🧬",bl:"DNA helix",w:"b",ans:"DNA!",e:"Snowflakes have 6-fold symmetry but each is unique. DNA's double helix has a precise, repeating structure with exactly 10 base pairs per turn, every time."},
  {q:"Which would win in a RACE?",a:"🐆",al:"Cheetah (land)",b:"🦅",bl:"Peregrine falcon (diving)",w:"b",ans:"Falcon!",e:"Cheetah: 112 km/h. Peregrine falcon dive: 389 km/h — the fastest animal on Earth. That's faster than a bullet train!"},
  {q:"Which SMELLS worse?",a:"🌺",al:"Corpse flower",b:"🦨",bl:"Skunk spray",w:"a",ans:"Corpse flower!",e:"The corpse flower (Amorphophallus titanum) smells like rotting flesh to attract pollinators. Skunk spray is awful but the corpse flower makes grown adults gag!"},
  {q:"Which is MORE elastic?",a:"🏀",al:"Rubber ball",b:"🕸️",bl:"Spider silk",w:"b",ans:"Spider silk!",e:"Spider silk can stretch 40% of its length without breaking. Rubber stretches more but breaks at lower relative force. Silk is elastic AND incredibly tough."},
  {q:"Which has MORE DNA in common with you?",a:"🐁",al:"Mouse",b:"🪰",bl:"Fruit fly",w:"a",ans:"Mouse!",e:"Mice share ~85% of protein-coding genes with humans. Fruit flies share ~60%. Mice are so similar that they're the top model for human disease research."},
  {q:"Which CAN'T jump?",a:"🐘",al:"Elephant",b:"🦛",bl:"Hippo",w:"a",ans:"Both can't!",e:"Elephants are the only mammals that truly cannot jump — their legs can't leave the ground simultaneously. Hippos also can't jump on land, but they 'bounce' underwater!"},
  // === BATCH 11: Gene Therapy & Biotech ===
  {q:"Which is MORE precise?",a:"✂️",al:"CRISPR-Cas9",b:"🧬",bl:"Prime editing",w:"b",ans:"Prime editing!",e:"CRISPR makes double-strand breaks (can cause errors). Prime editing writes exact changes without cutting both strands — like find-and-replace for DNA."},
  {q:"Which treats MORE diseases?",a:"💊",al:"Traditional drugs",b:"🧬",bl:"Gene therapy",w:"a",ans:"Traditional (for now)!",e:"Traditional drugs treat thousands of conditions. Gene therapy has ~20 approved treatments — but it's growing fast and can CURE diseases drugs only manage."},
  {q:"Which is MORE expensive per dose?",a:"💊",al:"Zolgensma",b:"💊",bl:"Hemgenix",w:"b",ans:"Hemgenix!",e:"Hemgenix (hemophilia B gene therapy): $3.5 million per dose — the most expensive drug ever. But it replaces a lifetime of $600K+/year in treatments."},
  {q:"Which was discovered FIRST?",a:"🧬",al:"Restriction enzymes",b:"✂️",bl:"CRISPR",w:"a",ans:"Restriction enzymes!",e:"Restriction enzymes were the first 'molecular scissors' in the 1970s. CRISPR came 40 years later but is programmable — you can target any DNA sequence."},
  {q:"Which can edit MORE genes at once?",a:"✂️",al:"CRISPR multiplex editing",b:"🧬",bl:"Traditional gene therapy (AAV)",w:"a",ans:"CRISPR!",e:"George Church's lab edited 62 genes simultaneously with CRISPR. AAV gene therapy typically delivers one gene at a time. CRISPR enables wholesale genome rewriting."},
  {q:"Which DELIVERS genes better?",a:"🦠",al:"Adeno-associated virus (AAV)",b:"🫧",bl:"Lipid nanoparticles (LNPs)",w:"a",ans:"It depends!",e:"AAV: better for long-term gene delivery to specific tissues. LNPs: better for temporary mRNA delivery (like vaccines). Different tools for different jobs!"},
  {q:"Which Nobel Prize was awarded FIRST?",a:"🧬",al:"DNA structure",b:"✂️",bl:"CRISPR",w:"a",ans:"DNA structure!",e:"Watson, Crick & Wilkins: Nobel 1962 for DNA structure. Doudna & Charpentier: Nobel 2020 for CRISPR. 58 years of progress between them!"},
{q:"Which has MORE mitochondria per cell?",a:"🫀",al:"Heart muscle cell",b:"🦠",bl:"Skin cell",w:"a",ans:"Heart cell!",e:"Heart muscle cells pack ~5,000 mitochondria each to fuel constant beating. Skin cells have only ~200. Your heart is the body's biggest energy consumer per cell!"},
{q:"Which cell is BIGGER?",a:"🥚",al:"Human egg cell",b:"🔴",bl:"Red blood cell",w:"a",ans:"Egg cell!",e:"A human egg is ~120 micrometers — visible to the naked eye. Red blood cells are only ~7 micrometers. The egg is the largest cell in the human body!"},
{q:"Which organism has MORE chromosomes?",a:"🧬",al:"Human",b:"🦋",bl:"Butterfly",w:"b",ans:"Butterfly!",e:"Humans have 46 chromosomes. The Atlas blue butterfly has ~450 chromosomes. More chromosomes doesn't mean more complex — it's about gene content!"},
{q:"Which divides FASTER?",a:"🦠",al:"E. coli bacterium",b:"🧫",bl:"Human cancer cell",w:"a",ans:"E. coli!",e:"E. coli divides every 20 minutes under ideal conditions. Even aggressive cancer cells take 24+ hours. Bacteria are the speed demons of cell division!"},
{q:"Which has a LONGER telomere?",a:"👶",al:"Newborn's cells",b:"🧓",bl:"80-year-old's cells",w:"a",ans:"Newborn!",e:"Newborns have telomeres ~8,000–13,000 base pairs long. By age 80, they shrink to ~4,000. Telomere shortening is a molecular clock of aging!"},
{q:"Which has MORE protein types?",a:"🧠",al:"Brain cell",b:"🦴",bl:"Bone cell",w:"a",ans:"Brain cell!",e:"Neurons express over 15,000 different protein types to manage synapses and signaling. Bone cells express roughly 8,000. The brain is a protein factory!"},
{q:"Which is OLDER as a life form?",a:"🦠",al:"Cyanobacteria",b:"🍄",bl:"Fungi",w:"a",ans:"Cyanobacteria!",e:"Cyanobacteria appeared ~3.5 billion years ago and invented photosynthesis. Fungi evolved ~1 billion years ago. Cyanobacteria literally created our oxygen atmosphere!"},
{q:"Which has MORE genes?",a:"🌾",al:"Rice",b:"🧬",bl:"Human",w:"a",ans:"Rice!",e:"Rice has ~37,000 genes while humans have ~20,000. A grain of rice is genetically more complex by gene count — but humans have more complex gene regulation!"},
{q:"Which reproduces FASTER?",a:"🐇",al:"Rabbit",b:"🐀",bl:"Rat",w:"b",ans:"Rat!",e:"Rats can reproduce at 5 weeks old with litters of 12 every 3 weeks. Rabbits start at 12 weeks with litters of 5–6. A single rat pair can produce 15,000 descendants per year!"},
{q:"Which virus is SMALLER?",a:"🦠",al:"Influenza virus",b:"🦠",bl:"Parvovirus",w:"b",ans:"Parvovirus!",e:"Influenza is ~80–120 nm across. Parvovirus is only ~18–26 nm — one of the smallest viruses known. It's so tiny it can slip through some filters!"},
{q:"Which produces MORE ATP daily?",a:"🧬",al:"Your body",b:"⚡",bl:"A car battery",w:"a",ans:"Your body!",e:"Your body produces and recycles ~40 kg of ATP daily — roughly your own body weight. A car battery stores far less energy. You are a biochemical powerhouse!"},
{q:"Which has a HIGHER metabolic rate?",a:"🐦",al:"Shrew",b:"🐝",bl:"Honeybee",w:"a",ans:"Shrew!",e:"Shrews have the highest metabolic rate of any mammal — they must eat every 2–3 hours or die. Their hearts beat 1,200 times per minute!"},
{q:"Which organism is MORE radiation-resistant?",a:"🦂",al:"Scorpion",b:"🪳",bl:"Cockroach",w:"a",ans:"Scorpion!",e:"Scorpions survive ~900 Gy of radiation. Cockroaches handle ~100 Gy. Scorpions are 9x tougher — they even glow under UV light due to fluorescent compounds!"},
{q:"Which has MORE bacteria species?",a:"🫁",al:"Your lungs",b:"🦷",bl:"Your mouth",w:"b",ans:"Your mouth!",e:"Your mouth hosts 700+ species of bacteria. Your lungs have a much smaller but important microbiome of ~100 species. Your mouth is a microbial metropolis!"},
{q:"Which is MORE genetically diverse?",a:"🐕",al:"Dog breeds",b:"🧬",bl:"All humans on Earth",w:"a",ans:"Dogs!",e:"Dogs have more genetic variation between breeds than exists between any two humans on Earth. A Chihuahua and Great Dane differ more genetically than any two people!"},
{q:"Which has a LONGER gestation period?",a:"🐘",al:"African elephant",b:"🦏",bl:"White rhinoceros",w:"a",ans:"Elephant!",e:"African elephants are pregnant for 22 months — the longest of any land animal. White rhinos carry for 16 months. Elephant babies are born already weighing 250 lbs!"},
{q:"Which plant is MORE deadly?",a:"🌿",al:"Castor bean plant",b:"☠️",bl:"Deadly nightshade",w:"a",ans:"Castor bean!",e:"Castor beans produce ricin, lethal at ~1 mg. Deadly nightshade's atropine requires ~10–20 berries to kill. Ricin is one of the most toxic natural substances known!"},
{q:"Which tree produces MORE oxygen?",a:"🌳",al:"Oak tree",b:"🌲",bl:"Spruce tree",w:"a",ans:"Oak!",e:"A mature oak produces ~118 kg of oxygen per year. A spruce produces ~36 kg. Broad-leaved trees generally outperform conifers due to their larger leaf surface area!"},
{q:"Which has MORE neurons?",a:"🐙",al:"Octopus",b:"🐕",bl:"Dog",w:"a",ans:"Octopus!",e:"Octopuses have ~500 million neurons, with 2/3 in their arms. Dogs have ~530 million cortical neurons. They're surprisingly close, but octopus arms can think independently!"},
{q:"Which can survive LONGER without water?",a:"🐫",al:"Camel",b:"🐀",bl:"Kangaroo rat",w:"b",ans:"Kangaroo rat!",e:"Camels survive ~2 weeks without water. Kangaroo rats can go their entire 3–5 year lifespan without drinking — they extract all water from dry seeds!"},
{q:"Which has THICKER cell walls?",a:"🌲",al:"Wood cell",b:"🍄",bl:"Fungal cell",w:"a",ans:"Wood cell!",e:"Wood cells have thick cellulose walls ~2–5 micrometers making trees rigid. Fungal cell walls are ~0.2 micrometers of chitin. Wood's thick walls are why trees stand tall!"},
{q:"Which organism clones itself MORE?",a:"🪸",al:"Coral",b:"🌿",bl:"Dandelion",w:"b",ans:"Dandelion!",e:"Many dandelion species reproduce via apomixis — creating seeds that are genetic clones without fertilization. Coral buds asexually but also reproduces sexually each year!"},
{q:"Which planet is MORE tilted?",a:"🪐",al:"Uranus",b:"🪐",bl:"Venus",w:"a",ans:"Uranus!",e:"Uranus tilts at 98 degrees — it essentially rolls around the Sun on its side. Venus tilts 177 degrees (nearly upside down) but that's close to vertical. Uranus wins for extreme tilt!"},
{q:"Which is LARGER in diameter?",a:"🪐",al:"Jupiter's Great Red Spot",b:"🌍",bl:"Earth",w:"a",ans:"Great Red Spot!",e:"Jupiter's Great Red Spot is ~16,000 km wide — bigger than Earth's 12,742 km diameter. This storm has been raging for at least 350 years!"},
{q:"Which moon has a THICKER atmosphere?",a:"🌙",al:"Titan (Saturn)",b:"🌙",bl:"Triton (Neptune)",w:"a",ans:"Titan!",e:"Titan's atmosphere is 1.5x denser than Earth's and mostly nitrogen. Triton has only a thin wisp of nitrogen. Titan is the only moon with a substantial atmosphere!"},
{q:"Which star is BIGGER?",a:"⭐",al:"Betelgeuse",b:"⭐",bl:"Rigel",w:"a",ans:"Betelgeuse!",e:"Betelgeuse's radius is ~900x the Sun's — it would engulf Jupiter's orbit. Rigel is ~80x the Sun. Betelgeuse is a red supergiant nearing the end of its life!"},
{q:"Which planet has LONGER days?",a:"🪐",al:"Mercury",b:"🌍",bl:"Venus",w:"b",ans:"Venus!",e:"A Venus day (243 Earth days) is longer than its year (225 Earth days). Mercury's day is 59 Earth days. Venus spins so slowly the Sun rises in the west!"},
{q:"Which spacecraft traveled FARTHER?",a:"🛸",al:"Voyager 1",b:"🛸",bl:"New Horizons",w:"a",ans:"Voyager 1!",e:"Voyager 1 is ~24 billion km from Earth — the farthest human-made object ever. New Horizons is ~8 billion km. Voyager 1 has been traveling since 1977!"},
{q:"Which is DENSER?",a:"🌍",al:"Earth",b:"🪐",bl:"Saturn",w:"a",ans:"Earth!",e:"Earth's density: 5.5 g/cm cubed. Saturn: 0.69 g/cm cubed — less dense than water! Saturn would float in a bathtub big enough to hold it!"},
{q:"Which has a STRONGER magnetic field?",a:"🌍",al:"Earth",b:"🪐",bl:"Jupiter",w:"b",ans:"Jupiter!",e:"Jupiter's magnetic field is 20,000x stronger than Earth's and extends 7 million km toward the Sun. It would be visible from Earth if our eyes could see it!"},
{q:"Which galaxy is CLOSER to us?",a:"🌌",al:"Andromeda",b:"🌌",bl:"Large Magellanic Cloud",w:"b",ans:"Magellanic Cloud!",e:"Large Magellanic Cloud: ~160,000 light-years away. Andromeda: ~2.5 million light-years. But Andromeda is heading toward us at 110 km/s — we'll collide in 4.5 billion years!"},
{q:"Which planet has MORE rings?",a:"🪐",al:"Saturn",b:"🪐",bl:"Uranus",w:"a",ans:"Saturn!",e:"Saturn has 7 main ring groups with thousands of individual ringlets. Uranus has 13 known rings. Saturn's rings span 282,000 km but are only ~10 meters thick!"},
{q:"Which is HOTTER?",a:"🌟",al:"Surface of Sirius",b:"☀️",bl:"Surface of the Sun",w:"a",ans:"Sirius!",e:"Sirius A's surface: ~9,940 K. Our Sun's surface: ~5,778 K. Sirius is the brightest star visible from Earth, and it's nearly twice as hot as our Sun!"},
{q:"Which object spins FASTER?",a:"🌟",al:"Pulsar",b:"🪐",bl:"Jupiter",w:"a",ans:"Pulsar!",e:"The fastest pulsars spin 716 times per second. Jupiter rotates once every 10 hours. Pulsars are collapsed stars spinning with mind-boggling speed!"},
{q:"Which crater is BIGGER?",a:"🌙",al:"Moon's South Pole-Aitken basin",b:"🪐",bl:"Mars's Hellas basin",w:"a",ans:"Moon's basin!",e:"South Pole-Aitken: ~2,500 km across and 8.2 km deep — one of the largest impact craters in the solar system. Hellas: ~2,300 km. Both are ancient scars from cosmic collisions!"},
{q:"Which has LESS gravity?",a:"🌙",al:"The Moon",b:"🪐",bl:"Pluto",w:"b",ans:"Pluto!",e:"Pluto's gravity: 0.063 g. Moon's gravity: 0.166 g. On Pluto you'd weigh only 6% of your Earth weight — you could jump 12 meters high!"},
{q:"Which planet has a LONGER year?",a:"🪐",al:"Neptune",b:"🪐",bl:"Pluto",w:"b",ans:"Pluto!",e:"Neptune's year: 165 Earth years. Pluto's year: 248 Earth years. Since its discovery in 1930, Pluto hasn't yet completed one full orbit!"},
{q:"Which produces MORE neutrinos?",a:"☀️",al:"The Sun",b:"💥",bl:"A supernova",w:"b",ans:"Supernova!",e:"A supernova releases ~10^58 neutrinos in seconds — 99% of its energy. The Sun emits ~2x10^38 neutrinos per second. A single supernova outdoes the Sun's lifetime neutrino output!"},
{q:"Which is COLDER?",a:"🌙",al:"Moon's dark side",b:"🪐",bl:"Pluto's surface",w:"b",ans:"Pluto!",e:"Moon's dark side: ~-173 C. Pluto's surface: ~-230 C. Pluto is so far from the Sun that nitrogen freezes solid on its surface!"},
{q:"Which asteroid is BIGGER?",a:"☄️",al:"Ceres",b:"☄️",bl:"Vesta",w:"a",ans:"Ceres!",e:"Ceres: 940 km diameter — so large it's classified as a dwarf planet. Vesta: 525 km. Ceres contains about a third of the asteroid belt's total mass!"},
{q:"Which telescope sees FARTHER back in time?",a:"🔭",al:"Hubble Space Telescope",b:"🔭",bl:"James Webb Space Telescope",w:"b",ans:"James Webb!",e:"JWST detects galaxies from 13.5 billion years ago — just 300 million years after the Big Bang. Hubble sees back ~13.4 billion years. JWST's infrared vision peers deeper into cosmic dawn!"},
{q:"Which has a THINNER atmosphere?",a:"🪐",al:"Mars",b:"🌙",bl:"Earth's Moon",w:"b",ans:"The Moon!",e:"Mars has a thin atmosphere at ~0.6% of Earth's pressure. The Moon has essentially no atmosphere — just trace gases. Mars at least has enough for dust storms and weather!"},
{q:"Which planet is MORE volcanic?",a:"🌍",al:"Earth",b:"🪐",bl:"Io (Jupiter's moon)",w:"b",ans:"Io!",e:"Io has over 400 active volcanoes — the most volcanically active body in our solar system. Jupiter's tidal forces squeeze Io like a stress ball, generating extreme internal heat!"},
{q:"Which comet has a LONGER orbital period?",a:"☄️",al:"Halley's Comet",b:"☄️",bl:"Comet Hale-Bopp",w:"b",ans:"Hale-Bopp!",e:"Halley's Comet returns every ~76 years. Hale-Bopp's orbital period is ~2,520 years. People who saw Hale-Bopp in 1997 won't see it again until roughly the year 4530!"},
{q:"Which is STRONGER?",a:"🧲",al:"Electromagnetic force",b:"⚛️",bl:"Strong nuclear force",w:"b",ans:"Strong nuclear force!",e:"The strong nuclear force is ~137x stronger than electromagnetism. It holds protons together in atomic nuclei despite their positive charges repelling each other!"},
{q:"Which wave has MORE energy?",a:"🔴",al:"Red light photon",b:"🟣",bl:"Violet light photon",w:"b",ans:"Violet!",e:"Violet photons carry ~1.8x more energy than red photons. Higher frequency means higher energy — that's why UV light causes sunburns but red light doesn't!"},
{q:"Which material CONDUCTS heat better?",a:"💎",al:"Diamond",b:"🥈",bl:"Silver",w:"a",ans:"Diamond!",e:"Diamond conducts heat at ~2,200 W/mK vs silver at ~429 W/mK. Diamond is 5x better at conducting heat than any metal, despite being an electrical insulator!"},
{q:"Which has MORE pressure?",a:"🌊",al:"Bottom of the Mariana Trench",b:"🪐",bl:"Center of Jupiter",w:"b",ans:"Jupiter's center!",e:"Mariana Trench: ~1,086 atmospheres. Jupiter's center: ~tens of millions of atmospheres. Jupiter's core pressure is so extreme it squeezes hydrogen into a metal!"},
{q:"Which is a BETTER insulator?",a:"🧊",al:"Styrofoam",b:"🌫️",bl:"Aerogel",w:"b",ans:"Aerogel!",e:"Aerogel conducts heat at 0.013 W/mK vs Styrofoam at 0.033 W/mK. Aerogel is 99.8% air and was used to insulate the Mars rovers from extreme cold!"},
{q:"Which moves FASTER through glass?",a:"🔴",al:"Red light",b:"🟣",bl:"Violet light",w:"a",ans:"Red light!",e:"Red light moves faster through glass because glass has a higher refractive index for shorter wavelengths. This is why prisms split white light — each color bends differently!"},
{q:"Which force is WEAKER?",a:"🌍",al:"Gravity",b:"⚛️",bl:"Weak nuclear force",w:"a",ans:"Gravity!",e:"Gravity is 10^25 times weaker than the weak nuclear force. It's the weakest fundamental force — yet it shapes galaxies because it acts over infinite distances!"},
{q:"Which has a HIGHER melting point?",a:"🔩",al:"Tungsten",b:"🧪",bl:"Tantalum hafnium carbide",w:"b",ans:"Tantalum hafnium carbide!",e:"Tungsten melts at 3,422 C. Tantalum hafnium carbide melts at ~3,990 C — the highest melting point of any known material. It's used in jet engine coatings!"},
{q:"Which is MORE magnetic?",a:"🧲",al:"Neodymium magnet",b:"🧲",bl:"Electromagnet in an MRI",w:"b",ans:"MRI magnet!",e:"Strong neodymium magnets: ~1.4 Tesla. MRI machines: 1.5–3 Tesla (some research MRIs reach 11.7T). MRI magnets are strong enough to pull a wrench across a room!"},
{q:"Which has LESS friction?",a:"🧊",al:"Ice on ice",b:"🔬",bl:"Teflon on Teflon",w:"b",ans:"Teflon!",e:"Ice-on-ice friction coefficient: ~0.03. Teflon-on-Teflon: ~0.04. They're extremely close, but ice actually beats Teflon in low-friction! The answer surprises most people."},
{q:"Which process releases MORE energy per kg?",a:"⚛️",al:"Nuclear fission",b:"⚛️",bl:"Nuclear fusion",w:"b",ans:"Fusion!",e:"Fusion releases ~4x more energy per kilogram than fission. Fusing hydrogen into helium produces ~7 million times more energy than burning gasoline!"},
{q:"Which is FASTER?",a:"🔊",al:"Sound in water",b:"🔊",bl:"Sound in steel",w:"b",ans:"Steel!",e:"Sound in water: ~1,480 m/s. Sound in steel: ~5,960 m/s. Sound travels ~4x faster in steel because steel molecules are more tightly packed!"},
{q:"Which has a LOWER boiling point?",a:"🧪",al:"Liquid helium",b:"🧪",bl:"Liquid hydrogen",w:"a",ans:"Helium!",e:"Helium boils at -269 C (4.2 K) — the lowest boiling point of any element. Hydrogen boils at -253 C. Helium is so reluctant to condense that it was discovered on the Sun before Earth!"},
{q:"Which pendulum swings FASTER?",a:"📏",al:"Short pendulum",b:"📏",bl:"Long pendulum",w:"a",ans:"Short pendulum!",e:"A pendulum's period depends only on its length and gravity — not its mass. A 25 cm pendulum swings twice as fast as a 1 m pendulum. Galileo discovered this watching a chandelier!"},
{q:"Which expands MORE when heated?",a:"🥈",al:"Aluminum",b:"🔩",bl:"Iron",w:"a",ans:"Aluminum!",e:"Aluminum's thermal expansion coefficient is roughly 2x that of iron. This is why bimetallic strips in thermostats work — different metals expand at different rates!"},
{q:"Which laser is MORE powerful?",a:"🔴",al:"Laser pointer",b:"⚡",bl:"National Ignition Facility laser",w:"b",ans:"NIF laser!",e:"A laser pointer: ~5 milliwatts. NIF laser: 500 trillion watts for a nanosecond. NIF's laser delivers more power than the entire US electrical grid, but only for an instant!"},
{q:"Which particle is HEAVIER?",a:"⚛️",al:"Proton",b:"⚛️",bl:"Neutron",w:"b",ans:"Neutron!",e:"Neutron: 1.6749 x 10^-27 kg. Proton: 1.6726 x 10^-27 kg. The neutron is ~0.14% heavier. This tiny difference matters — free neutrons decay in ~15 minutes!"},
{q:"Which travels FASTER in a vacuum?",a:"📻",al:"Radio waves",b:"🔴",bl:"Visible light",w:"tie",ans:"Same speed!",e:"Radio waves and visible light are both electromagnetic waves — they travel at exactly the same speed (c = 299,792,458 m/s) in a vacuum. Only their wavelength and frequency differ!"},
{q:"Which state of matter is HOTTEST?",a:"🔥",al:"Plasma",b:"🧪",bl:"Bose-Einstein condensate",w:"a",ans:"Plasma!",e:"Plasma exists at millions of degrees (like in the Sun's corona). Bose-Einstein condensates exist near absolute zero. These are opposite extremes of the temperature scale!"},
{q:"Which type of radiation is MORE penetrating?",a:"☢️",al:"Gamma rays",b:"☢️",bl:"Alpha particles",w:"a",ans:"Gamma rays!",e:"Gamma rays penetrate meters of concrete. Alpha particles are stopped by a sheet of paper. But alpha particles cause more damage to tissue if they get inside your body!"},
{q:"Which material is MORE transparent to X-rays?",a:"🦴",al:"Bone",b:"💪",bl:"Muscle tissue",w:"b",ans:"Muscle tissue!",e:"Soft tissues let X-rays pass through easily (appearing dark on film). Dense bone absorbs X-rays (appearing white). This contrast is what makes X-ray imaging possible!"},
{q:"Which carries MORE momentum?",a:"🚂",al:"Freight train at walking speed",b:"🔫",bl:"Speeding bullet",w:"a",ans:"Freight train!",e:"A 10,000-ton train at 5 km/h has ~14,000 kg m/s of momentum. A bullet has ~10 kg m/s. Mass matters enormously — that's why trains take over a mile to stop!"},
{q:"Which has a BIGGER brain relative to body?",a:"🐜",al:"Ant",b:"🧠",bl:"Human",w:"a",ans:"Ant!",e:"An ant's brain is ~15% of its body mass. A human brain is ~2% of body mass. Ants have 250,000 neurons packed into a brain smaller than a pinhead!"},
{q:"Which can SMELL from farther away?",a:"🐻",al:"Grizzly bear",b:"🦈",bl:"Great white shark",w:"a",ans:"Grizzly bear!",e:"Grizzly bears can smell food from 18 miles away. Great white sharks detect blood at 1/3 mile. Bears have one of the best noses in the animal kingdom!"},
{q:"Which has STRONGER bite force?",a:"🐊",al:"Saltwater crocodile",b:"🦛",bl:"Hippopotamus",w:"a",ans:"Crocodile!",e:"Saltwater croc bite: ~3,700 PSI — the strongest bite ever measured. Hippo bite: ~1,800 PSI. But hippos are more dangerous to humans due to their aggression!"},
{q:"Which runs FASTER?",a:"🐎",al:"Thoroughbred horse",b:"🦌",bl:"Pronghorn antelope",w:"b",ans:"Pronghorn!",e:"Pronghorn: sustained 55 mph for miles. Thoroughbreds: ~44 mph max. Pronghorns evolved to outrun the now-extinct American cheetah!"},
{q:"Which lives LONGER?",a:"🐦",al:"Albatross",b:"🦜",bl:"Macaw",w:"a",ans:"Albatross!",e:"Wisdom, a Laysan albatross, was still breeding at age 73+. Macaws live 50–60 years. Albatrosses are among the longest-lived birds on Earth!"},
{q:"Which can LIFT more relative to its weight?",a:"🐜",al:"Leafcutter ant",b:"🪲",bl:"Dung beetle",w:"b",ans:"Dung beetle!",e:"Dung beetles can move 1,141 times their body weight. Leafcutter ants carry ~50x their weight. The horned dung beetle is the strongest animal on Earth pound for pound!"},
{q:"Which has BETTER hearing?",a:"🦇",al:"Bat",b:"🦉",bl:"Barn owl",w:"a",ans:"Bat!",e:"Bats hear frequencies up to 200 kHz and use echolocation with microsecond precision. Barn owls hear excellently (~0.5–10 kHz) but can't match bat ultrasonic range!"},
{q:"Which has MORE stomachs?",a:"🐄",al:"Cow",b:"🐦",bl:"Hoatzin bird",w:"a",ans:"Cow!",e:"Cows have 4 stomach chambers for fermenting grass. The hoatzin has a unique 2-chambered crop that ferments leaves — it's the only bird that digests like a cow!"},
{q:"Which lays MORE eggs at once?",a:"🐟",al:"Ocean sunfish",b:"🐢",bl:"Sea turtle",w:"a",ans:"Ocean sunfish!",e:"Ocean sunfish release up to 300 million eggs at once — more than any vertebrate. Sea turtles lay ~100 eggs per nest. Most sunfish eggs are eaten immediately!"},
{q:"Which animal is LOUDER?",a:"🐋",al:"Blue whale",b:"🦐",bl:"Snapping shrimp colony",w:"b",ans:"Snapping shrimp!",e:"A colony of snapping shrimp produces ~200 dB underwater — louder than a blue whale's 188 dB call. They're so loud they can interfere with submarine sonar!"},
{q:"Which can see MORE colors?",a:"🦋",al:"Mantis shrimp",b:"🧑",bl:"Human",w:"a",ans:"Mantis shrimp!",e:"Mantis shrimp have 16 types of color receptors vs our 3. They see UV, infrared, and polarized light. Their vision is the most complex in the animal kingdom!"},
{q:"Which has a FASTER strike?",a:"🐍",al:"Rattlesnake",b:"🦐",bl:"Mantis shrimp",w:"b",ans:"Mantis shrimp!",e:"Mantis shrimp clubs accelerate at 10,400 g, striking in 3 milliseconds. Rattlesnakes strike in ~50 milliseconds. The shrimp's punch is so fast it boils water on contact!"},
{q:"Which animal can FLY higher?",a:"🦅",al:"Ruppell's griffon vulture",b:"🦢",bl:"Bar-headed goose",w:"a",ans:"Ruppell's vulture!",e:"Ruppell's griffon vulture was recorded at 11,300 m (37,000 feet) — hitting a plane engine. Bar-headed geese fly over Everest at ~8,800 m during migration!"},
{q:"Which spider is BIGGER?",a:"🕷️",al:"Goliath birdeater",b:"🕷️",bl:"Giant huntsman spider",w:"b",ans:"Giant huntsman!",e:"Giant huntsman: 30 cm leg span — the widest of any spider. Goliath birdeater: 28 cm span but heavier at 175 g. The huntsman spreads wider, the goliath weighs more!"},
{q:"Which has a LONGER tongue relative to body?",a:"🦎",al:"Chameleon",b:"🐸",bl:"Frog",w:"a",ans:"Chameleon!",e:"A chameleon's tongue is 1.5–2x its body length and shoots out in 0.07 seconds. Frog tongues are roughly body length. Chameleons catch prey with ballistic precision!"},
{q:"Which fish SWIMS faster?",a:"⚔️",al:"Sailfish",b:"🐟",bl:"Yellowfin tuna",w:"a",ans:"Sailfish!",e:"Sailfish: ~110 km/h — the fastest fish in the ocean. Yellowfin tuna: ~75 km/h. Sailfish use their giant dorsal fin to herd prey before slashing with their bill!"},
{q:"Which insect flaps wings FASTER?",a:"🦟",al:"Mosquito",b:"🐝",bl:"Honeybee",w:"a",ans:"Mosquito!",e:"Mosquitoes flap at ~600 beats per second (creating that annoying whine). Honeybees: ~230 beats per second. That high-pitched buzz is actually mosquito wingbeats!"},
{q:"Which has BETTER camouflage?",a:"🐙",al:"Mimic octopus",b:"🦎",bl:"Leaf-tailed gecko",w:"a",ans:"Mimic octopus!",e:"The mimic octopus impersonates 15+ different species including lionfish, flatfish, and sea snakes. The gecko mimics leaves. The octopus is nature's ultimate shapeshifter!"},
{q:"Which has THICKER skin?",a:"🐘",al:"Elephant",b:"🦏",bl:"Rhinoceros",w:"b",ans:"Rhinoceros!",e:"Rhino skin is up to 5 cm thick in places. Elephant skin is ~2.5 cm. Rhino skin is so tough it was historically used to make armor shields in parts of Asia!"},
{q:"Which animal has MORE teeth?",a:"🐌",al:"Garden snail",b:"🦈",bl:"Great white shark",w:"a",ans:"Snail!",e:"Snails have ~20,000 microscopic teeth on a ribbon-like tongue called a radula. Great whites have ~300. Snails have more teeth than any other animal!"},
{q:"Which can survive COLDER temperatures?",a:"🐧",al:"Emperor penguin",b:"🐛",bl:"Arctic woolly bear caterpillar",w:"b",ans:"Woolly bear!",e:"Arctic woolly bears survive -70 C by producing antifreeze compounds and literally freezing solid. Emperor penguins endure -60 C but stay warm-blooded. The caterpillar spends 14 winters frozen before becoming a moth!"},
{q:"Which lives at a HIGHER altitude?",a:"🐐",al:"Alpine ibex",b:"🕷️",bl:"Himalayan jumping spider",w:"b",ans:"Jumping spider!",e:"Himalayan jumping spiders live at 6,700 m on Mount Everest — the highest permanent resident of any animal. Alpine ibex max out at ~3,500 m. These tiny spiders eat wind-blown insects!"},
{q:"Which ocean is DEEPER on average?",a:"🌊",al:"Pacific Ocean",b:"🌊",bl:"Atlantic Ocean",w:"a",ans:"Pacific!",e:"Pacific average depth: 4,280 m. Atlantic average: 3,646 m. The Pacific is also the largest ocean — it covers more area than all land on Earth combined!"},
{q:"Which is SALTIER?",a:"🌊",al:"Dead Sea",b:"🌊",bl:"Don Juan Pond (Antarctica)",w:"b",ans:"Don Juan Pond!",e:"Dead Sea: ~34% salinity. Don Juan Pond: ~40% salinity — the saltiest body of water on Earth. It's so salty it doesn't freeze even at -50 C!"},
{q:"Which has MORE tectonic plates?",a:"🌍",al:"Earth's surface",b:"🌙",bl:"Mars's surface",w:"a",ans:"Earth!",e:"Earth has 15 major tectonic plates in active motion. Mars has no active plate tectonics at all — it's a one-plate planet. Earth is the only known world with plate tectonics!"},
{q:"Which mountain GROWS faster?",a:"🏔️",al:"Mount Everest",b:"🌋",bl:"Mauna Loa",w:"a",ans:"Everest!",e:"Everest grows ~4 mm/year as India pushes into Asia. Mauna Loa grows during eruptions but actually sinks ~2.4 mm/year under its own weight. Continental collision wins!"},
{q:"Which wave was TALLER?",a:"🌊",al:"Tallest tsunami ever recorded",b:"🌊",bl:"Tallest ocean surface wave",w:"a",ans:"Tsunami!",e:"The 1958 Lituya Bay tsunami reached 524 m — taller than the Empire State Building. The tallest open-ocean wave measured was 29 m. Tsunamis in confined bays can reach staggering heights!"},
{q:"Which has MORE species per square km?",a:"🌊",al:"Coral reef",b:"🌳",bl:"Tropical rainforest",w:"a",ans:"Coral reef!",e:"Coral reefs support ~830,000 species on just 0.1% of ocean floor — the highest density of life anywhere. Rainforests have more total species but are spread over far more area!"},
{q:"Which is HOTTER underground?",a:"🌋",al:"Mid-ocean ridge magma",b:"🌍",bl:"Kola Superdeep Borehole",w:"a",ans:"Mid-ocean ridge!",e:"Mid-ocean ridge magma: ~1,200 C. Kola borehole at 12 km depth: ~180 C. Ridge magma is fresh from Earth's mantle — the planet's conveyor belt of liquid rock!"},
{q:"Which ice sheet is THICKER?",a:"🧊",al:"East Antarctic ice sheet",b:"🧊",bl:"Greenland ice sheet",w:"a",ans:"East Antarctic!",e:"East Antarctic ice: up to 4,776 m thick. Greenland ice: up to 3,400 m. If East Antarctica melted, sea levels would rise ~52 meters — goodbye coastlines!"},
{q:"Which trench is NARROWER?",a:"🌊",al:"Mariana Trench",b:"🌊",bl:"Puerto Rico Trench",w:"a",ans:"Mariana Trench!",e:"The Mariana Trench is ~69 km wide at its widest. The Puerto Rico Trench is ~97 km wide. The Mariana is deeper AND narrower — a dramatic gash in the seafloor!"},
{q:"Which has MORE earthquakes per year?",a:"🌋",al:"Japan",b:"🌋",bl:"Indonesia",w:"a",ans:"Japan!",e:"Japan experiences ~1,500 felt earthquakes per year. Indonesia has ~400+ significant quakes. Japan sits at the junction of 4 tectonic plates — the most seismically complex spot on Earth!"},
{q:"Which ocean current is STRONGER?",a:"🌊",al:"Gulf Stream",b:"🌊",bl:"Antarctic Circumpolar Current",w:"b",ans:"Circumpolar Current!",e:"The Antarctic Circumpolar Current moves 130 million cubic meters per second — 600x the Amazon River's flow. The Gulf Stream moves ~30 million cubic meters per second. It's the mightiest current on Earth!"},
{q:"Which cave is LONGER?",a:"🕳️",al:"Mammoth Cave",b:"🕳️",bl:"Son Doong Cave (largest chamber)",w:"a",ans:"Mammoth Cave!",e:"Mammoth Cave: 676+ km of surveyed passages — the world's longest cave system. Son Doong has the world's largest single chamber but only ~9 km of passages!"},
{q:"Which lake is DEEPER?",a:"🌊",al:"Lake Baikal",b:"🌊",bl:"Lake Tanganyika",w:"a",ans:"Lake Baikal!",e:"Baikal: 1,642 m deep — the deepest lake on Earth. Tanganyika: 1,470 m. Baikal holds 20% of the world's unfrozen surface freshwater. It's also ~25 million years old!"},
{q:"Which waterfall drops FARTHER?",a:"💧",al:"Angel Falls",b:"💧",bl:"Niagara Falls",w:"a",ans:"Angel Falls!",e:"Angel Falls in Venezuela: 979 m — the world's tallest uninterrupted waterfall. Niagara: 51 m. Angel Falls is so tall that water turns to mist before reaching the bottom!"},
{q:"Which volcano has ERUPTED more recently?",a:"🌋",al:"Mount St. Helens",b:"🌋",bl:"Kilauea",w:"b",ans:"Kilauea!",e:"Kilauea has been erupting almost continuously since 1983 and had major events through 2023. St. Helens' last significant eruption was 1980. Kilauea is one of Earth's most active volcanoes!"},
{q:"Which has MORE seamounts?",a:"🌊",al:"Pacific Ocean floor",b:"🌊",bl:"Atlantic Ocean floor",w:"a",ans:"Pacific!",e:"The Pacific has an estimated 30,000+ seamounts — undersea mountains taller than 1,000 m. The Atlantic has roughly 800. Most Pacific seamounts are ancient sunken volcanoes!"},
{q:"Which river carries MORE sediment?",a:"🌊",al:"Amazon River",b:"🌊",bl:"Ganges-Brahmaputra",w:"b",ans:"Ganges-Brahmaputra!",e:"Ganges-Brahmaputra delivers ~1.7 billion tons of sediment per year to the Bay of Bengal. Amazon: ~1.2 billion tons. The Himalayan rivers erode the youngest, tallest mountains on Earth!"},
{q:"Which sea floor feature is LONGEST?",a:"🌊",al:"Mid-Atlantic Ridge",b:"🌊",bl:"East Pacific Rise",w:"a",ans:"Mid-Atlantic Ridge!",e:"The Mid-Atlantic Ridge stretches ~16,000 km — the longest mountain range on Earth (mostly underwater). The East Pacific Rise: ~9,000 km. Combined, ocean ridges span 65,000 km!"},
{q:"Which mineral is MORE common in Earth's crust?",a:"🪨",al:"Feldspar",b:"🪨",bl:"Quartz",w:"a",ans:"Feldspar!",e:"Feldspar makes up ~60% of Earth's crust. Quartz: ~12%. Most people think quartz is most common because it's more visible, but feldspar quietly dominates our planet's surface!"},
{q:"Which has HIGHER water pressure?",a:"🌊",al:"Fire hydrant",b:"🐋",bl:"Whale's blowhole spray",w:"a",ans:"Fire hydrant!",e:"Fire hydrants deliver water at ~50–150 PSI. A whale's blowhole expels air at ~35 PSI. But whales propel spray 6+ meters high — impressive for a nostril on top of your head!"},
{q:"Which is WIDER?",a:"🏜️",al:"Grand Canyon",b:"🌊",bl:"Great Barrier Reef",w:"b",ans:"Great Barrier Reef!",e:"The Grand Canyon is ~29 km wide at its widest. The Great Barrier Reef stretches 2,300 km long and ~65 km wide. It's the largest living structure visible from space!"},
{q:"Which island formed MORE recently?",a:"🌋",al:"Surtsey (Iceland)",b:"🌋",bl:"Nishinoshima (Japan)",w:"b",ans:"Nishinoshima!",e:"Surtsey emerged from the sea in 1963. Nishinoshima dramatically expanded starting in 2013 and continues growing. Nishinoshima is one of Earth's newest expanding landmasses!"},
{q:"Which element is RARER on Earth?",a:"🧪",al:"Gold",b:"🧪",bl:"Platinum",w:"b",ans:"Platinum!",e:"Platinum is ~30x rarer than gold in Earth's crust. Only ~190 tons of platinum are mined per year vs ~3,300 tons of gold. Platinum is also denser and has a higher melting point!"},
{q:"Which gas is MORE abundant in our atmosphere?",a:"💨",al:"Nitrogen",b:"💨",bl:"Oxygen",w:"a",ans:"Nitrogen!",e:"Nitrogen: 78% of the atmosphere. Oxygen: 21%. We breathe mostly nitrogen — it just passes in and out of our lungs while oxygen does the work!"},
{q:"Which acid is STRONGER?",a:"🧪",al:"Hydrofluoric acid",b:"🧪",bl:"Sulfuric acid",w:"b",ans:"Sulfuric acid!",e:"Sulfuric acid is a stronger acid by dissociation. But hydrofluoric acid is far more dangerous — it penetrates skin and dissolves bone by attacking calcium. HF is terrifyingly insidious!"},
{q:"Which reaction is MORE exothermic?",a:"🧪",al:"Thermite reaction",b:"💣",bl:"TNT explosion",w:"a",ans:"Thermite!",e:"Thermite produces ~850 kJ/mol — enough to melt through steel at 2,500 C. TNT releases ~230 kJ/mol. Thermite burns hotter but TNT releases energy faster as a shock wave!"},
{q:"Which element has MORE allotropes?",a:"🧪",al:"Carbon",b:"🧪",bl:"Sulfur",w:"b",ans:"Sulfur!",e:"Sulfur has over 30 known allotropes — the most of any element. Carbon has ~8 (diamond, graphite, graphene, fullerene, etc.). Carbon's are more famous, but sulfur is the allotrope champion!"},
{q:"Which dissolves FASTER in water?",a:"🧂",al:"Table salt",b:"🍬",bl:"Sugar",w:"a",ans:"Salt!",e:"Salt dissolves in seconds due to ionic dissociation. Sugar takes longer because its large molecular structure must be surrounded by water one molecule at a time. Ions separate faster than molecules!"},
{q:"Which metal is MORE reactive?",a:"🧪",al:"Sodium",b:"🧪",bl:"Potassium",w:"b",ans:"Potassium!",e:"Potassium reacts more violently with water than sodium — it instantly ignites with a lilac flame. Moving down Group 1, elements become more reactive because outer electrons are easier to lose!"},
{q:"Which noble gas was discovered FIRST?",a:"🧪",al:"Argon",b:"🧪",bl:"Helium",w:"b",ans:"Helium!",e:"Helium was discovered in 1868 via the Sun's spectrum — 26 years before argon was isolated in 1894. Helium was found in space before anyone found it on Earth!"},
{q:"Which polymer is STRONGER?",a:"🧪",al:"Kevlar",b:"🧪",bl:"Dyneema (UHMWPE)",w:"b",ans:"Dyneema!",e:"Dyneema is 15x stronger than steel by weight and lighter than Kevlar. It floats on water and is used in body armor and climbing ropes. It's the strongest fiber commercially produced!"},
{q:"Which compound has a HIGHER boiling point?",a:"💧",al:"Water",b:"🧪",bl:"Ethanol",w:"a",ans:"Water!",e:"Water boils at 100 C. Ethanol at 78.4 C. Water's extensive hydrogen bonding network gives it an unusually high boiling point for such a small molecule!"},
{q:"Which element is MORE expensive per gram?",a:"🧪",al:"Californium",b:"💎",bl:"Diamond",w:"a",ans:"Californium!",e:"Californium-252 costs ~$27 million per gram. Gem diamond: ~$55,000 per gram. Californium is made atom-by-atom in nuclear reactors and used for detecting gold and oil!"},
{q:"Which element was synthesized FIRST artificially?",a:"🧪",al:"Technetium",b:"🧪",bl:"Plutonium",w:"a",ans:"Technetium!",e:"Technetium was first synthesized in 1937 — the first artificially produced element. Plutonium was made in 1940. Every atom of technetium on Earth is synthetic!"},
{q:"Which bond is STRONGER?",a:"🧪",al:"Covalent triple bond (N2)",b:"🧪",bl:"Ionic bond (NaCl)",w:"a",ans:"Triple bond!",e:"N2 triple bond: 945 kJ/mol. NaCl ionic bond: ~787 kJ/mol lattice energy. Nitrogen's triple bond is one of the strongest chemical bonds — that's why N2 gas is so unreactive!"},
{q:"Which has a LOWER pH?",a:"🍋",al:"Lemon juice",b:"🧪",bl:"Vinegar",w:"a",ans:"Lemon juice!",e:"Lemon juice: pH ~2.0. Vinegar: pH ~2.5. Lemon juice is about 3x more acidic than vinegar. The citric acid in lemons is more concentrated than acetic acid in vinegar!"},
{q:"Which alloy is HARDER?",a:"🔩",al:"Stainless steel",b:"🔩",bl:"Titanium alloy (Ti-6Al-4V)",w:"a",ans:"Stainless steel!",e:"Most stainless steels are harder (150–300 HB Brinell) than Ti-6Al-4V (~334 HB max). But titanium is preferred in aerospace because it's 45% lighter with similar strength!"},
{q:"Which chemical process is OLDER?",a:"🍺",al:"Fermentation",b:"🧪",bl:"Soapmaking",w:"a",ans:"Fermentation!",e:"Fermentation has been used for ~9,000 years (ancient beer and bread). Soapmaking dates to ~2800 BC Babylon (~5,000 years). Humans discovered alcohol before hygiene!"},
{q:"Which element has MORE oxidation states?",a:"🧪",al:"Manganese",b:"🧪",bl:"Osmium",w:"b",ans:"Osmium!",e:"Osmium exhibits oxidation states from -2 to +8 — the widest range of any element. Manganese ranges from -3 to +7. Osmium is also the densest naturally occurring element!"},
{q:"Which crystal structure is MORE common?",a:"🔬",al:"Face-centered cubic (FCC)",b:"🔬",bl:"Body-centered cubic (BCC)",w:"a",ans:"FCC!",e:"FCC is found in gold, silver, copper, aluminum, and lead. BCC in iron, tungsten, and chromium. FCC metals tend to be more ductile because they have more slip planes for deformation!"},
{q:"Which substance is MORE flammable?",a:"🧪",al:"Hydrogen gas",b:"🧪",bl:"Acetylene gas",w:"b",ans:"Acetylene!",e:"Acetylene has a wider flammable range (2.5–100% in air) vs hydrogen (4–75%). Acetylene can even decompose explosively without oxygen. Welders treat it with enormous respect!"},
{q:"Which isotope has a LONGER half-life?",a:"☢️",al:"Carbon-14",b:"☢️",bl:"Uranium-238",w:"b",ans:"Uranium-238!",e:"Carbon-14 half-life: 5,730 years (great for dating recent artifacts). Uranium-238: 4.5 billion years — roughly the age of Earth. U-238 is used to date the oldest rocks and meteorites!"},
{q:"Which transition produces BRIGHTER color?",a:"🧪",al:"Copper flame test",b:"🧪",bl:"Strontium flame test",w:"b",ans:"Strontium!",e:"Strontium produces an intensely bright crimson-red flame. Copper gives blue-green. Strontium is the key ingredient in red fireworks — its emission lines are perfectly in the red spectrum!"},
{q:"Which material is LIGHTER per volume?",a:"🧪",al:"Graphene aerogel",b:"💨",bl:"Air",w:"a",ans:"Graphene aerogel!",e:"Graphene aerogel density: 0.16 mg/cm cubed. Air density: 1.2 mg/cm cubed. Graphene aerogel is 7.5x lighter than air — the lightest solid material ever made!"},
{q:"Which computer was BIGGER?",a:"💻",al:"ENIAC",b:"📱",bl:"First iPhone",w:"a",ans:"ENIAC!",e:"ENIAC weighed 30 tons, filled a 50x30 foot room, and used 18,000 vacuum tubes. The first iPhone fit in your pocket with millions of times more computing power!"},
{q:"Which stores MORE data?",a:"💾",al:"First hard drive ever",b:"💿",bl:"Single floppy disk",w:"b",ans:"Floppy disk!",e:"IBM's first hard drive (1956) stored 5 MB and was the size of two refrigerators. A 3.5 inch floppy disk held 1.44 MB. The hard drive was bigger but the comparison shows how much smaller storage got!"},
{q:"Which network is FASTER?",a:"📡",al:"5G mobile network",b:"🔌",bl:"Fiber optic cable",w:"b",ans:"Fiber optic!",e:"5G theoretical max: ~20 Gbps. Fiber optic cables carry data at ~100+ Tbps in labs. Fiber is ~5,000x faster at peak — light through glass beats radio waves!"},
{q:"Which was invented MORE recently?",a:"🔋",al:"Lithium-ion battery",b:"🌐",bl:"World Wide Web",w:"b",ans:"The Web!",e:"Lithium-ion battery: commercialized by Sony in 1991. World Wide Web: invented by Tim Berners-Lee in 1989 but publicly launched in 1991. They emerged in the same era!"},
{q:"Which uses MORE electricity?",a:"🔍",al:"Google search query",b:"💡",bl:"LED bulb for one hour",w:"b",ans:"LED bulb!",e:"A Google search: ~0.3 Wh. An LED bulb for one hour: ~10 Wh. But Google processes 8.5 billion searches per day — collectively using enormous energy!"},
{q:"Which has MORE lines of code?",a:"🚗",al:"Modern car software",b:"📱",bl:"Android OS",w:"a",ans:"Car software!",e:"A modern car runs ~150 million lines of code. Android OS: ~15 million lines. Your car has 10x more code than your phone's operating system. Vehicles are rolling supercomputers!"},
{q:"Which satellite is OLDER (still working)?",a:"📡",al:"Voyager 1",b:"📡",bl:"Hubble Space Telescope",w:"a",ans:"Voyager 1!",e:"Voyager 1 launched in 1977 and still transmits data from interstellar space. Hubble launched in 1990. Voyager 1 is the oldest functioning spacecraft — 48+ years and counting!"},
{q:"Which display has MORE pixels?",a:"📺",al:"8K TV",b:"👁️",bl:"Human retina",w:"b",ans:"Human retina!",e:"8K TV: ~33 million pixels. Human retina: ~120 million rods + 6 million cones (~126 million receptors). Your eye has 4x more resolution than the best TV!"},
{q:"Which robot is FASTER?",a:"🤖",al:"Boston Dynamics Spot",b:"🤖",bl:"Cheetah robot (MIT)",w:"b",ans:"Cheetah robot!",e:"MIT's Cheetah 3 runs at ~14 mph and can jump over obstacles. Boston Dynamics Spot: ~5 mph. The Cheetah robot is designed specifically for speed and agility!"},
{q:"Which has MORE users worldwide?",a:"📱",al:"Smartphones",b:"🚽",bl:"Flush toilets",w:"a",ans:"Smartphones!",e:"Over 6.8 billion people have smartphones. Only about 4.5 billion have access to proper sanitation. More people own a phone than have a toilet — a surprising development gap!"},
{q:"Which chip has SMALLER transistors?",a:"📱",al:"Apple M4 chip",b:"🖥️",bl:"Intel's latest desktop chip",w:"a",ans:"Apple M4!",e:"Apple's M4 uses 3 nm process technology. Intel's latest consumer chips use 4–7 nm. Smaller transistors mean more computing power in less space with less heat!"},
{q:"Which programming language is OLDER?",a:"💻",al:"FORTRAN",b:"💻",bl:"LISP",w:"a",ans:"FORTRAN!",e:"FORTRAN was created in 1957 for scientific computing. LISP came in 1958 for AI research. FORTRAN is still widely used in weather forecasting and physics simulations!"},
{q:"Which encryption is HARDER to break?",a:"🔒",al:"AES-256",b:"🔒",bl:"RSA-2048",w:"a",ans:"AES-256!",e:"AES-256 has 2^256 possible keys — more than atoms in the observable universe. RSA-2048 is theoretically breakable with quantum computers. AES-256 is considered quantum-resistant!"},
{q:"Which battery lasts LONGER?",a:"🔋",al:"Nuclear battery (RTG)",b:"🔋",bl:"Best lithium-ion battery",w:"a",ans:"Nuclear battery!",e:"RTGs (radioisotope thermoelectric generators) last 30+ years — Voyager's RTG is still working after 48 years. Best Li-ion batteries degrade significantly after 3–5 years!"},
{q:"Which camera sensor is BIGGER?",a:"📱",al:"Smartphone camera sensor",b:"📷",bl:"Full-frame DSLR sensor",w:"b",ans:"DSLR!",e:"A full-frame sensor is ~864 mm squared. Top smartphone sensors are ~50 mm squared. The DSLR sensor is ~17x larger, which is why DSLRs still excel in low light!"},
{q:"Which internet cable is LONGER?",a:"🌊",al:"Transatlantic submarine cable",b:"🌊",bl:"Transpacific submarine cable",w:"b",ans:"Transpacific!",e:"The longest transpacific cables stretch ~15,000 km. Transatlantic cables: ~6,600 km. Over 500 submarine cables carry 97% of intercontinental data — the internet's hidden backbone!"},
{q:"Which can process MORE images per second?",a:"🧠",al:"Human visual system",b:"🤖",bl:"GPUs for AI",w:"b",ans:"GPUs!",e:"Modern GPUs process millions of images per second for AI training. Humans process ~10–12 distinct images per second consciously. But our brains use far less power for comparable understanding!"},
{q:"Which spacecraft was MORE expensive?",a:"🚀",al:"International Space Station",b:"🔭",bl:"James Webb Space Telescope",w:"a",ans:"ISS!",e:"The ISS cost ~$150 billion over decades of construction. JWST cost ~$10 billion. The ISS is the most expensive single structure ever built by humanity!"},
{q:"Which data center uses MORE water?",a:"🤖",al:"AI training facility",b:"📺",bl:"Video streaming data center",w:"a",ans:"AI training!",e:"Training a large AI model like GPT-4 uses millions of liters of water for cooling. Video streaming is less computationally intensive per query. Each ChatGPT conversation uses ~500 mL of water!"},
{q:"Which communication is FASTER?",a:"📡",al:"Radio signal to Mars",b:"🌐",bl:"Internet ping to Australia",w:"b",ans:"Internet to Australia!",e:"A radio signal to Mars takes 3–22 minutes depending on orbital positions. An internet ping to Australia from the US: ~150–300 milliseconds. Mars is really, really far away!"},
{q:"Which device has MORE sensors?",a:"📱",al:"Modern smartphone",b:"🚗",bl:"Self-driving car",w:"b",ans:"Self-driving car!",e:"Autonomous cars use 30+ sensors: LIDAR, radar, cameras, ultrasonic, GPS, IMU, and more. Smartphones have ~15 sensors. Self-driving cars need redundant sensing for safety!"},
{q:"Which weighs MORE?",a:"📊",al:"All data on the internet",b:"🍓",bl:"A strawberry",w:"b",ans:"Strawberry!",e:"All internet data stored as electrons weighs about 50 grams total. An average strawberry weighs ~12 grams. Wait — the internet actually weighs more! But it's surprisingly close to a strawberry!"},
{q:"Which organ is HEAVIER?",a:"🧠",al:"Brain",b:"🫁",bl:"Both lungs combined",w:"b",ans:"Lungs!",e:"Both lungs: ~1.3 kg. Brain: ~1.4 kg. They're remarkably close, but the brain edges ahead. However, the liver at ~1.5 kg outweighs both!"},
{q:"Which happens MORE times per day?",a:"👁️",al:"Blinks",b:"💓",bl:"Heartbeats",w:"b",ans:"Heartbeats!",e:"You blink ~15,000–20,000 times per day. Your heart beats ~100,000 times per day. Your heart works 5x harder than your eyelids!"},
{q:"Which bone is STRONGER pound for pound?",a:"🦴",al:"Human femur",b:"🔩",bl:"Concrete",w:"a",ans:"Femur!",e:"Human bone is 4x stronger than concrete in compression. Your femur can support ~1,700 lbs before breaking. Bone is nature's reinforced composite material!"},
{q:"Which has a LARGER surface area?",a:"🫁",al:"Your lungs (all alveoli)",b:"🎾",bl:"Tennis court",w:"a",ans:"Your lungs!",e:"If flattened, your lung alveoli cover ~70 square meters — roughly half a tennis court (260 sq m). Actually, a tennis court is bigger! But 70 sq m packed inside your chest is still amazing!"},
{q:"Which lasts LONGER in your body?",a:"🦴",al:"A bone cell",b:"🧠",bl:"A brain neuron",w:"b",ans:"Neuron!",e:"Most neurons last your entire lifetime — they're rarely replaced. Bone cells (osteocytes) live ~25 years before being replaced. Your brain cells are older than your skeleton!"},
{q:"Which sense responds FASTER?",a:"👂",al:"Hearing",b:"👁️",bl:"Vision",w:"a",ans:"Hearing!",e:"Auditory reaction time: ~150 milliseconds. Visual reaction time: ~200 milliseconds. That's why races use starting guns instead of lights — your ears react 25% faster!"},
{q:"Which produces MORE saliva daily?",a:"👅",al:"Your mouth",b:"💧",bl:"A kitchen faucet drip",w:"a",ans:"Your mouth!",e:"You produce 0.5–1.5 liters of saliva daily. A dripping faucet loses ~20 liters per day. The faucet actually produces more, but your saliva production is still impressively high!"},
{q:"Which is LONGER?",a:"🦴",al:"Your small intestine",b:"🏠",bl:"A bowling lane",w:"a",ans:"Small intestine!",e:"Your small intestine is ~6 meters (20 feet) long. A bowling lane is 18.3 meters (60 feet). The bowling lane is longer! But your small intestine is remarkably long for fitting inside your abdomen!"},
{q:"Which muscle contracts FASTER?",a:"👁️",al:"Eye muscles (extraocular)",b:"👆",bl:"Finger muscles",w:"a",ans:"Eye muscles!",e:"Your eye muscles are the fastest in your body, completing a saccade (rapid eye movement) in ~20–200 milliseconds. Finger muscles take ~100–200 ms. Your eyes move faster than any other body part!"},
{q:"Which has MORE sweat glands?",a:"🦶",al:"Your feet",b:"✋",bl:"Your palms",w:"a",ans:"Your feet!",e:"Each foot has ~250,000 sweat glands producing up to half a pint of sweat daily. Your palms have ~370 per sq cm but less total area. Feet are among the sweatiest parts of your body!"},
{q:"Which contains MORE water?",a:"🧠",al:"Your brain",b:"🩸",bl:"Your blood",w:"b",ans:"Your blood!",e:"Blood is ~92% water by volume (total: ~5 liters). Your brain is 73% water (~1 kg). Your blood contains more total water, but the brain is one of the most water-rich organs!"},
{q:"Which grows FASTER?",a:"💅",al:"Fingernails",b:"🦶",bl:"Toenails",w:"a",ans:"Fingernails!",e:"Fingernails grow ~3.5 mm/month. Toenails grow ~1.6 mm/month. Fingernails grow 2x faster, possibly because hands have better blood circulation from more frequent use!"},
{q:"Which has MORE taste buds?",a:"👶",al:"A baby",b:"🧑",bl:"An adult",w:"a",ans:"A baby!",e:"Babies have ~10,000 taste buds covering their tongue, cheeks, and throat. Adults have ~2,000–8,000 on the tongue only. This is why children find flavors more intense!"},
{q:"Which carries signals FASTER?",a:"🧠",al:"Myelinated nerve fiber",b:"🧠",bl:"Unmyelinated nerve fiber",w:"a",ans:"Myelinated!",e:"Myelinated nerves: 70–120 m/s. Unmyelinated: 0.5–2 m/s. Myelin insulation makes signals 60–100x faster. Diseases like MS that damage myelin devastate nerve function!"},
{q:"Which has a HIGHER surface area?",a:"🦴",al:"Inside of your bones (trabecular)",b:"🧠",bl:"Cerebral cortex (unfolded)",w:"a",ans:"Bone interior!",e:"Trabecular bone total surface area: ~7 square meters. Unfolded cortex: ~2,500 square centimeters (0.25 sq m). Your porous bone interior has massive surface area for mineral exchange!"},
{q:"Which regenerates FASTER?",a:"🫁",al:"Liver tissue",b:"🩸",bl:"Skin tissue",w:"a",ans:"Liver!",e:"Your liver can regenerate to full size from just 25% remaining tissue in weeks. Skin regeneration takes months for deep wounds. The liver is the only internal organ that can fully regenerate!"},
{q:"Which is LONGER per cell?",a:"🧬",al:"Stretched-out DNA",b:"🔬",bl:"Longest human nerve cell",w:"b",ans:"Nerve cell!",e:"DNA in a cell: ~2 meters stretched out. The sciatic nerve cell runs from your spine to your foot — up to 1 meter in tall people. But DNA still wins at 2 meters per cell!"},
{q:"Which works HARDER during sleep?",a:"🧠",al:"Brain (memory consolidation)",b:"💪",bl:"Growth hormone secretion",w:"a",ans:"Brain!",e:"Your brain is highly active during sleep — processing memories, clearing toxins via the glymphatic system, and dreaming. It uses nearly as much energy asleep as awake!"},
{q:"Which has MORE receptors?",a:"👁️",al:"Your retina",b:"👃",bl:"Your olfactory epithelium",w:"a",ans:"Retina!",e:"Your retina has ~126 million photoreceptors. Your nose has ~10–20 million olfactory receptors. Your eyes detect far more raw data, but your nose can distinguish more categories!"},
{q:"Which is THICKER?",a:"💪",al:"Skin on your eyelid",b:"🦶",bl:"Skin on your heel",w:"b",ans:"Heel skin!",e:"Eyelid skin: ~0.5 mm — the thinnest on your body. Heel skin: ~4 mm — the thickest. Your heel skin is 8x thicker to handle the pressure of walking!"},
{q:"Which blood type is RARER?",a:"🩸",al:"AB negative",b:"🩸",bl:"O negative",w:"a",ans:"AB negative!",e:"AB negative: only ~0.6% of the population. O negative: ~6.6%. AB negative is the rarest common blood type. But Rh-null ('golden blood') is even rarer — fewer than 50 people worldwide!"},
{q:"Which system has MORE lymph nodes?",a:"🦠",al:"Your neck region",b:"🦠",bl:"Your intestinal region",w:"b",ans:"Intestinal region!",e:"Your gut-associated lymphoid tissue contains ~500 lymph nodes. Your neck has ~300. About 70% of your immune system is concentrated in your gut — it's your body's largest immune organ!"},
{q:"Which was published FIRST?",a:"📕",al:"Newton's Principia",b:"📘",bl:"Darwin's Origin of Species",w:"a",ans:"Newton!",e:"Newton's Principia Mathematica was published in 1687. Darwin's On the Origin of Species in 1859 — 172 years later. Newton invented calculus to write his book!"},
{q:"Which discovery happened FIRST?",a:"⚡",al:"Electricity (Galvani's experiments)",b:"🧲",bl:"Electromagnetism (Oersted)",w:"a",ans:"Electricity!",e:"Galvani's bioelectricity experiments were in 1780. Oersted discovered the link between electricity and magnetism in 1820. It took 40 years to connect the two phenomena!"},
{q:"Which scientist held MORE patents?",a:"💡",al:"Thomas Edison",b:"🔬",bl:"Nikola Tesla",w:"a",ans:"Edison!",e:"Edison held 1,093 US patents — the most of any individual at the time. Tesla held ~300. Edison's lab was essentially the first industrial research facility!"},
{q:"Which was discovered FIRST?",a:"⚛️",al:"The electron",b:"☢️",bl:"Radioactivity",w:"b",ans:"Radioactivity!",e:"Becquerel discovered radioactivity in 1896. J.J. Thomson discovered the electron in 1897 — just one year later. The 1890s were a golden age of physics discoveries!"},
{q:"Which experiment cost MORE?",a:"⚛️",al:"Large Hadron Collider",b:"🧬",bl:"Human Genome Project",w:"a",ans:"LHC!",e:"The LHC cost ~$13.25 billion. The Human Genome Project cost ~$2.7 billion. The LHC is the most expensive single scientific instrument ever built!"},
{q:"Which theory was proposed FIRST?",a:"⚛️",al:"Atomic theory (Dalton)",b:"🌊",bl:"Wave theory of light (Young)",w:"a",ans:"Atomic theory!",e:"Dalton proposed modern atomic theory in 1803. Thomas Young demonstrated light's wave nature in 1801. They were nearly simultaneous — both revolutionary insights of the early 1800s!"},
{q:"Which happened FIRST?",a:"💉",al:"First vaccination",b:"🔬",bl:"Germ theory of disease",w:"a",ans:"Vaccination!",e:"Jenner developed smallpox vaccination in 1796. Pasteur established germ theory in the 1860s. We learned to prevent disease 70 years before understanding what caused it!"},
{q:"Who lived LONGER?",a:"🍎",al:"Isaac Newton",b:"⚡",bl:"Albert Einstein",w:"a",ans:"Newton!",e:"Newton lived 84 years (1642–1727). Einstein lived 76 years (1879–1955). Newton also spent his later decades as Master of the Royal Mint, catching counterfeiters!"},
{q:"Which element was isolated FIRST?",a:"🧪",al:"Oxygen",b:"🧪",bl:"Hydrogen",w:"b",ans:"Hydrogen!",e:"Hydrogen was first isolated by Cavendish in 1766. Oxygen was isolated by Scheele in 1771 and Priestley in 1774. Hydrogen — the lightest element — was also the first to be captured!"},
{q:"Which was built FIRST?",a:"🔬",al:"First electron microscope",b:"📻",bl:"First radio broadcast",w:"b",ans:"Radio!",e:"Fessenden's first radio broadcast was in 1906. The first electron microscope was built by Ruska in 1931. Radio technology preceded electron microscopy by 25 years!"},
{q:"Which won the Nobel Prize YOUNGER?",a:"👩‍🔬",al:"Marie Curie",b:"⚛️",bl:"Lawrence Bragg",w:"b",ans:"Bragg!",e:"Lawrence Bragg won the Nobel Prize in Physics at age 25 in 1915 — the youngest science Nobel laureate ever. Marie Curie won her first Nobel at age 36 in 1903!"},
{q:"Which was measured FIRST accurately?",a:"💡",al:"Speed of light",b:"🔊",bl:"Speed of sound",w:"b",ans:"Speed of sound!",e:"The speed of sound was first accurately measured by Marin Mersenne in 1630. The speed of light wasn't measured until Roemer in 1676 — a 46-year gap!"},
{q:"Which scientific instrument is OLDER?",a:"🌡️",al:"Thermometer",b:"⏱️",bl:"Barometer",w:"a",ans:"Thermometer!",e:"Galileo invented the thermoscope around 1592. Torricelli invented the barometer in 1643. Temperature measurement came 50 years before atmospheric pressure measurement!"},
{q:"Which space achievement came FIRST?",a:"🐕",al:"Animal in orbit (Laika)",b:"🧑‍🚀",bl:"Human in space (Gagarin)",w:"a",ans:"Laika!",e:"Laika orbited Earth on Sputnik 2 in November 1957. Gagarin's first human spaceflight was April 1961. Sadly, Laika didn't survive — but she paved the way for human spaceflight!"},
{q:"Which periodic table element was predicted BEFORE discovery?",a:"🧪",al:"Gallium",b:"🧪",bl:"Germanium",w:"a",ans:"Gallium!",e:"Mendeleev predicted gallium (eka-aluminum) in 1871; it was discovered in 1875. He predicted germanium (eka-silicon) in 1871; discovered in 1886. Gallium was found first — vindicated Mendeleev's table!"},
{q:"Which medical breakthrough happened FIRST?",a:"💉",al:"First antibiotic (penicillin)",b:"🩻",bl:"First X-ray image",w:"b",ans:"X-ray!",e:"Rontgen took the first X-ray image in 1895. Fleming discovered penicillin in 1928 — 33 years later. We could see inside the body long before we could fight bacterial infections!"},
{q:"Which was mapped FIRST?",a:"🧬",al:"Structure of insulin",b:"🧬",bl:"Structure of hemoglobin",w:"a",ans:"Insulin!",e:"Sanger determined insulin's amino acid sequence in 1951 — winning the Nobel Prize. Perutz solved hemoglobin's 3D structure in 1959. Insulin was the first protein ever sequenced!"},
{q:"Which mathematical concept is OLDER?",a:"🔢",al:"Zero as a number",b:"📐",bl:"Pi calculation",w:"b",ans:"Pi!",e:"Babylonians approximated pi around 1900 BC. Zero as a number concept emerged in India around 500 AD. Humans calculated circles for 2,400 years before inventing zero!"},
{q:"Which law was formulated FIRST?",a:"🌍",al:"Law of gravity (Newton)",b:"⚡",bl:"Coulomb's law (electric force)",w:"a",ans:"Gravity!",e:"Newton published the law of gravity in 1687. Coulomb's law came in 1785 — 98 years later. Both describe inverse-square forces, and they have strikingly similar mathematical forms!"},
{q:"Which was observed FIRST through a microscope?",a:"🦠",al:"Bacteria",b:"🧫",bl:"Human cells",w:"b",ans:"Human cells!",e:"Hooke observed cork cells in 1665. Leeuwenhoek first saw bacteria in 1676 — 11 years later. Hooke coined the word 'cell' because cork chambers reminded him of monastery cells!"},
{q:"Which was synthesized in a lab FIRST?",a:"🧪",al:"Urea (organic compound)",b:"💎",bl:"Synthetic diamond",w:"a",ans:"Urea!",e:"Wohler synthesized urea in 1828 — the first organic compound made from inorganic materials, shattering 'vitalism.' Synthetic diamonds weren't made until 1954!"},
{q:"Which particle was theorized FIRST?",a:"⚛️",al:"Neutrino",b:"⚛️",bl:"Positron",w:"b",ans:"Positron!",e:"Dirac predicted the positron (antimatter) in 1928. Pauli proposed the neutrino in 1930. The positron was found in 1932, but the neutrino wasn't detected until 1956 — it's incredibly elusive!"},
{q:"Which organ can you donate while ALIVE?",a:"🫁",al:"One lung lobe",b:"🧠",bl:"Part of your brain",w:"a",ans:"Lung lobe!",e:"Living donors can give a lung lobe, kidney, or part of their liver. Brain tissue cannot be transplanted. Your liver even regrows after partial donation — the only organ that does!"},
{q:"Which disease has killed MORE people historically?",a:"🦟",al:"Malaria",b:"🫁",bl:"Tuberculosis",w:"a",ans:"Malaria!",e:"Malaria has killed an estimated 50+ billion people throughout human history — nearly half of all humans who ever lived. TB has killed ~1 billion. Malaria is humanity's deadliest enemy!"},
{q:"Which surgery was performed FIRST?",a:"🫀",al:"Heart transplant",b:"🦴",bl:"Hip replacement",w:"b",ans:"Hip replacement!",e:"The first hip replacement was performed in 1960 by Charnley. The first heart transplant was by Christiaan Barnard in 1967. Today over 1 million hip replacements are done yearly!"},
{q:"Which heals FASTER?",a:"🦴",al:"Broken rib",b:"💪",bl:"Torn ACL",w:"a",ans:"Broken rib!",e:"Ribs heal naturally in 6–8 weeks. A torn ACL often requires surgery and 6–9 months of recovery. Bones heal better than ligaments because bones have a richer blood supply!"},
{q:"Which is MORE common worldwide?",a:"👁️",al:"Nearsightedness (myopia)",b:"🦷",bl:"Tooth decay",w:"b",ans:"Tooth decay!",e:"Tooth decay affects ~3.5 billion people — nearly half of humanity. Myopia affects ~1.4 billion. Dental cavities are the single most common chronic disease on Earth!"},
{q:"Which medicine is OLDER?",a:"🌿",al:"Aspirin (willow bark use)",b:"💉",bl:"Morphine isolation",w:"a",ans:"Aspirin!",e:"Willow bark (salicin/aspirin) was used by ancient Egyptians 3,500+ years ago. Morphine was isolated from opium in 1804. Aspirin's origins predate recorded history!"},
{q:"Which has a HIGHER survival rate today?",a:"🫀",al:"Heart attack",b:"🧠",bl:"Stroke",w:"a",ans:"Heart attack!",e:"Heart attack 30-day survival rate: ~90–95%. Stroke survival: ~75–85%. Modern cardiac care has dramatically improved heart attack outcomes with stents and clot-busting drugs!"},
{q:"Which scan uses MORE radiation?",a:"🩻",al:"Chest X-ray",b:"🔬",bl:"CT scan of the abdomen",w:"b",ans:"CT scan!",e:"A chest X-ray delivers ~0.02 mSv. An abdominal CT: ~8 mSv — 400x more. One CT equals roughly 3 years of natural background radiation exposure!"},
{q:"Which vitamin deficiency is MORE common globally?",a:"🌞",al:"Vitamin D deficiency",b:"🥩",bl:"Iron deficiency",w:"b",ans:"Iron deficiency!",e:"Iron deficiency affects ~2 billion people worldwide. Vitamin D deficiency affects ~1 billion. Iron deficiency anemia is the most common nutritional disorder on the planet!"},
{q:"Which antibiotic was discovered MORE recently?",a:"💊",al:"Teixobactin",b:"💊",bl:"Daptomycin",w:"a",ans:"Teixobactin!",e:"Teixobactin was discovered in 2015 using a novel soil-screening method. Daptomycin was discovered in 1987. Teixobactin was the first new antibiotic class in 30 years!"},
{q:"Which procedure is SHORTER?",a:"👁️",al:"LASIK eye surgery",b:"🦷",bl:"Wisdom tooth extraction",w:"a",ans:"LASIK!",e:"LASIK takes ~15 minutes for both eyes, with the laser active for only 20–50 seconds per eye. Wisdom tooth extraction: 20–60 minutes. LASIK is one of the fastest surgeries!"},
{q:"Which organ was transplanted FIRST successfully?",a:"🫘",al:"Kidney",b:"🫀",bl:"Heart",w:"a",ans:"Kidney!",e:"The first successful kidney transplant was in 1954 between identical twins by Dr. Joseph Murray (who won the Nobel Prize). The first heart transplant didn't happen until 1967!"},
{q:"Which vaccine was developed FASTER?",a:"💉",al:"COVID-19 mRNA vaccine",b:"💉",bl:"Mumps vaccine",w:"a",ans:"COVID-19 vaccine!",e:"COVID-19 mRNA vaccines took ~11 months from sequencing to authorization. The mumps vaccine held the previous record at ~4 years. mRNA technology enabled unprecedented speed!"},
{q:"Which has a LONGER recovery time?",a:"🫀",al:"Open heart surgery",b:"🧠",bl:"Brain surgery (craniotomy)",w:"a",ans:"Heart surgery!",e:"Open heart surgery recovery: 6–12 weeks. Craniotomy recovery: 4–8 weeks typically. Heart surgery requires the chest to re-heal after being split open — the sternum takes time!"},
{q:"Which costs MORE per year of treatment?",a:"💊",al:"Type 1 diabetes management",b:"💊",bl:"Hemophilia A treatment",w:"b",ans:"Hemophilia A!",e:"Hemophilia A treatment: $300,000–$600,000+ per year. Type 1 diabetes: ~$10,000–$20,000 per year. Hemophilia requires frequent infusions of expensive clotting factors!"},
{q:"Which causes MORE deaths annually?",a:"🍬",al:"Diabetes",b:"🫁",bl:"Air pollution-related disease",w:"b",ans:"Air pollution!",e:"Air pollution causes ~6.7 million deaths annually. Diabetes: ~1.5 million direct deaths. Air pollution is a silent pandemic — the single largest environmental health risk in the world!"},
{q:"Which test is MORE sensitive?",a:"🧪",al:"PCR test",b:"🧪",bl:"Rapid antigen test",w:"a",ans:"PCR!",e:"PCR can detect as few as 1–10 copies of viral RNA. Rapid antigen tests need millions of viral particles. PCR is ~1,000x more sensitive, which is why it's the gold standard for diagnostics!"},
{q:"Which is MORE common in humans?",a:"🧬",al:"Genetic mutations at birth",b:"🦠",bl:"Bacterial infections per year",w:"b",ans:"Infections!",e:"Humans average ~70 new mutations at birth. But we get dozens of infections per year from childhood onward. Your immune system fights off countless bacterial invaders daily!"},
{q:"Which takes LONGER to develop?",a:"💊",al:"Average new drug",b:"✈️",bl:"New commercial airplane",w:"a",ans:"New drug!",e:"Average drug development: 10–15 years and $2.6 billion from lab to pharmacy. A new airplane model: 5–8 years. Drug development is one of the longest and most expensive R&D processes!"},
{q:"Which carries MORE oxygen?",a:"🩸",al:"Hemoglobin in blood",b:"🩸",bl:"Dissolved oxygen in plasma",w:"a",ans:"Hemoglobin!",e:"Hemoglobin carries 98.5% of blood oxygen. Only 1.5% dissolves directly in plasma. Without hemoglobin, blood would need to flow 15x faster to deliver the same oxygen — impossible!"},
];

